// ============================================
// CHINESE MASTER - HSK READING EXTRA Passages
// 300 Additional Passages for HSK Levels 1-5
// ALL SIMPLIFIED CHINESE
// ============================================

(function() {
    var byLevel = { hsk1: [], hsk2: [], hsk3: [], hsk4: [], hsk5: [] };
    var items = [
        { id:'hrex_001', title:'你好', titleEn:'Hello', hsk:1, passage:'你好！我叫小华。我今年八岁。我是小学生。我喜欢看书和画画。', questions:[{ q:'他叫什么名字？', options:['小明','小华','小红','小李'], correct:1 },{ q:'他今年几岁？', options:['七岁','八岁','九岁','十岁'], correct:1 }] },
        { id:'hrex_002', title:'我的猫', titleEn:'My Cat', hsk:1, passage:'我有一只猫。它很可爱。它的毛是白色的。它喜欢吃鱼。我很喜欢它。', questions:[{ q:'他有什么？', options:['一只狗','一只猫','一只鸟','一条鱼'], correct:1 },{ q:'猫喜欢吃什么？', options:['肉','鱼','菜','米'], correct:1 }] },
        { id:'hrex_003', title:'苹果', titleEn:'Apple', hsk:1, passage:'这是苹果。苹果是红色的。苹果很好吃。妈妈买了五个苹果。我吃了两个。', questions:[{ q:'苹果是什么颜色？', options:['红色','绿色','黄色','蓝色'], correct:0 },{ q:'妈妈买了几个苹果？', options:['三个','四个','五个','六个'], correct:2 }] },
        { id:'hrex_004', title:'在学校', titleEn:'At School', hsk:1, passage:'今天星期一。我去学校上课。第一节课是中文。老师很好。我学了很多生字。', questions:[{ q:'今天星期几？', options:['星期一','星期二','星期三','星期四'], correct:0 },{ q:'第一节课是什么？', options:['英文','数学','中文','画画'], correct:2 }] },
        { id:'hrex_005', title:'我的书包', titleEn:'My Backpack', hsk:1, passage:'我的书包是蓝色的。书包里有一本书、两支笔和一块橡皮。书包很重。', questions:[{ q:'书包是什么颜色？', options:['红色','蓝色','绿色','白色'], correct:1 },{ q:'书包里有几支笔？', options:['一支','两支','三支','四支'], correct:1 }] },
        { id:'hrex_006', title:'喝水', titleEn:'Drinking Water', hsk:1, passage:'我渴了。我想喝水。杯子里有水。我喝了很多水。现在不渴了。', questions:[{ q:'他怎么了？', options:['饿了','渴了','累了','困了'], correct:1 },{ q:'他喝了什么？', options:['牛奶','水','果汁','茶'], correct:1 }] },
        { id:'hrex_007', title:'我的爸爸', titleEn:'My Father', hsk:1, passage:'我的爸爸很高。他戴眼镜。他是老师。他教数学。爸爸每天都很忙。', questions:[{ q:'爸爸做什么工作？', options:['医生','老师','工人','司机'], correct:1 },{ q:'爸爸教什么？', options:['中文','英文','数学','音乐'], correct:2 }] },
        { id:'hrex_008', title:'坐车', titleEn:'Taking the Bus', hsk:1, passage:'我坐公共汽车去公园。车上人很多。我站了一会儿。到站了，我下车了。', questions:[{ q:'他去哪里？', options:['学校','商店','公园','医院'], correct:2 },{ q:'车上人多吗？', options:['不多','很多','没有人','很少'], correct:1 }] },
        { id:'hrex_009', title:'我的房间', titleEn:'My Room', hsk:1, passage:'我的房间不大。房间里有一张床、一张桌子和一把椅子。桌子上有一盏灯。', questions:[{ q:'房间里有什么？', options:['床和桌子','电视','电脑','冰箱'], correct:0 },{ q:'桌子上有什么？', options:['书','灯','笔','花'], correct:1 }] },
        { id:'hrex_010', title:'去饭馆', titleEn:'Going to a Restaurant', hsk:1, passage:'中午我和妈妈去饭馆。我点了米饭和鱼。妈妈点了面条。很好吃。', questions:[{ q:'他和谁去饭馆？', options:['爸爸','妈妈','朋友','哥哥'], correct:1 },{ q:'他点了什么？', options:['面条','米饭和鱼','饺子','包子'], correct:1 }] },
        { id:'hrex_011', title:'下雨了', titleEn:'It Is Raining', hsk:1, passage:'今天下雨了。雨很大。我没有带伞。我跑回家。身上都湿了。', questions:[{ q:'今天天气怎么样？', options:['晴天','下雨','下雪','刮风'], correct:1 },{ q:'他带伞了吗？', options:['带了','没带','不知道','买了'], correct:1 }] },
        { id:'hrex_012', title:'我的妈妈', titleEn:'My Mother', hsk:1, passage:'我妈妈很漂亮。她头发很长。她喜欢穿裙子。妈妈做的饭很好吃。我爱妈妈。', questions:[{ q:'妈妈喜欢穿什么？', options:['裤子','裙子','毛衣','大衣'], correct:1 },{ q:'妈妈做的饭怎么样？', options:['不好吃','很好吃','很咸','很甜'], correct:1 }] },
        { id:'hrex_013', title:'生日', titleEn:'Birthday', hsk:1, passage:'今天是我的生日。我八岁了。妈妈给我买了一个大蛋糕。我很高兴。', questions:[{ q:'今天是什么日子？', options:['过年','生日','节日','周末'], correct:1 },{ q:'妈妈买了什么？', options:['玩具','蛋糕','书','衣服'], correct:1 }] },
        { id:'hrex_014', title:'小狗', titleEn:'Little Dog', hsk:1, passage:'我家有一只小狗。小狗很小。它的毛是黄色的。小狗喜欢在草地上跑。', questions:[{ q:'小狗的毛是什么颜色？', options:['白色','黑色','黄色','棕色'], correct:2 },{ q:'小狗喜欢在哪里跑？', options:['家里','草地上','路上','公园里'], correct:1 }] },
        { id:'hrex_015', title:'买衣服', titleEn:'Buying Clothes', hsk:1, passage:'妈妈带我去买衣服。我选了一件红色的T恤。T恤五十块钱。妈妈付了钱。', questions:[{ q:'他买了什么颜色？', options:['蓝色','红色','白色','黑色'], correct:1 },{ q:'T恤多少钱？', options:['三十','四十','五十','六十'], correct:2 }] },
        { id:'hrex_016', title:'我的好朋友', titleEn:'My Good Friend', hsk:1, passage:'我有一个好朋友。他叫小东。他和我一样大。我们经常一起玩。', questions:[{ q:'好朋友叫什么？', options:['小明','小东','小华','小刚'], correct:1 },{ q:'他们经常一起做什么？', options:['学习','玩','吃饭','睡觉'], correct:1 }] },
        { id:'hrex_017', title:'春天', titleEn:'Spring', hsk:1, passage:'春天来了。天气暖和了。花儿开了。树也绿了。我喜欢春天。', questions:[{ q:'春天天气怎么样？', options:['很冷','很热','暖和','凉快'], correct:2 },{ q:'春天什么开了？', options:['花','门','窗','书'], correct:0 }] },
        { id:'hrex_018', title:'看电视', titleEn:'Watching TV', hsk:1, passage:'晚上我在家看电视。我喜欢看动画片。今天的动画片很有意思。我看了半小时。', questions:[{ q:'他喜欢看什么？', options:['新闻','动画片','电影','体育'], correct:1 },{ q:'他看了多长时间？', options:['二十分钟','半小时','一小时','两小时'], correct:1 }] },
        { id:'hrex_019', title:'动物园', titleEn:'Zoo', hsk:1, passage:'星期日我们去动物园。动物园里有大象、老虎和猴子。猴子最可爱。', questions:[{ q:'他们去了哪里？', options:['公园','动物园','学校','商店'], correct:1 },{ q:'什么最可爱？', options:['大象','老虎','猴子','鸟'], correct:2 }] },
        { id:'hrex_020', title:'画画', titleEn:'Drawing', hsk:1, passage:'我喜欢画画。今天我画了一棵大树和一朵红花。妈妈说我画得很好看。', questions:[{ q:'他喜欢做什么？', options:['唱歌','跳舞','画画','写字'], correct:2 },{ q:'他画了什么？', options:['大树和红花','小猫和小狗','房子和车','太阳和月亮'], correct:0 }] },
        { id:'hrex_021', title:'踢足球', titleEn:'Playing Soccer', hsk:1, passage:'下午我和同学踢足球。我们玩得很开心。我进了一个球。大家都为我高兴。', questions:[{ q:'他和谁踢足球？', options:['老师','同学','哥哥','爸爸'], correct:1 },{ q:'他进了几个球？', options:['零个','一个','两个','三个'], correct:1 }] },
        { id:'hrex_022', title:'睡觉', titleEn:'Sleeping', hsk:1, passage:'晚上九点半了。我困了。我去刷牙洗脸。然后上床睡觉。晚安。', questions:[{ q:'现在几点了？', options:['八点半','九点','九点半','十点'], correct:2 },{ q:'睡觉前他要做什么？', options:['吃饭','看书','刷牙洗脸','洗澡'], correct:2 }] },
        { id:'hrex_023', title:'我的学校', titleEn:'My School', hsk:1, passage:'我的学校很大。学校里有教学楼和操场。操场上有篮球架。我很喜欢我的学校。', questions:[{ q:'学校大吗？', options:['很小','不大','很大','不知道'], correct:2 },{ q:'操场上有什么？', options:['足球门','篮球架','乒乓球台','跑道'], correct:1 }] },
        { id:'hrex_024', title:'吃水果', titleEn:'Eating Fruit', hsk:1, passage:'我喜欢吃水果。苹果、香蕉和葡萄我都喜欢。水果很健康。我每天吃水果。', questions:[{ q:'文中提到了几种水果？', options:['两种','三种','四种','五种'], correct:1 },{ q:'水果怎么样？', options:['很贵','很健康','很甜','很大'], correct:1 }] },
        { id:'hrex_025', title:'坐飞机', titleEn:'Taking a Plane', hsk:1, passage:'暑假我们坐飞机去旅行。这是我第一次坐飞机。飞机飞得很高。我很激动。', questions:[{ q:'他们怎么去旅行？', options:['坐火车','坐飞机','坐汽车','坐船'], correct:1 },{ q:'这是他第几次坐飞机？', options:['第一次','第二次','第三次','第四次'], correct:0 }] },
        { id:'hrex_026', title:'电话号码', titleEn:'Phone Number', hsk:1, passage:'我的电话号码是13812345678。你记住了吗？你可以给我打电话。', questions:[{ q:'这是什么？', options:['门牌号','电话号码','身份证号','车号'], correct:1 },{ q:'他让别人做什么？', options:['写信','发短信','打电话','来家里'], correct:2 }] },
        { id:'hrex_027', title:'我的老师', titleEn:'My Teacher', hsk:1, passage:'王老师是我的中文老师。她很年轻。她说话很慢。我们都很喜欢她。', questions:[{ q:'老师姓什么？', options:['李','王','张','刘'], correct:1 },{ q:'老师说话怎么样？', options:['很快','很慢','很大声','很小声'], correct:1 }] },
        { id:'hrex_028', title:'去超市', titleEn:'Going to the Supermarket', hsk:1, passage:'我和妈妈去超市。我们买了牛奶、面包和鸡蛋。一共花了三十块钱。', questions:[{ q:'他们买了什么？', options:['牛奶面包鸡蛋','水果蔬菜肉','饮料零食','米面油'], correct:0 },{ q:'一共花了多少钱？', options:['二十','三十','四十','五十'], correct:1 }] },
        { id:'hrex_029', title:'夏天', titleEn:'Summer', hsk:1, passage:'夏天很热。我喜欢吃冰淇淋。我也喜欢去游泳。夏天可以穿裙子。', questions:[{ q:'夏天天气怎么样？', options:['很冷','很热','很凉快','很暖和'], correct:1 },{ q:'夏天他喜欢做什么？', options:['滑雪','游泳','跑步','打球'], correct:1 }] },
        { id:'hrex_030', title:'我的爱好', titleEn:'My Hobby', hsk:1, passage:'我喜欢听音乐。我每天都要听。音乐让我很开心。我也喜欢唱歌。', questions:[{ q:'他喜欢做什么？', options:['听音乐','看电视','看书','玩游戏'], correct:0 },{ q:'音乐让他怎么样？', options:['难过','开心','累','困'], correct:1 }] },
        { id:'hrex_031', title:'奶奶', titleEn:'Grandma', hsk:1, passage:'我的奶奶六十岁了。她头发白了。奶奶对我很好。她经常给我做好吃的。', questions:[{ q:'奶奶多大年纪？', options:['五十岁','六十岁','七十岁','八十岁'], correct:1 },{ q:'奶奶经常做什么？', options:['买玩具','做好吃的','买衣服','讲故事'], correct:1 }] },
        { id:'hrex_032', title:'学汉字', titleEn:'Learning Characters', hsk:1, passage:'我在学汉字。汉字很难写。但是很有意思。我每天写十个汉字。', questions:[{ q:'他在学什么？', options:['英文','汉字','数学','画画'], correct:1 },{ q:'他每天写几个汉字？', options:['五个','八个','十个','十五个'], correct:2 }] },
        { id:'hrex_033', title:'一杯牛奶', titleEn:'A Glass of Milk', hsk:1, passage:'早上我喝一杯牛奶。牛奶对身体好。我还吃了一个面包。早饭很重要。', questions:[{ q:'早上他喝了什么？', options:['水','牛奶','果汁','茶'], correct:1 },{ q:'他还吃了什么？', options:['鸡蛋','面包','蛋糕','包子'], correct:1 }] },
        { id:'hrex_034', title:'公园里', titleEn:'In the Park', hsk:1, passage:'公园里有很多人。有的人在散步，有的人在跑步。孩子们在玩滑梯。', questions:[{ q:'公园里人多吗？', options:['不多','很多','没有人','很少'], correct:1 },{ q:'孩子们在做什么？', options:['跑步','散步','玩滑梯','看书'], correct:2 }] },
        { id:'hrex_035', title:'我的自行车', titleEn:'My Bicycle', hsk:1, passage:'我有一辆自行车。它是黑色的。我每天骑自行车去学校。骑车很快。', questions:[{ q:'自行车是什么颜色？', options:['白色','黑色','红色','蓝色'], correct:1 },{ q:'他每天怎么去学校？', options:['走路','骑自行车','坐车','跑步'], correct:1 }] },
        { id:'hrex_036', title:'冬天', titleEn:'Winter', hsk:1, passage:'冬天很冷。下雪了。地上白白的。我和朋友堆雪人。我们玩得很高兴。', questions:[{ q:'冬天天气怎么样？', options:['很热','很冷','很暖和','很凉快'], correct:1 },{ q:'他们做了什么？', options:['滑雪','堆雪人','打雪仗','滑冰'], correct:1 }] },
        { id:'hrex_037', title:'我的哥哥', titleEn:'My Older Brother', hsk:1, passage:'我有个哥哥。他比我大五岁。哥哥很高。他在大学学习。我很少见到他。', questions:[{ q:'哥哥在哪里学习？', options:['中学','大学','小学','幼儿园'], correct:1 },{ q:'哥哥比他大几岁？', options:['三岁','四岁','五岁','六岁'], correct:2 }] },
        { id:'hrex_038', title:'去图书馆', titleEn:'Going to the Library', hsk:1, passage:'星期天我去图书馆。图书馆里有很多书。我借了两本书。一本是故事书。', questions:[{ q:'图书馆里有什么？', options:['很多书','很多花','很多人','很多吃的'], correct:0 },{ q:'他借了几本书？', options:['一本','两本','三本','四本'], correct:1 }] },
        { id:'hrex_039', title:'看医生', titleEn:'Seeing a Doctor', hsk:1, passage:'我生病了。妈妈带我去医院。医生说我感冒了。要吃药多喝水。', questions:[{ q:'他怎么了？', options:['感冒了','肚子疼','头疼','牙疼'], correct:0 },{ q:'医生让他做什么？', options:['多运动','吃药多喝水','多睡觉','多吃东西'], correct:1 }] },
        { id:'hrex_040', title:'中秋节', titleEn:'Mid-Autumn Festival', hsk:1, passage:'中秋节到了。我们吃月饼。月饼很甜。晚上我们看月亮。月亮很圆。', questions:[{ q:'中秋节吃什么？', options:['饺子','月饼','粽子','汤圆'], correct:1 },{ q:'晚上的月亮怎么样？', options:['不圆','很圆','很小','看不到'], correct:1 }] },
        { id:'hrex_041', title:'数数', titleEn:'Counting', hsk:1, passage:'我在学数数。一、二、三、四、五。我会数到一百。数数很有意思。', questions:[{ q:'他在学什么？', options:['写字','数数','画画','唱歌'], correct:1 },{ q:'他会数到多少？', options:['五十','一百','两百','一千'], correct:1 }] },
        { id:'hrex_042', title:'我的笔', titleEn:'My Pen', hsk:1, passage:'我有一支新笔。它是妈妈给我买的。笔是蓝色的。写字很好看。我很喜欢。', questions:[{ q:'笔是谁买的？', options:['爸爸','妈妈','哥哥','朋友'], correct:1 },{ q:'笔是什么颜色？', options:['红色','黑色','蓝色','绿色'], correct:2 }] },
        { id:'hrex_043', title:'去海边', titleEn:'Going to the Beach', hsk:1, passage:'夏天我们去海边玩。海水蓝蓝的。沙滩软软的。我捡了很多贝壳。', questions:[{ q:'他们去哪里玩？', options:['公园','海边','山上','河边'], correct:1 },{ q:'他捡了什么？', options:['石头','贝壳','沙子','螃蟹'], correct:1 }] },
        { id:'hrex_044', title:'狗和猫', titleEn:'Dog and Cat', hsk:1, passage:'我家有狗和猫。狗叫旺旺。猫叫咪咪。它们经常一起玩。是好朋友。', questions:[{ q:'狗叫什么名字？', options:['咪咪','旺旺','花花','小黑'], correct:1 },{ q:'它们经常一起做什么？', options:['打架','玩','吃饭','睡觉'], correct:1 }] },
        { id:'hrex_045', title:'我的帽子', titleEn:'My Hat', hsk:1, passage:'我有一顶红色的帽子。夏天我戴帽子遮太阳。冬天我戴帽子保暖。', questions:[{ q:'帽子是什么颜色？', options:['白色','蓝色','红色','黄色'], correct:2 },{ q:'冬天戴帽子做什么？', options:['好看','保暖','遮太阳','防雨'], correct:1 }] },
        { id:'hrex_046', title:'爷爷的茶', titleEn:'Grandpa Tea', hsk:1, passage:'爷爷喜欢喝茶。他每天都要泡茶。茶很香。我也喜欢喝爷爷泡的茶。', questions:[{ q:'爷爷喜欢喝什么？', options:['水','果汁','茶','牛奶'], correct:2 },{ q:'他每天都要做什么？', options:['泡茶','买茶','洗茶壶','看报纸'], correct:0 }] },
        { id:'hrex_047', title:'运动会', titleEn:'Sports Day', hsk:1, passage:'今天学校开运动会。我参加跑步比赛。我跑得很快。得了第一名。', questions:[{ q:'他参加了什么比赛？', options:['跳远','跑步','跳绳','踢球'], correct:1 },{ q:'他得了第几名？', options:['第二名','第三名','第一名','第四名'], correct:2 }] },
        { id:'hrex_048', title:'月亮', titleEn:'The Moon', hsk:1, passage:'晚上天上的月亮很美。月亮有时候圆有时候弯。我喜欢看月亮。', questions:[{ q:'什么时候看月亮？', options:['早上','中午','晚上','下午'], correct:2 },{ q:'月亮是什么样的？', options:['一直圆','一直弯','有时候圆有时候弯','每天不同'], correct:2 }] },
        { id:'hrex_049', title:'学唱歌', titleEn:'Learning to Sing', hsk:1, passage:'我喜欢唱歌。我在学校学唱歌。老师教我们唱中文歌。唱歌很快乐。', questions:[{ q:'他在学校学什么？', options:['跳舞','唱歌','画画','写字'], correct:1 },{ q:'老师教什么歌？', options:['英文歌','中文歌','日文歌','法文歌'], correct:1 }] },
        { id:'hrex_050', title:'新年', titleEn:'New Year', hsk:1, passage:'新年到了。我们一家人在一起吃饭。爸爸做了很多好吃的菜。我很开心。', questions:[{ q:'新年他们做什么？', options:['出门玩','一起吃饭','看电视','睡觉'], correct:1 },{ q:'谁做了菜？', options:['妈妈','爸爸','奶奶','爷爷'], correct:1 }] },
        { id:'hrex_051', title:'在教室', titleEn:'In the Classroom', hsk:1, passage:'教室里有很多桌子和椅子。黑板是黑色的。同学们正在上课。很安静。', questions:[{ q:'教室里有什么？', options:['床和桌子','桌子和椅子','电视和沙发','电脑'], correct:1 },{ q:'同学们在做什么？', options:['玩','吃饭','上课','睡觉'], correct:2 }] },
        { id:'hrex_052', title:'吃饺子', titleEn:'Eating Dumplings', hsk:1, passage:'今天是冬至。我们吃饺子。饺子很好吃。我吃了十五个饺子。很饱了。', questions:[{ q:'今天是什么节日？', options:['春节','冬至','中秋','端午'], correct:1 },{ q:'他吃了多少个饺子？', options:['十个','十二个','十五个','二十个'], correct:2 }] },
        { id:'hrex_053', title:'我的手表', titleEn:'My Watch', hsk:1, passage:'爸爸送给我一块手表。手表是白色的。它可以看时间。我每天戴着它。', questions:[{ q:'手表是谁送的？', options:['妈妈','爸爸','哥哥','爷爷'], correct:1 },{ q:'手表有什么用？', options:['看时间','看天气','打电话','听音乐'], correct:0 }] },
        { id:'hrex_054', title:'去爬山', titleEn:'Climbing a Mountain', hsk:1, passage:'今天天气很好。我们去爬山。山很高。我慢慢爬。终于到了山顶。', questions:[{ q:'他们去做什么？', options:['散步','爬山','跑步','骑车'], correct:1 },{ q:'山怎么样？', options:['不高','很高','很小','很平'], correct:1 }] },
        { id:'hrex_055', title:'我的裙子', titleEn:'My Dress', hsk:1, passage:'我有一条花裙子。是阿姨送给我的。穿上很漂亮。我常常穿它去学校。', questions:[{ q:'裙子是什么样的？', options:['蓝色','红色','花的','白色'], correct:2 },{ q:'谁送的裙子？', options:['妈妈','奶奶','阿姨','姐姐'], correct:2 }] },
        { id:'hrex_056', title:'太阳', titleEn:'The Sun', hsk:1, passage:'太阳从东边升起。太阳是红色的。太阳给我们光和热。我们需要太阳。', questions:[{ q:'太阳从哪里升起？', options:['西边','南边','北边','东边'], correct:3 },{ q:'太阳是什么颜色？', options:['黄色','红色','金色','白色'], correct:1 }] },
        { id:'hrex_057', title:'在餐厅', titleEn:'At the Restaurant', hsk:1, passage:'我们坐在餐厅里。服务员来了。我们要了两碗米饭和三个菜。菜很香。', questions:[{ q:'他们坐在哪里？', options:['家里','餐厅','学校','公园'], correct:1 },{ q:'他们要了几碗米饭？', options:['一碗','两碗','三碗','四碗'], correct:1 }] },
        { id:'hrex_058', title:'小鸟', titleEn:'Little Bird', hsk:1, passage:'树上有一只小鸟。小鸟在唱歌。它的歌声很好听。我喜欢听小鸟唱歌。', questions:[{ q:'小鸟在哪里？', options:['屋顶','树上','地上','天上'], correct:1 },{ q:'小鸟在做什么？', options:['飞','吃虫子','唱歌','睡觉'], correct:2 }] },
        { id:'hrex_059', title:'做作业', titleEn:'Doing Homework', hsk:1, passage:'放学了。我回家做作业。数学作业很难。我写了一个小时才写好。', questions:[{ q:'他回家做什么？', options:['玩','吃饭','做作业','看电视'], correct:2 },{ q:'什么作业很难？', options:['中文','英文','数学','画画'], correct:2 }] },
        { id:'hrex_060', title:'晚安', titleEn:'Good Night', hsk:1, passage:'天黑了。我要睡觉了。妈妈对我说晚安。我说妈妈晚安。好梦。', questions:[{ q:'什么时候了？', options:['早上','中午','下午','晚上'], correct:3 },{ q:'妈妈对他说什么？', options:['早上好','你好','晚安','再见'], correct:2 }] },
        { id:'hrex_061', title:'去北京旅游', titleEn:'Traveling to Beijing', hsk:2, passage:'去年暑假我和爸爸妈妈一起去北京旅游。我们看了天安门和故宫。北京很大，人也很多。我们玩得很开心。', questions:[{ q:'他们去了哪个城市？', options:['上海','北京','广州','深圳'], correct:1 },{ q:'他们参观了什么地方？', options:['天安门和故宫','长城','颐和园','天坛'], correct:0 },{ q:'他们觉得北京怎么样？', options:['很小','人很少','很大','很旧'], correct:2 }] },
        { id:'hrex_062', title:'我的周末', titleEn:'My Weekend', hsk:2, passage:'星期六上午我打扫房间，下午去超市买东西。星期天我和朋友一起打篮球。周末过得很愉快。', questions:[{ q:'星期六上午他做什么？', options:['去超市','打扫房间','打篮球','看书'], correct:1 },{ q:'星期天他和谁打篮球？', options:['哥哥','同学','朋友','爸爸'], correct:2 }] },
        { id:'hrex_063', title:'学做饭', titleEn:'Learning to Cook', hsk:2, passage:'妈妈教我做西红柿炒鸡蛋。先把西红柿切好，再把鸡蛋打好，然后放在锅里炒。我学会了，很高兴。', questions:[{ q:'妈妈教他做什么菜？', options:['西红柿炒鸡蛋','炒青菜','红烧肉','鱼汤'], correct:0 },{ q:'他学完后觉得怎么样？', options:['很难','很高兴','不想学了','太麻烦了'], correct:1 }] },
        { id:'hrex_064', title:'坐地铁', titleEn:'Taking the Subway', hsk:2, passage:'我每天坐地铁去上班。地铁很快也很方便。今天地铁上人不多，我找到了座位。可以看手机了。', questions:[{ q:'他怎么去上班？', options:['坐公共汽车','坐地铁','开车','走路'], correct:1 },{ q:'今天地铁上人多吗？', options:['很多','不多','没有人','很挤'], correct:1 }] },
        { id:'hrex_065', title:'看比赛', titleEn:'Watching a Game', hsk:2, passage:'昨天我和同学去看足球比赛。红队赢了，三比一。球员们跑得很快。观众们都在喊加油。', questions:[{ q:'他们去看什么比赛？', options:['篮球','足球','排球','乒乓球'], correct:1 },{ q:'红队进了几个球？', options:['一个','两个','三个','四个'], correct:2 }] },
        { id:'hrex_066', title:'图书馆借书', titleEn:'Borrowing Books', hsk:2, passage:'我去图书馆还书，又借了两本新书。一本是小说，一本是历史书。图书管理员说可以借一个月。', questions:[{ q:'他去图书馆做什么？', options:['看书','还书和借书','买书','找朋友'], correct:1 },{ q:'可以借多长时间？', options:['一周','两周','一个月','两个月'], correct:2 }] },
        { id:'hrex_067', title:'我的家乡', titleEn:'My Hometown', hsk:2, passage:'我的家乡在一个小城市。那里空气很好。马路很干净。人也不多。我喜欢我的家乡，它很美。', questions:[{ q:'他的家乡在哪里？', options:['大城市','小城市','农村','海边'], correct:1 },{ q:'家乡的马路怎么样？', options:['很脏','很干净','很窄','很吵'], correct:1 }] },
        { id:'hrex_068', title:'买手机', titleEn:'Buying a Phone', hsk:2, passage:'我想买一个新手机。旧手机太慢了。我看中了一款黑色的。价钱是两千五百块。我决定下个月买。', questions:[{ q:'他为什么要买新手机？', options:['旧手机丢了','旧手机太慢','新手机好看','朋友送的'], correct:1 },{ q:'新手机多少钱？', options:['两千块','两千五百块','三千块','三千五百块'], correct:1 }] },
        { id:'hrex_069', title:'去医院', titleEn:'Going to the Hospital', hsk:2, passage:'我牙疼了好几天。今天妈妈带我去医院看牙。医生检查后说有一个蛀牙。要补一下。不是很疼。', questions:[{ q:'他哪里不舒服？', options:['头疼','肚子疼','牙疼','腿疼'], correct:2 },{ q:'医生说怎么办？', options:['拔牙','吃药','补牙','洗牙'], correct:2 }] },
        { id:'hrex_070', title:'生日礼物', titleEn:'Birthday Gift', hsk:2, passage:'朋友过生日，我送了他一本书。他非常喜欢。他说他正好想看这本书。我也很高兴他喜欢我送的礼物。', questions:[{ q:'他送了朋友什么礼物？', options:['蛋糕','书','衣服','玩具'], correct:1 },{ q:'朋友收到礼物后怎么样？', options:['不喜欢','很高兴','觉得太贵','想要别的'], correct:1 }] },
        { id:'hrex_071', title:'天气变化', titleEn:'Weather Change', hsk:2, passage:'早上出门的时候还是晴天，中午突然下起了大雨。我没有带伞。只好在商店里等了一会儿。雨停了我才回家。', questions:[{ q:'早上天气怎么样？', options:['下雨','晴天','刮风','阴天'], correct:1 },{ q:'他在哪里躲雨？', options:['家里','学校','商店','车站'], correct:2 }] },
        { id:'hrex_072', title:'养花', titleEn:'Growing Flowers', hsk:2, passage:'妈妈喜欢养花。阳台上有很多花。她每天给花浇水。花开的时候很漂亮。有时候她还会给花施肥。', questions:[{ q:'妈妈喜欢做什么？', options:['种菜','养花','画画','做饭'], correct:1 },{ q:'她每天给花做什么？', options:['浇水','晒太阳','施肥','剪枝'], correct:0 }] },
        { id:'hrex_073', title:'去邮局', titleEn:'Going to the Post Office', hsk:2, passage:'我要给远方的朋友寄一封信。我去邮局买了邮票。把信寄出去了。邮局的人说大概五天能到。', questions:[{ q:'他去邮局做什么？', options:['取钱','寄信','买报纸','交电话费'], correct:1 },{ q:'信要几天能到？', options:['三天','五天','一周','十天'], correct:1 }] },
        { id:'hrex_074', title:'看电影', titleEn:'Watching a Movie', hsk:2, passage:'晚上我和女朋友去看电影。电影是八点开始的。我们买了爆米花和可乐。电影很好看，有两个小时。', questions:[{ q:'电影几点开始？', options:['七点','七点半','八点','八点半'], correct:2 },{ q:'他们买了什么吃的？', options:['薯片和可乐','爆米花和可乐','瓜子和水','冰激凌'], correct:1 }] },
        { id:'hrex_075', title:'做运动', titleEn:'Doing Exercise', hsk:2, passage:'医生说我太胖了，要多运动。现在我每天早起跑步半个小时。晚上吃完饭了再散步。一个月瘦了五斤。', questions:[{ q:'医生说他怎么了？', options:['太瘦了','太胖了','太矮了','太累了'], correct:1 },{ q:'他每天跑步多长时间？', options:['二十分钟','半小时','四十分钟','一小时'], correct:1 }] },
        { id:'hrex_076', title:'去海边度假', titleEn:'Beach Vacation', hsk:2, passage:'今年夏天我们去海边度假。海水很蓝，沙滩很白。我每天游泳和晒太阳。还吃了很多海鲜。真舒服。', questions:[{ q:'他们去哪里度假？', options:['山上','海边','城市','乡村'], correct:1 },{ q:'他每天做什么？', options:['爬山','滑雪','游泳晒太阳','逛街'], correct:2 }] },
        { id:'hrex_077', title:'学英语', titleEn:'Learning English', hsk:2, passage:'我每天背二十个英语单词。早上起床后和晚上睡觉前各记一遍。我的英语越来越好了。能看懂简单的文章了。', questions:[{ q:'他每天背多少个单词？', options:['十个','十五个','二十个','三十个'], correct:2 },{ q:'他什么时候记单词？', options:['中午和下午','早上和晚上','下午和晚上','早上和中午'], correct:1 }] },
        { id:'hrex_078', title:'坐火车', titleEn:'Taking the Train', hsk:2, passage:'我从北京坐火车去上海。火车开了五个小时。车厢里很干净。我在车上看了会儿书，又睡了一觉。到站了。', questions:[{ q:'他坐火车去哪里？', options:['广州','上海','南京','杭州'], correct:1 },{ q:'火车开了几个小时？', options:['四个','五个','六个','七个'], correct:1 }] },
        { id:'hrex_079', title:'去银行', titleEn:'Going to the Bank', hsk:2, passage:'星期六我去银行办业务。银行的号码排到一百多号了。我等了半个小时。我取了点钱，想买一件新衣服。', questions:[{ q:'他什么时候去银行？', options:['星期一','星期三','星期六','星期日'], correct:2 },{ q:'他等了多长时间？', options:['十分钟','二十分钟','半小时','一小时'], correct:2 }] },
        { id:'hrex_080', title:'宠物狗', titleEn:'Pet Dog', hsk:2, passage:'我家养了一只白色的宠物狗。它很聪明，会听很多口令。每天我放学回家，它都会在门口等我。', questions:[{ q:'他家的狗是什么颜色？', options:['黑色','棕色','白色','黄色'], correct:2 },{ q:'每天放学它做什么？', options:['睡觉','在门口等他','吃东西','玩球'], correct:1 }] },
        { id:'hrex_081', title:'找房子', titleEn:'Finding an Apartment', hsk:2, passage:'我在公司附近找了一个房子。一个月房租一千五百块。房子不大，但是很干净。走路十分钟就到公司了。', questions:[{ q:'房子在哪里？', options:['学校附近','公司附近','市中心','公园旁边'], correct:1 },{ q:'房租多少钱一个月？', options:['一千','一千五百','两千','两千五百'], correct:1 }] },
        { id:'hrex_082', title:'学游泳', titleEn:'Learning to Swim', hsk:2, passage:'暑假我去学游泳。老师教得很好。一开始我很害怕，不敢下水。后来我慢慢学会了。现在我可以游五十米了。', questions:[{ q:'他什么时候学游泳？', options:['寒假','暑假','周末','每天'], correct:1 },{ q:'现在他能游多远？', options:['二十米','三十米','五十米','一百米'], correct:2 }] },
        { id:'hrex_083', title:'去公园野餐', titleEn:'Picnic in the Park', hsk:2, passage:'天气好的时候，我们一家人去公园野餐。妈妈准备了三明治和水果。爸爸带了饮料。我们在草地上吃得很开心。', questions:[{ q:'他们去哪里野餐？', options:['山上','河边','公园','海边'], correct:2 },{ q:'妈妈准备了什么？', options:['三明治和水果','汉堡和薯条','米饭和菜','面包和牛奶'], correct:0 }] },
        { id:'hrex_084', title:'看电视新闻', titleEn:'Watching the News', hsk:2, passage:'爸爸每天晚上七点看新闻。他说看新闻可以知道每天发生了什么事。有时候我也跟着他一起看。', questions:[{ q:'爸爸什么时候看新闻？', options:['早上七点','中午十二点','晚上七点','晚上十点'], correct:2 },{ q:'爸爸为什么看新闻？', options:['喜欢看广告','知道发生了什么事','学习外语','打发时间'], correct:1 }] },
        { id:'hrex_085', title:'买电脑', titleEn:'Buying a Computer', hsk:2, passage:'我存了半年的钱，终于买了一台新电脑。这台电脑很快，屏幕也很大。我现在可以用它来学习和玩游戏了。', questions:[{ q:'他存了多久的钱？', options:['三个月','半年','一年','两年'], correct:1 },{ q:'新电脑怎么样？', options:['很慢','屏幕大速度快','很便宜','很小'], correct:1 }] },
        { id:'hrex_086', title:'理发', titleEn:'Getting a Haircut', hsk:2, passage:'我的头发太长了。我去理发店理发。理发师问我要剪什么样的。我说剪短一点就行了。理完发我觉得很清爽。', questions:[{ q:'他为什么去理发？', options:['头发太脏','头发太长','想换发型','陪朋友'], correct:1 },{ q:'理完发他觉得怎么样？', options:['后悔了','很清爽','不好看','太短了'], correct:1 }] },
        { id:'hrex_087', title:'做蛋糕', titleEn:'Making a Cake', hsk:2, passage:'妈妈教我做蛋糕。我们把鸡蛋、面粉和糖放在一起搅拌。然后放进烤箱里烤。三十分钟后蛋糕就做好了。很香。', questions:[{ q:'做蛋糕需要什么材料？', options:['鸡蛋面粉糖','米和水','肉和菜','水果'], correct:0 },{ q:'蛋糕烤了多长时间？', options:['二十分钟','三十分钟','四十分钟','一小时'], correct:1 }] },
        { id:'hrex_088', title:'去健身房', titleEn:'Going to the Gym', hsk:2, passage:'我办了一张健身卡。每个星期去健身房三次。先跑步再举重。运动后洗个澡。坚持了两个月，身体好多了。', questions:[{ q:'他每星期去几次健身房？', options:['一次','两次','三次','五次'], correct:2 },{ q:'坚持了多久身体变好了？', options:['一个月','两个月','三个月','半年'], correct:1 }] },
        { id:'hrex_089', title:'下雪了', titleEn:'It Is Snowing', hsk:2, passage:'早上起来发现外面下雪了。地上白茫茫的一片。孩子们在雪地里打雪仗。我也出去堆了一个雪人。', questions:[{ q:'早上起来外面怎么了？', options:['下雨了','下雪了','刮风了','出太阳了'], correct:1 },{ q:'孩子们在做什么？', options:['堆雪人','打雪仗','滑雪','散步'], correct:1 }] },
        { id:'hrex_090', title:'坐出租车', titleEn:'Taking a Taxi', hsk:2, passage:'要迟到了，我赶紧叫了一辆出租车。司机开得很快。十分钟就到了。花了二十块钱。虽然贵了点，但是没有迟到。', questions:[{ q:'他为什么坐出租车？', options:['不挤公共汽车','要迟到了','太远了','下雨了'], correct:1 },{ q:'车费花了多少钱？', options:['十块','十五块','二十块','二十五块'], correct:2 }] },
        { id:'hrex_091', title:'交朋友', titleEn:'Making Friends', hsk:2, passage:'我在中文课上认识了一个新朋友。他叫大卫，从美国来。我们互相学习。他教我英文，我教他中文。', questions:[{ q:'新朋友叫什么？', options:['小明','大卫','约翰','汤姆'], correct:1 },{ q:'他教朋友什么？', options:['英文','中文','数学','音乐'], correct:1 }] },
        { id:'hrex_092', title:'去茶馆', titleEn:'Going to a Tea House', hsk:2, passage:'周末我和爸爸去茶馆喝茶。茶馆里很安静。我们点了绿茶和点心。茶很香，点心也很好吃。坐了俩小时。', questions:[{ q:'他们去了哪里？', options:['酒吧','咖啡馆','茶馆','饭馆'], correct:2 },{ q:'他们坐了多久？', options:['一小时','两小时','三小时','一下午'], correct:1 }] },
        { id:'hrex_093', title:'逛商场', titleEn:'Shopping at the Mall', hsk:2, passage:'星期天我和朋友去逛商场。商场很大，一共有六层。一楼是化妆品，二楼是女装，三楼是男装。我们逛了一下午。', questions:[{ q:'商场有几层？', options:['四层','五层','六层','七层'], correct:2 },{ q:'二楼卖什么？', options:['化妆品','女装','男装','电子产品'], correct:1 }] },
        { id:'hrex_094', title:'看日出', titleEn:'Watching the Sunrise', hsk:2, passage:'为了看日出，我早上五点就起床了。爬到山顶后，太阳慢慢升起来了。天空变成了红色。太美了。', questions:[{ q:'他几点起床看日出？', options:['四点','五点','六点','七点'], correct:1 },{ q:'太阳升起来时天空什么颜色？', options:['蓝色','白色','红色','金色'], correct:2 }] },
        { id:'hrex_095', title:'节日送礼', titleEn:'Gift Giving', hsk:2, passage:'过春节的时候，我去爷爷奶奶家拜年。我给他们带了一盒茶叶和一篮水果。爷爷奶奶很高兴，给了我红包。', questions:[{ q:'他带了什么礼物？', options:['蛋糕和花','茶叶和水果','酒和烟','衣服'], correct:1 },{ q:'爷爷奶奶给了他什么？', options:['玩具','红包','书','吃的'], correct:1 }] },
        { id:'hrex_096', title:'加班', titleEn:'Working Overtime', hsk:2, passage:'今天公司有很多工作要做。我加班到晚上九点。虽然很累，但是工作做完了。回家后吃了碗泡面就睡了。', questions:[{ q:'他加班到几点？', options:['七点','八点','九点','十点'], correct:2 },{ q:'回家后他做了什么？', options:['做饭','看电视','吃泡面','洗澡'], correct:2 }] },
        { id:'hrex_097', title:'坐船', titleEn:'Taking a Boat', hsk:2, passage:'在杭州旅游的时候，我们坐船游西湖。湖面很平静。风吹过来很舒服。船上还有导游介绍风景。', questions:[{ q:'他们坐船游哪里？', options:['太湖','西湖','洞庭湖','鄱阳湖'], correct:1 },{ q:'船上有什么？', options:['音乐','导游','电视','饮料'], correct:1 }] },
        { id:'hrex_098', title:'考驾照', titleEn:'Getting a Driver License', hsk:2, passage:'我报名学开车了。先考科目一，是笔试。我看了半天的书，考了九十五分。接下来要练习倒车了。', questions:[{ q:'科目一是什么考试？', options:['路考','笔试','倒车','停车'], correct:1 },{ q:'他考了多少分？', options:['八十五','九十','九十五','一百'], correct:2 }] },
        { id:'hrex_099', title:'手机坏了', titleEn:'Phone Broken', hsk:2, passage:'我的手机掉在地上摔坏了。屏幕裂了。我拿去手机店修。老板说要换屏幕，要三百块钱。只好换了。', questions:[{ q:'手机怎么了？', options:['丢了','没电了','摔坏了','被偷了'], correct:2 },{ q:'修手机花了多少钱？', options:['两百','三百','四百','五百'], correct:1 }] },
        { id:'hrex_100', title:'在飞机场', titleEn:'At the Airport', hsk:2, passage:'我们要坐飞机去旅行。提前两个小时到了机场。先换登机牌，然后托运行李。过安检后就在登机口等着。', questions:[{ q:'他们提前多久到机场？', options:['一小时','两小时','三小时','半小时'], correct:1 },{ q:'换登机牌后要做什么？', options:['吃饭','托运行李','买礼物','看手机'], correct:1 }] },
        { id:'hrex_101', title:'中秋节团圆', titleEn:'Mid-Autumn Reunion', hsk:2, passage:'中秋节是团圆的日子。在外面工作的子女都会回家。晚上一家人坐在一起吃月饼看月亮。月亮又大又圆。', questions:[{ q:'中秋节是什么日子？', options:['放假','团圆','旅游','购物'], correct:1 },{ q:'晚上他们做什么？', options:['放鞭炮','吃月饼看月亮','吃饺子','串门'], correct:1 }] },
        { id:'hrex_102', title:'穿衣服', titleEn:'Getting Dressed', hsk:2, passage:'今天降温了。妈妈让我多穿点衣服。我穿了一件毛衣和一件外套。出门的时候觉得很暖和。', questions:[{ q:'今天天气怎么样？', options:['升温了','降温了','下雨了','刮风了'], correct:1 },{ q:'他穿了什么？', options:['T恤和短裤','毛衣和外套','衬衫和西装','裙子'], correct:1 }] },
        { id:'hrex_103', title:'去菜市场', titleEn:'Going to the Market', hsk:2, passage:'早上奶奶去菜市场买菜。菜市场很热闹。青菜很新鲜。奶奶买了白菜、土豆和鱼。还买了豆腐。', questions:[{ q:'菜市场怎么样？', options:['很安静','很热闹','很小','很脏'], correct:1 },{ q:'文中提到了几种菜？', options:['三种','四种','五种','六种'], correct:1 }] },
        { id:'hrex_104', title:'洗衣服', titleEn:'Doing Laundry', hsk:2, passage:'周末我把脏衣服放进洗衣机里。倒了一些洗衣液。按了开关。洗衣机就开始洗了。三十分钟后衣服洗好了。', questions:[{ q:'他用了什么洗衣服？', options:['手洗','洗衣机','干洗店','清洁工'], correct:1 },{ q:'洗了多长时间？', options:['二十分钟','三十分钟','四十分钟','一小时'], correct:1 }] },
        { id:'hrex_105', title:'看京剧', titleEn:'Watching Beijing Opera', hsk:2, passage:'爷爷带我去看京剧。演员们穿着漂亮的衣服。他们的脸画得很特别。虽然我听不懂，但是觉得很精彩。', questions:[{ q:'他们去看了什么？', options:['电影','京剧','话剧','音乐会'], correct:1 },{ q:'演员们的脸怎么样？', options:['很普通','画得很特别','很丑','很吓人'], correct:1 }] },
        { id:'hrex_106', title:'坐高铁', titleEn:'Taking the High-Speed Rail', hsk:2, passage:'从北京到上海坐高铁只要四个多小时。高铁上很干净也很稳。可以在车上用电脑。比飞机还方便。', questions:[{ q:'北京到上海坐高铁要多久？', options:['三小时','四小时多','六小时','八小时'], correct:1 },{ q:'高铁上可以做什么？', options:['用电脑','抽烟','喝酒','跳舞'], correct:0 }] },
        { id:'hrex_107', title:'写日记', titleEn:'Keeping a Diary', hsk:2, passage:'我每天晚上写日记。把当天发生的有趣的事情记下来。有时候是开心的事，有时候是难过的事。写日记很有意思。', questions:[{ q:'他什么时候写日记？', options:['早上','中午','下午','晚上'], correct:3 },{ q:'他会在日记里记什么？', options:['天气','有趣的事情','明天的计划','别人的秘密'], correct:1 }] },
        { id:'hrex_108', title:'去唱歌', titleEn:'Going to Sing Karaoke', hsk:2, passage:'朋友约我去KTV唱歌。我们订了一个小包间。我唱了几首中文歌。朋友们说我唱得不错。我很开心。', questions:[{ q:'他们去了哪里？', options:['酒吧','KTV','电影院','游乐场'], correct:1 },{ q:'朋友们觉得他唱得怎么样？', options:['不好听','还不错','很难听','需要练习'], correct:1 }] },
        { id:'hrex_109', title:'坐公交车', titleEn:'Taking the Bus', hsk:2, passage:'今天公交车特别挤。人太多了。我被挤在中间动弹不了。下次早点出门就好了。再也不赶高峰期了。', questions:[{ q:'今天公交车上怎么样？', options:['很空','特别挤','很舒服','有座位'], correct:1 },{ q:'他决定下次怎么做？', options:['走路','早点出门','打车','骑车'], correct:1 }] },
        { id:'hrex_110', title:'我的同桌', titleEn:'My Deskmate', hsk:2, passage:'我的同桌叫王芳。她学习很好。上课认真听讲，下课也认真复习。我有不懂的问题就会问她。她都会耐心回答。', questions:[{ q:'同桌叫什么？', options:['李芳','王芳','张芳','刘芳'], correct:1 },{ q:'他有不懂的问题会怎么做？', options:['问老师','问同桌','查字典','不管了'], correct:1 }] },
        { id:'hrex_111', title:'拍照片', titleEn:'Taking Photos', hsk:2, passage:'爸爸买了一台新相机。周末我们去公园拍照。公园里的花都开了。爸爸拍了很多好看的照片。发到了朋友圈。', questions:[{ q:'爸爸买了什么？', options:['手机','电脑','相机','平板'], correct:2 },{ q:'爸爸拍了照片后做了什么？', options:['打印出来','存起来','发朋友圈','寄给朋友'], correct:2 }] },
        { id:'hrex_112', title:'喝咖啡', titleEn:'Drinking Coffee', hsk:2, passage:'我喜欢喝咖啡。每天早上都要喝一杯。喝咖啡可以提神。但是不能喝太多，喝多了晚上睡不着。', questions:[{ q:'他什么时候喝咖啡？', options:['中午','下午','晚上','早上'], correct:3 },{ q:'喝咖啡有什么作用？', options:['帮助睡觉','提神','帮助消化','解渴'], correct:1 }] },
        { id:'hrex_113', title:'养鱼', titleEn:'Keeping Fish', hsk:2, passage:'我在家里养了几条金鱼。它们在水里游来游去很好看。我每天给它们喂一次食。换水的时候要小心。', questions:[{ q:'他养了什么？', options:['猫','狗','金鱼','鸟'], correct:2 },{ q:'他每天给鱼做什么？', options:['换水','喂食','晒太阳','听音乐'], correct:1 }] },
        { id:'hrex_114', title:'第一次滑雪', titleEn:'First Time Skiing', hsk:2, passage:'冬天我们去滑雪场滑雪。这是我第一次滑雪。开始总是摔倒。后来教练教了我，慢慢就学会了。滑雪真好玩。', questions:[{ q:'这是第几次滑雪？', options:['第一次','第二次','第三次','第四次'], correct:0 },{ q:'谁教了他？', options:['朋友','教练','爸爸','自己学的'], correct:1 }] },
        { id:'hrex_115', title:'过生日', titleEn:'Celebrating Birthday', hsk:2, passage:'今天是我十岁的生日。同学们都来我家给我过生日。妈妈做了很多好吃的菜。我们吃蛋糕唱生日歌。', questions:[{ q:'今天他几岁？', options:['八岁','九岁','十岁','十一岁'], correct:2 },{ q:'同学们来做什么？', options:['学习','做客','过生日','开派对'], correct:2 }] },
        { id:'hrex_116', title:'看医生', titleEn:'Seeing the Doctor', hsk:2, passage:'最近我总是咳嗽。去看了医生。医生说我得了支气管炎。给我开了药。让我多喝水少说话。', questions:[{ q:'他最近怎么了？', options:['发烧','头疼','咳嗽','嗓子疼'], correct:2 },{ q:'医生让他做什么？', options:['多运动','多喝水少说话','住院','打针'], correct:1 }] },
        { id:'hrex_117', title:'骑共享单车', titleEn:'Riding a Shared Bike', hsk:2, passage:'现在共享单车很方便。扫码就能骑。我去附近的超市都是骑共享单车。比走路快多了。还便宜。', questions:[{ q:'怎么用共享单车？', options:['投币','扫码','办卡','买钥匙'], correct:1 },{ q:'骑共享单车有什么好处？', options:['快又便宜','舒服','安全','可以带人'], correct:0 }] },
        { id:'hrex_118', title:'去博物馆', titleEn:'Going to the Museum', hsk:2, passage:'学校组织我们去博物馆参观。博物馆里有很多古代的东西。老师给我们讲了很多历史故事。我觉得很有收获。', questions:[{ q:'谁组织去博物馆？', options:['班级','学校','老师','家长'], correct:1 },{ q:'博物馆里有什么？', options:['现代画','古代东西','新科技','动物'], correct:1 }] },
        { id:'hrex_119', title:'打太极拳', titleEn:'Doing Tai Chi', hsk:2, passage:'爷爷每天早上在公园里打太极拳。动作很慢但是很好看。他说打太极对身体好。我也跟着学了几下。', questions:[{ q:'爷爷什么时候打太极拳？', options:['中午','下午','早上','晚上'], correct:2 },{ q:'爷爷说打太极对身体怎么样？', options:['不好','好','太累','浪费时间'], correct:1 }] },
        { id:'hrex_120', title:'搬家', titleEn:'Moving House', hsk:2, passage:'我们家搬到了一个新小区。新房子比旧房子大。小区旁边有一个公园和一个超市。生活很方便。我很喜欢新家。', questions:[{ q:'新房子怎么样？', options:['比旧房子小','比旧房子大','一样大','很旧'], correct:1 },{ q:'小区旁边有什么？', options:['学校','医院','公园和超市','银行'], correct:2 }] },
        { id:'hrex_121', title:'春节的习俗', titleEn:'Spring Festival Customs', hsk:3, passage:'春节是中国最重要的节日。每年春节，人们都要回家团圆。大家贴春联、放鞭炮、吃年夜饭。小孩子最喜欢收红包。春节大概有十五天，一直到元宵节结束。', questions:[{ q:'春节有多少天？', options:['七天','十天','十五天','一个月'], correct:2 },{ q:'小孩子最喜欢什么？', options:['放鞭炮','吃年夜饭','收红包','贴春联'], correct:2 },{ q:'春节以什么节日结束？', options:['中秋节','端午节','元宵节','清明节'], correct:2 }] },
        { id:'hrex_122', title:'健康的饮食', titleEn:'Healthy Diet', hsk:3, passage:'健康的饮食对身体非常重要。我们应该多吃蔬菜和水果，少吃油炸食品。每天喝八杯水也很重要。另外，不要吃得太饱，七分饱就可以了。', questions:[{ q:'健康的饮食应该多吃什么？', options:['肉和蛋','蔬菜和水果','面包和牛奶','甜点'], correct:1 },{ q:'每天应该喝多少水？', options:['四杯','六杯','八杯','十杯'], correct:2 },{ q:'吃饭应该吃到几分饱？', options:['全饱','八分饱','七分饱','六分饱'], correct:2 }] },
        { id:'hrex_123', title:'去上海出差', titleEn:'Business Trip to Shanghai', hsk:3, passage:'上个月我去上海出差。公司安排我住在一个酒店里。白天开会，晚上和客户吃饭。上海的夜景很美。虽然工作很忙，但是我还是抽空去外滩走了走。', questions:[{ q:'他去上海做什么？', options:['旅游','出差','探亲','学习'], correct:1 },{ q:'晚上他做什么？', options:['开会','逛街','和客户吃饭','看电影'], correct:2 },{ q:'他去外滩走了走说明了什么？', options:['他很闲','他抽空看了看上海','他喜欢走路','他住在附近'], correct:1 }] },
        { id:'hrex_124', title:'手机支付', titleEn:'Mobile Payment', hsk:3, passage:'现在中国很多人都用手机支付。出门只需要带一个手机就可以了。买菜、坐车、买东西都可以扫码。手机支付非常方便，但是也要注意安全。', questions:[{ q:'手机支付需要带什么？', options:['钱包','银行卡','手机','身份证'], correct:2 },{ q:'什么地方可以用手机支付？', options:['只有超市','只有商场','很多地方都可以','只有网上'], correct:2 },{ q:'使用手机支付要注意什么？', options:['注意电量','注意安全','注意网络','注意时间'], correct:1 }] },
        { id:'hrex_125', title:'我的梦想', titleEn:'My Dream', hsk:3, passage:'我从小就有一个梦想，长大以后当一名医生。因为医生可以帮助病人解除痛苦。为了这个梦想，我一直努力学习。虽然学医很难，但是我不会放弃。', questions:[{ q:'他的梦想是什么？', options:['当老师','当医生','当科学家','当演员'], correct:1 },{ q:'他为什么有这个梦想？', options:['因为工资高','因为可以帮助病人','因为受人尊敬','因为工作轻松'], correct:1 },{ q:'他会放弃吗？', options:['会','不会','不知道','还没决定'], correct:1 }] },
        { id:'hrex_126', title:'中国的茶文化', titleEn:'Chinese Tea Culture', hsk:3, passage:'中国是茶的故乡。茶的历史非常悠久。中国人喜欢喝茶。不同地方有不同的茶。比如龙井茶、铁观音和普洱茶。喝茶不但有利于健康，还能交到朋友。', questions:[{ q:'文中提到了几种茶？', options:['两种','三种','四种','五种'], correct:1 },{ q:'喝茶有什么好处？', options:['有利于健康和交友','减肥','帮助睡眠','提神'], correct:0 },{ q:'中国是茶的什么？', options:['产地','故乡','市场','工厂'], correct:1 }] },
        { id:'hrex_127', title:'坐地铁的经历', titleEn:'Subway Experience', hsk:3, passage:'今天早上我坐地铁去上班。地铁里人很多，非常拥挤。到了换乘站的时候，很多人都跑着换车。我不小心被一个人撞了一下，包掉在地上。虽然有点不开心，但是没迟到就好。', questions:[{ q:'今天地铁里怎么样？', options:['很空','很拥挤','很安静','很干净'], correct:1 },{ q:'他被撞了以后什么掉了？', options:['手机','钱包','包','钥匙'], correct:2 },{ q:'他最后觉得怎么样？', options:['很开心','很生气','没迟到就好','很难过'], correct:2 }] },
        { id:'hrex_128', title:'春游', titleEn:'Spring Outing', hsk:3, passage:'春天来了，学校组织我们去春游。我们去了一座山上。山上的花都开了。有红色的、黄色的和紫色的。我们还在山上吃了午饭。饭后大家一起做游戏。这次春游非常愉快。', questions:[{ q:'他们去哪里春游？', options:['公园','山上','河边','海边'], correct:1 },{ q:'山上的花有什么颜色？', options:['只有红色','红黄紫','红黄白','红蓝紫'], correct:1 },{ q:'饭后他们做了什么？', options:['睡觉','回家','做游戏','爬山'], correct:2 }] },
        { id:'hrex_129', title:'网购的体验', titleEn:'Online Shopping Experience', hsk:3, passage:'现在我经常在网上买东西。网上的东西比商店里便宜。而且送货很快，今天下单明天就能到。但是网上买东西不能试。有时候买回来不合适，还得退货。', questions:[{ q:'网上的东西和店里比怎么样？', options:['更贵','更便宜','一样','质量更好'], correct:1 },{ q:'送货需要多长时间？', options:['当天到','明天到','三天到','一周到'], correct:1 },{ q:'网购有什么不好的地方？', options:['不能试','太贵','太慢','不安全'], correct:0 }] },
        { id:'hrex_130', title:'学书法', titleEn:'Learning Calligraphy', hsk:3, passage:'我参加了学校的书法社团。书法是中国传统的艺术。写书法的时候需要安静和耐心。老师教我们握笔的姿势。虽然我的字还写得不好看，但是我在慢慢进步。', questions:[{ q:'他参加了什么社团？', options:['绘画社','书法社','音乐社','舞蹈社'], correct:1 },{ q:'写书法需要什么？', options:['很快的速度','安静和耐心','很大的力气','很多的纸'], correct:1 },{ q:'他的字写得怎么样？', options:['很好看','不好看','一般','还不错'], correct:1 }] },
        { id:'hrex_131', title:'保护环境', titleEn:'Protecting the Environment', hsk:3, passage:'保护环境是每个人的责任。我们应该少用塑料袋和一次性筷子。出门尽量坐公共交通工具。垃圾分类也很重要。每个人做一点点，地球就会变得更美好。', questions:[{ q:'保护环境应该少用什么？', options:['布料','塑料袋和一次性筷子','纸张','木制品'], correct:1 },{ q:'出门应该尽量怎么样？', options:['开车','走路','坐公共交通工具','打车'], correct:2 },{ q:'我们应该怎么做？', options:['什么都不做','每个人做一点点','只做大事','等别人做'], correct:1 }] },
        { id:'hrex_132', title:'天气预报', titleEn:'Weather Forecast', hsk:3, passage:'我每天早上都会看天气预报。这样可以知道今天要不要带伞或者加衣服。天气预报有时候准有时候不准。比如昨天预报说下雨，结果一整天都是大太阳。', questions:[{ q:'他为什么看天气预报？', options:['想知道新闻','知道要不要带伞加衣服','打发时间','学习地理'], correct:1 },{ q:'天气预报准吗？', options:['每次都准','每次都不准','有时候准有时候不准','不知道'], correct:2 },{ q:'昨天实际天气怎么样？', options:['下雨了','阴天','大太阳','下雪了'], correct:2 }] },
        { id:'hrex_133', title:'去朋友家做客', titleEn:'Visiting a Friend', hsk:3, passage:'周末我去朋友家做客。朋友亲自下厨做了几个菜。虽然菜的味道一般，但是我很感动。吃完饭我们聊了很久。他告诉我他最近换工作了。新工作他很喜欢。', questions:[{ q:'朋友做了什么菜？', options:['点了外卖','亲自下厨','去饭店','叫了厨师'], correct:1 },{ q:'朋友告诉他什么消息？', options:['结婚了','换工作了','搬家了','出国了'], correct:1 },{ q:'他吃了朋友做的菜感觉怎么样？', options:['非常好吃','很感动','觉得难吃','没吃饱'], correct:1 }] },
        { id:'hrex_134', title:'机场送别', titleEn:'Farewell at the Airport', hsk:3, passage:'今天我去机场送好朋友回国。他来中国学习了两年。现在要回去了。我们拥抱告别。他说以后有机会还会再来中国。我也答应明年去他的国家看他。', questions:[{ q:'朋友在中国待了多久？', options:['一年','两年','三年','四年'], correct:1 },{ q:'朋友说了什么？', options:['不想回去','以后还会再来','不喜欢中国','马上回来'], correct:1 },{ q:'他答应了什么？', options:['去朋友的国家看他','寄礼物','写信','打电话'], correct:0 }] },
        { id:'hrex_135', title:'乘地铁的礼貌', titleEn:'Subway Etiquette', hsk:3, passage:'在地铁上要注意礼貌。应该先下后上。不要拥挤。地铁里不能吃东西，也不能大声说话。看到老人和抱小孩的人要主动让座。做一个文明的乘客。', questions:[{ q:'坐地铁应该怎么上下车？', options:['一起上下','先下后上','先上后下','随便'], correct:1 },{ q:'地铁里不能做什么？', options:['看书','听音乐','吃东西','玩手机'], correct:2 },{ q:'看到老人应该怎么做？', options:['当没看见','让座','挤过去','拍照'], correct:1 }] },
        { id:'hrex_136', title:'暑假计划', titleEn:'Summer Vacation Plan', hsk:3, passage:'暑假快到了，我计划去云南旅行。云南的风景很美。我打算先飞到昆明，然后坐火车去大理。还会去丽江古城看看。这个计划让我非常期待暑假的到来。', questions:[{ q:'他计划去哪里旅行？', options:['四川','云南','海南','新疆'], correct:1 },{ q:'他先坐什么去昆明？', options:['火车','飞机','汽车','船'], correct:1 },{ q:'他期待什么？', options:['暑假的到来','考试成绩','新手机','朋友聚会'], correct:0 }] },
        { id:'hrex_137', title:'中国传统节日', titleEn:'Traditional Chinese Festivals', hsk:3, passage:'中国有很多传统节日。春节是最重要的。端午节吃粽子、赛龙舟。中秋节吃月饼、赏月。清明节人们去扫墓。每个节日都有自己的习俗和文化。', questions:[{ q:'端午节做什么？', options:['吃月饼赏月','吃粽子赛龙舟','扫墓','贴春联'], correct:1 },{ q:'中秋节做什么？', options:['吃粽子赛龙舟','吃月饼赏月','扫墓','放鞭炮'], correct:1 },{ q:'文中提到了几个传统节日？', options:['两个','三个','四个','五个'], correct:2 }] },
        { id:'hrex_138', title:'坐飞机丢行李', titleEn:'Lost Luggage on Flight', hsk:3, passage:'这次坐飞机到目的地后，我发现行李丢了。我马上去机场的服务台报告。工作人员记下了我的信息，说找到后会联系我。两天后航空公司把我的行李送到了家里。', questions:[{ q:'到了目的地他发现了什么问题？', options:['飞机晚点','行李丢了','手机没电','钱包被偷'], correct:1 },{ q:'他去了哪里报告？', options:['警察局','服务台','酒店','航空公司'], correct:1 },{ q:'行李什么时候找到的？', options:['当天','一天后','两天后','一周后'], correct:2 }] },
        { id:'hrex_139', title:'健身房锻炼', titleEn:'Working Out at the Gym', hsk:3, passage:'最近我每隔一天去一次健身房。先做二十分钟有氧运动，然后举铁。教练给我制定了一个训练计划。坚持了一个月后，肌肉结实了一些。不过想看到明显的效果还需要更长时间。', questions:[{ q:'他多长时间去一次健身房？', options:['每天','隔天','每周一次','每月一次'], correct:1 },{ q:'教练给他做了什么？', options:['训练计划','饮食计划','体检','按摩'], correct:0 },{ q:'坚持了一个月后怎么样？', options:['效果很明显','肌肉结实了一些','变瘦了','没有任何变化'], correct:1 }] },
        { id:'hrex_140', title:'我学会了骑自行车', titleEn:'I Learned to Ride a Bike', hsk:3, passage:'小时候我一直不会骑自行车。今年夏天我终于决定学了。一开始我老是摔倒。爸爸在后面扶着车。慢慢地我掌握了平衡。现在我可以自己骑车去上学了。', questions:[{ q:'他什么时候决定学骑车？', options:['去年','今年春天','今年夏天','最近'], correct:2 },{ q:'一开始他怎么样？', options:['很顺利','老是摔倒','很害怕','很快就学会了'], correct:1 },{ q:'谁在后面扶着他？', options:['妈妈','哥哥','爸爸','朋友'], correct:2 }] },
        { id:'hrex_141', title:'垃圾分类', titleEn:'Waste Sorting', hsk:3, passage:'现在很多城市都开始实行垃圾分类。垃圾分为可回收垃圾、厨余垃圾、有害垃圾和其他垃圾。分类可以减少污染。刚开始我觉得很麻烦，现在慢慢习惯了。', questions:[{ q:'垃圾分为几类？', options:['两类','三类','四类','五类'], correct:2 },{ q:'垃圾分类有什么好处？', options:['增加垃圾','减少污染','方便运输','节约空间'], correct:1 },{ q:'他现在觉得垃圾分类怎么样？', options:['还是很麻烦','慢慢习惯了','没必要','太简单了'], correct:1 }] },
        { id:'hrex_142', title:'周末爬山', titleEn:'Weekend Hiking', hsk:3, passage:'上周末我和几个朋友去爬山。山不算高，但是很陡。我们爬了两个小时才到山顶。在山顶看到的风景非常漂亮。我们还拍了合影留念。下山后一起去吃了火锅。', questions:[{ q:'他们爬了多久到山顶？', options:['一小时','两小时','三小时','四小时'], correct:1 },{ q:'在山顶他们做了什么？', options:['吃饭','睡觉','拍照','唱歌'], correct:2 },{ q:'下山后他们去吃了什么？', options:['烤鱼','火锅','烧烤','川菜'], correct:1 }] },
        { id:'hrex_143', title:'在餐厅打工', titleEn:'Working at a Restaurant', hsk:3, passage:'暑假我在一家西餐厅打工。工作很辛苦，每天站八个小时。但是学到了很多东西。学会了怎么跟客人沟通。老板和同事对我都很好。工资虽然不高，但经验很宝贵。', questions:[{ q:'他在哪里打工？', options:['咖啡厅','西餐厅','超市','书店'], correct:1 },{ q:'他每天工作多长时间？', options:['六小时','七小时','八小时','九小时'], correct:2 },{ q:'他学到了什么？', options:['做菜','怎么跟客人沟通','管理餐厅','咖啡制作'], correct:1 }] },
        { id:'hrex_144', title:'堵车', titleEn:'Traffic Jam', hsk:3, passage:'今天早上我开车去上班，遇到了严重堵车。平时二十分钟的路程开了快一个小时。很多车主都下车看情况。原来是前面发生了车祸。没办法，只能耐心等待。', questions:[{ q:'平时上班开车要多久？', options:['十分钟','二十分钟','半小时','四十分钟'], correct:1 },{ q:'今天为什么堵车？', options:['修路','车祸','下大雨','有活动'], correct:1 },{ q:'车主们做了什么？', options:['掉头走','下车看情况','按喇叭','报警'], correct:1 }] },
        { id:'hrex_145', title:'中国功夫', titleEn:'Chinese Kung Fu', hsk:3, passage:'中国功夫很有名。我从小就喜欢看功夫电影。我觉得练功夫的人很厉害。上个月我开始学武术。练习基本功很辛苦，劈叉和踢腿都很疼。但是我会坚持下去的。', questions:[{ q:'他从小就喜欢看什么？', options:['动画片','功夫电影','电视剧','新闻'], correct:1 },{ q:'他什么时候开始学武术？', options:['去年','上个月','上周','今年'], correct:1 },{ q:'练习基本功感觉怎么样？', options:['很轻松','很辛苦','很无聊','很好玩'], correct:1 }] },
        { id:'hrex_146', title:'家乡的变化', titleEn:'Changes in Hometown', hsk:3, passage:'我三年没回家了。这次回去发现家乡变化很大。以前的小路变成了大马路。新建了很多高楼。还开了一家很大的商场。但是空气没有以前好了。', questions:[{ q:'他多久没回家了？', options:['一年','两年','三年','四年'], correct:2 },{ q:'家乡的什么变了？', options:['天气','小路变成大马路','人口变少了','物价降低了'], correct:1 },{ q:'什么没有以前好了？', options:['交通','空气','房子','学校'], correct:1 }] },
        { id:'hrex_147', title:'考试前', titleEn:'Before the Exam', hsk:3, passage:'下个星期要考试了。这几天我每天晚上都在复习。知识点很多，我有点紧张。妈妈告诉我要放松，不要给自己太大压力。我决定今天早点休息，保持好的状态。', questions:[{ q:'他什么时候考试？', options:['明天','后天','下个星期','下个月'], correct:2 },{ q:'他每天晚上做什么？', options:['看电视','玩游戏','复习','运动'], correct:2 },{ q:'妈妈告诉他什么？', options:['多看书','要放松','早点起床','别玩手机'], correct:1 }] },
        { id:'hrex_148', title:'中国火锅', titleEn:'Chinese Hotpot', hsk:3, passage:'火锅是中国人很喜欢的食物。大家围着一个锅，把各种菜和肉放进去煮。有辣的也有不辣的。冬天吃火锅最暖和。朋友聚会吃火锅气氛也很好。', questions:[{ q:'火锅怎么吃？', options:['炒着吃','煮着吃','蒸着吃','烤着吃'], correct:1 },{ q:'什么时候吃火锅最好？', options:['夏天','冬天','春天','秋天'], correct:1 },{ q:'为什么朋友聚会吃火锅？', options:['便宜','气氛好','方便','不用洗碗'], correct:1 }] },
        { id:'hrex_149', title:'我的室友', titleEn:'My Roommate', hsk:3, passage:'我的室友是一个韩国人。他来中国学中文。我们住在一起半年了。他中文说得越来越好。我们经常一起做饭。他做韩国料理，我做中国菜。互相学习了很多。', questions:[{ q:'室友是哪国人？', options:['日本人','韩国人','美国人','泰国人'], correct:1 },{ q:'他们住在一起多久了？', options:['三个月','半年','一年','两年'], correct:1 },{ q:'他们一起做什么？', options:['打游戏','唱歌','做饭','运动'], correct:2 }] },
        { id:'hrex_150', title:'买火车票', titleEn:'Buying Train Tickets', hsk:3, passage:'春节回家的人太多了。我提前半个月在网上买火车票。打开网站一看，很多车次的票都卖光了。幸好最后抢到了一张硬座票。虽然要坐十几个小时，但是能回家就满足了。', questions:[{ q:'他提前多久买火车票？', options:['一周','半个月','一个月','两天'], correct:1 },{ q:'他买到了什么票？', options:['硬座票','硬卧票','软卧票','高铁票'], correct:0 },{ q:'他需要坐多久？', options:['几个小时','十几个小时','一天一夜','两天一夜'], correct:1 }] },
        { id:'hrex_151', title:'第一次做志愿者', titleEn:'First Time Volunteering', hsk:3, passage:'上周末我第一次去做志愿者。我们去养老院看望老人。我们帮老人打扫卫生，陪他们聊天。有位老奶奶给我们讲了她年轻时候的故事。我觉得做志愿者很有意义。', questions:[{ q:'他们去了哪里做志愿者？', options:['孤儿院','养老院','医院','学校'], correct:1 },{ q:'他们帮老人做了什么？', options:['做饭','打扫卫生和聊天','洗衣服','买东西'], correct:1 },{ q:'他觉得做志愿者怎么样？', options:['很累','没意思','很有意义','浪费时间'], correct:2 }] },
        { id:'hrex_152', title:'参加婚礼', titleEn:'Attending a Wedding', hsk:3, passage:'上个周末我去参加了表哥的婚礼。婚礼在一个大酒店举行。新娘子很漂亮。新郎也很帅。仪式上他们交换了戒指。之后大家一起吃饭喝酒。气氛很热闹。', questions:[{ q:'谁的婚礼？', options:['朋友','同事','表哥','同学'], correct:2 },{ q:'婚礼在哪里举行？', options:['家里','教堂','酒店','公园'], correct:2 },{ q:'仪式上他们做了什么？', options:['切蛋糕','交换戒指','开香槟','跳舞'], correct:1 }] },
        { id:'hrex_153', title:'失眠', titleEn:'Insomnia', hsk:3, passage:'最近我老是失眠。躺在床上翻来覆去睡不着。可能是最近工作压力太大了。我试着在睡前喝牛奶和听轻音乐。效果还不错。希望大家都能睡个好觉。', questions:[{ q:'他遇到了什么问题？', options:['头疼','失眠','胃疼','没胃口'], correct:1 },{ q:'失眠可能是什么原因？', options:['吃太多了','工作压力大','运动太多','天气太热'], correct:1 },{ q:'他试了什么方法？', options:['吃药','喝酒','喝牛奶听音乐','运动'], correct:2 }] },
        { id:'hrex_154', title:'手机丢在出租车', titleEn:'Phone Left in Taxi', hsk:3, passage:'昨天我不小心把手机丢在出租车上了。发现的时候车已经开走了。我赶紧打电话给自己的号码。司机接了电话，说会给我送回来。真是遇到了好人。为了表示感谢，我给了司机一些钱。', questions:[{ q:'他把手机丢在哪里了？', options:['地铁','出租车','商店','家'], correct:1 },{ q:'谁接了电话？', options:['乘客','司机','路人','警察'], correct:1 },{ q:'他为了表示感谢做了什么？', options:['请吃饭','给了钱','送了礼物','写了表扬信'], correct:1 }] },
        { id:'hrex_155', title:'学做中国菜', titleEn:'Learning Chinese Cooking', hsk:3, passage:'我一直想学做中国菜。这周末妈妈终于教我做了红烧肉。先把肉切块，然后放锅里炒。加入酱油和糖。最后用小火慢炖一个小时。做出来味道很好。很有成就感。', questions:[{ q:'妈妈教他做了什么菜？', options:['鱼香肉丝','红烧肉','麻婆豆腐','宫保鸡丁'], correct:1 },{ q:'最后要用什么火炖？', options:['大火','中火','小火','不用火'], correct:2 },{ q:'炖了多长时间？', options:['半小时','四十五分钟','一小时','两小时'], correct:2 }] },
        { id:'hrex_156', title:'去理发店', titleEn:'At the Hair Salon', hsk:3, passage:'我去理发店剪头发。理发师问我想要什么发型。我给他看了一张照片。他按照照片给我剪了。剪完以后我发现跟照片上不太一样。不过也不算难看。下次换个理发师试试。', questions:[{ q:'他给理发师看了什么？', options:['自己的照片','别人的照片','杂志','手机'], correct:1 },{ q:'剪完后他觉得怎么样？', options:['完全一样','不太一样但不算难看','很难看','非常满意'], correct:1 },{ q:'下次他打算怎么做？', options:['还找这个理发师','换一个理发师','不剪了','自己剪'], correct:1 }] },
        { id:'hrex_157', title:'带父母旅游', titleEn:'Traveling with Parents', hsk:3, passage:'今年国庆节我带父母去西安旅游。西安是古都，有很多历史景点。我们去了兵马俑、大雁塔和回民街。父母玩得很开心。我觉得能带父母出来玩是一件很幸福的事情。', questions:[{ q:'他们去了哪个城市？', options:['北京','南京','西安','洛阳'], correct:2 },{ q:'文中提到了几个景点？', options:['两个','三个','四个','五个'], correct:1 },{ q:'他带父母旅游觉得怎么样？', options:['很累','很幸福','很花钱','很麻烦'], correct:1 }] },
        { id:'hrex_158', title:'学钢琴', titleEn:'Learning Piano', hsk:3, passage:'我从小就学钢琴。已经学了八年了。每天都要练习一个小时。有时候觉得很枯燥。但是弹出一首好听的曲子的时候，觉得一切都值得。最近我在准备钢琴考级。', questions:[{ q:'他学钢琴多久了？', options:['五年','六年','七年','八年'], correct:3 },{ q:'他每天练习多长时间？', options:['半小时','一小时','两小时','三小时'], correct:1 },{ q:'最近他在准备什么？', options:['比赛','考级','表演','考试'], correct:1 }] },
        { id:'hrex_159', title:'下雨天的回忆', titleEn:'Rainy Day Memories', hsk:3, passage:'今天又下雨了。这让我想起小时候。那时候我最喜欢下雨天。因为可以穿着雨鞋在水坑里踩水玩。妈妈总是会骂我，但是我还是很开心。现在长大了，反而觉得下雨天出门很麻烦。', questions:[{ q:'小时候他为什么喜欢下雨天？', options:['可以不去上学','可以踩水玩','可以看到彩虹','可以吃好吃的'], correct:1 },{ q:'妈妈会怎么样？', options:['很生气','骂他','给他买雨鞋','也一起玩'], correct:1 },{ q:'现在他觉得下雨天怎么样？', options:['一样喜欢','觉得麻烦','很讨厌','无所谓'], correct:1 }] },
        { id:'hrex_160', title:'坐摩天轮', titleEn:'Riding the Ferris Wheel', hsk:3, passage:'周末女朋友带我去坐摩天轮。摩天轮很高，有一百多米。当转到最高点的时候，整个城市的景色都在脚下。非常壮观。女朋友有点害怕，一直抓着我的手。虽然票价不便宜，但是很值得。', questions:[{ q:'摩天轮多高？', options:['五十米','一百多米','两百米','三百米'], correct:1 },{ q:'到了最高点他们看到了什么？', options:['大海','整个城市','山脉','公园'], correct:1 },{ q:'女朋友怎么样？', options:['很开心','有点害怕','很兴奋','睡着了'], correct:1 }] },
        { id:'hrex_161', title:'换工作', titleEn:'Changing Jobs', hsk:3, passage:'我在现在的公司工作两年了。工资不高，而且经常加班。最近我收到了另一家公司的面试邀请。我已经去面试了。面试官对我的表现很满意。如果顺利的话，下个月就能换到新公司。', questions:[{ q:'他在现在的公司工作多久了？', options:['一年','两年','三年','四年'], correct:1 },{ q:'他为什么想换工作？', options:['离家太远','工资不高常加班','不喜欢同事','公司倒闭了'], correct:1 },{ q:'如果顺利他什么时候换？', options:['下周','下个月','三个月后','明年'], correct:1 }] },
        { id:'hrex_162', title:'在家种菜', titleEn:'Growing Vegetables at Home', hsk:3, passage:'奶奶退休后在家里的阳台上种菜。她种了小番茄、辣椒和生菜。每天早上她都会给菜浇水。看着小苗慢慢长大，很有成就感。自己种的菜没有农药，吃着也放心。', questions:[{ q:'奶奶在阳台种了什么？', options:['花','小番茄辣椒生菜','水果','草药'], correct:1 },{ q:'她每天早上做什么？', options:['施肥','捉虫','浇水','播种'], correct:2 },{ q:'自己种的菜有什么好处？', options:['便宜','没有农药','长得大','很漂亮'], correct:1 }] },
        { id:'hrex_163', title:'乘飞机晚点', titleEn:'Flight Delay', hsk:3, passage:'今天坐飞机去广州。到了机场才知道飞机晚点了。因为天气不好，要推迟两个小时。我只好在候机厅等着。买了杯咖啡，看了会儿书。虽然晚点不太好，但是安全最重要。', questions:[{ q:'飞机为什么晚点？', options:['飞机坏了','天气不好','人没到齐','机场有问题'], correct:1 },{ q:'飞机推迟了多久？', options:['一小时','两小时','三小时','四小时'], correct:1 },{ q:'他在候机厅做了什么？', options:['睡觉','吃饭','喝咖啡看书','打游戏'], correct:2 }] },
        { id:'hrex_164', title:'拔牙', titleEn:'Tooth Extraction', hsk:3, passage:'我有一个智齿长歪了。经常发炎，很疼。今天终于鼓起勇气去医院拔了。医生打了麻药，所以拔的时候不疼。但是麻药过了以后很疼。现在只能喝粥。希望快点好起来。', questions:[{ q:'他为什么要拔牙？', options:['牙坏了','智齿长歪了','牙不好看','换了新牙'], correct:1 },{ q:'拔牙的时候疼吗？', options:['很疼','不疼','有点疼','非常疼'], correct:1 },{ q:'麻药过后他只能吃什么？', options:['米饭','面条','粥','面包'], correct:2 }] },
        { id:'hrex_165', title:'买礼物给妈妈', titleEn:'Buying a Gift for Mom', hsk:3, passage:'母亲节快到了。我想给妈妈买一份礼物。去商场逛了一圈。看到一条围巾很漂亮。颜色是妈妈喜欢的蓝色。虽然价格有点贵，但是还是买了。妈妈收到礼物后很开心。', questions:[{ q:'他为什么要买礼物？', options:['妈妈生日','母亲节','过新年','妈妈要出国'], correct:1 },{ q:'他买了什么？', options:['衣服','围巾','包','化妆品'], correct:1 },{ q:'妈妈喜欢什么颜色？', options:['红色','白色','蓝色','粉色'], correct:2 }] },
        { id:'hrex_166', title:'看画展', titleEn:'Art Exhibition', hsk:3, passage:'我的画家朋友举办了一个画展。周末我去看了他的画展。他的画大多数是山水画。其中一幅画的是黄山。云雾缭绕，非常逼真。我为朋友感到骄傲。他的梦想终于实现了。', questions:[{ q:'朋友举办的是什么？', options:['音乐会','画展','摄影展','舞蹈表演'], correct:1 },{ q:'朋友画的多数是什么？', options:['人物','山水','动物','城市'], correct:1 },{ q:'朋友画的黄山怎么样？', options:['很一般','很逼真','太抽象了','不漂亮'], correct:1 }] },
        { id:'hrex_167', title:'自己修电脑', titleEn:'Fixing My Computer', hsk:3, passage:'我的电脑突然开不了机了。本来想送去维修店。但是查了一下，维修费很贵。于是我在网上搜索了教程。自己拆开检查了一下。原来是内存条松了。重新插好后就正常了。省了一笔钱。', questions:[{ q:'电脑出了什么问题？', options:['屏幕坏了','开不了机','没有声音','很慢'], correct:1 },{ q:'他为什么不去维修店？', options:['太远了','维修费很贵','没时间','懒得去'], correct:1 },{ q:'电脑的问题是什么？', options:['硬盘坏了','内存条松了','电池没电了','系统坏了'], correct:1 }] },
        { id:'hrex_168', title:'做月饼', titleEn:'Making Mooncakes', hsk:3, passage:'中秋节前，学校组织我们做月饼。面点师傅教我们包馅料和压模。我做的是豆沙馅的。放进烤箱烤二十分钟就好了。虽然做的没有买的好看，但是味道还不错。自己做的就是香。', questions:[{ q:'谁教他们做月饼？', options:['老师','面点师傅','妈妈','同学'], correct:1 },{ q:'他做的是什么馅？', options:['莲蓉','豆沙','五仁','蛋黄'], correct:1 },{ q:'烤了多久？', options:['十分钟','二十分钟','三十分钟','四十分钟'], correct:1 }] },
        { id:'hrex_169', title:'旅行时生病', titleEn:'Getting Sick While Traveling', hsk:3, passage:'在泰国旅行的时候，我突然肚子疼。可能是吃了不干净的东西。同行的朋友陪我去当地的医院。医生给我开了药。我在酒店休息了一天。虽然耽误了行程，但是身体最重要。', questions:[{ q:'他在哪里旅行时生病了？', options:['日本','泰国','韩国','越南'], correct:1 },{ q:'他为什么肚子疼？', options:['着凉了','吃了不干净的东西','水土不服','太累了'], correct:1 },{ q:'他在哪里休息了一天？', options:['医院','酒店','朋友家','机场'], correct:1 }] },
        { id:'hrex_170', title:'放风筝', titleEn:'Flying a Kite', hsk:3, passage:'今天风很大，适合放风筝。爸爸带我去广场放风筝。我的风筝是老鹰形状的。一开始怎么也飞不起来。爸爸教我要逆着风跑。风筝终于飞上天了。我高兴得跳了起来。', questions:[{ q:'今天天气怎么样？', options:['下雨','风很大','很热','下雪'], correct:1 },{ q:'他的风筝是什么形状？', options:['蝴蝶','老鹰','蜻蜓','燕子'], correct:1 },{ q:'爸爸教他要怎么做？', options:['顺着风跑','逆着风跑','站着不动','快速收线'], correct:1 }] },
        { id:'hrex_171', title:'在银行开户', titleEn:'Opening a Bank Account', hsk:3, passage:'我工作后需要开一个银行账户。带上身份证去银行。工作人员很热情。帮我填了表格，设置了密码。还推荐我开通了手机银行。以后转账查余额就方便多了。', questions:[{ q:'他去银行做什么？', options:['取钱','存钱','开账户','换钱'], correct:2 },{ q:'他带了什么？', options:['护照','身份证','驾照','学生证'], correct:1 },{ q:'工作人员还推荐了什么？', options:['信用卡','手机银行','理财','贷款'], correct:1 }] },
        { id:'hrex_172', title:'参加马拉松', titleEn:'Running a Marathon', hsk:3, passage:'今年我报名参加了半程马拉松。为了准备，我训练了三个月。每天早上跑五公里。比赛那天来了很多人。虽然跑到后面很累，但是我坚持跑完了。拿到奖牌的那一刻我很激动。', questions:[{ q:'他报名参加了什么？', options:['全程马拉松','半程马拉松','五公里跑','十公里跑'], correct:1 },{ q:'他准备了多久？', options:['一个月','两个月','三个月','半年'], correct:2 },{ q:'他每天早上跑多少？', options:['三公里','五公里','八公里','十公里'], correct:1 }] },
        { id:'hrex_173', title:'火车上遇到老乡', titleEn:'Meeting a Fellow Townsman', hsk:3, passage:'坐火车的时候，我对面坐了一个人。聊起来发现我们来自同一个城市。真是太巧了。他在外地工作，这次是回家过年。我们聊了一路。下车时还互相留了联系方式。', questions:[{ q:'他和对面的人发现了什么？', options:['同岁','来自同一个城市','同一个学校','同一个公司'], correct:1 },{ q:'那个人为什么坐火车？', options:['旅游','出差','回家过年','搬家'], correct:2 },{ q:'下车时他们做了什么？', options:['合影','留联系方式','一起吃饭','约好再见'], correct:1 }] },
        { id:'hrex_174', title:'去水上乐园', titleEn:'Going to a Water Park', hsk:3, passage:'夏天热得受不了。朋友约我去水上乐园玩。那里有各种滑梯和游泳池。最好玩的是大喇叭滑梯。冲下去的时候非常刺激。我玩了好几次。太阳很大，回家后发现皮肤都晒黑了。', questions:[{ q:'他们去了哪里？', options:['海边','水上乐园','游泳馆','河边'], correct:1 },{ q:'什么最好玩？', options:['游泳池','大喇叭滑梯','漂流','冲浪'], correct:1 },{ q:'回家后发现了什么？', options:['受伤了','晒黑了','感冒了','钱包丢了'], correct:1 }] },
        { id:'hrex_175', title:'申请大学', titleEn:'Applying for University', hsk:3, passage:'我今年高中毕业，正在申请大学。我想去北京上大学。北京有很多好大学。我选了三所学校。专业方面我选择了计算机。因为我对编程很感兴趣。希望能被录取。', questions:[{ q:'他想到哪个城市上大学？', options:['上海','北京','广州','深圳'], correct:1 },{ q:'他选了几所学校？', options:['两所','三所','四所','五所'], correct:1 },{ q:'他选择了什么专业？', options:['英语','计算机','经济','法律'], correct:1 }] },
        { id:'hrex_176', title:'第一次养猫', titleEn:'First Time Having a Cat', hsk:3, passage:'我领养了一只流浪猫。它很小，只有两个月大。全身是橘色的。刚来的时候很怕生。躲在沙发底下不出来。我给它准备了猫粮和水。慢慢的它开始信任我了。现在天天黏着我。', questions:[{ q:'他领养了什么？', options:['狗','流浪猫','兔子','仓鼠'], correct:1 },{ q:'猫刚来的时候怎么样？', options:['很活泼','很怕生','很凶','很胖'], correct:1 },{ q:'现在猫怎么样？', options:['还是怕人','天天黏着他','已经走了','不喜欢他'], correct:1 }] },
        { id:'hrex_177', title:'新年计划', titleEn:'New Year Resolution', hsk:3, passage:'新的一年开始了。我给自己定了几个目标。第一，每周运动三次。第二，每个月读一本书。第三，存钱去国外旅行。希望年底的时候这些目标都能实现。', questions:[{ q:'他定了几个目标？', options:['两个','三个','四个','五个'], correct:1 },{ q:'他每周要运动几次？', options:['一次','两次','三次','四次'], correct:2 },{ q:'他每个月要做什么？', options:['看电影','读一本书','写日记','存钱'], correct:1 }] },
        { id:'hrex_178', title:'在地铁站迷路', titleEn:'Lost in the Subway Station', hsk:3, passage:'第一次去上海的地铁站。站太大了。出口太多了。我分不清该走哪个口。幸好有工作人员。我问了他。他很耐心地告诉我怎么走。原来只要跟着指示牌走就可以了。', questions:[{ q:'他在哪里迷路了？', options:['火车站','地铁站','商场','机场'], correct:1 },{ q:'他问了谁？', options:['路人','工作人员','警察','保安'], correct:1 },{ q:'工作人员告诉他怎么做？', options:['看手机地图','跟着指示牌','打车','问别人'], correct:1 }] },
        { id:'hrex_179', title:'去露营', titleEn:'Going Camping', hsk:3, passage:'几个好朋友约好周末去露营。我们带了帐篷、睡袋和食物。到了山里，空气非常清新。晚上我们生火烤肉。然后躺在草地上看星星。虽然晚上很冷，但是很难忘。', questions:[{ q:'他们带了什么？', options:['帐篷睡袋食物','相机和电脑','书和游戏机','衣服和包'], correct:0 },{ q:'晚上他们做了什么？', options:['打牌','生火烤肉看星星','唱歌跳舞','钓鱼'], correct:1 },{ q:'晚上天气怎么样？', options:['很热','很冷','下雨了','刮风了'], correct:1 }] },
        { id:'hrex_180', title:'买二手书', titleEn:'Buying Secondhand Books', hsk:3, passage:'我在网上买了几本二手书。比新书便宜了一半。书虽然旧了一点，但是内容是一样的。而且前主人还在上面做了笔记。我觉得很有价值。以后可以考虑多买二手书。', questions:[{ q:'他买了什么？', options:['二手衣服','二手书','二手手机','二手家具'], correct:1 },{ q:'二手书比新书便宜多少？', options:['三分之一','一半','三分之二','四分之三'], correct:1 },{ q:'他觉得书上的笔记怎么样？', options:['很乱','很有价值','很无聊','看不懂'], correct:1 }] },
        { id:'hrex_181', title:'中国的快递服务', titleEn:'Chinas Express Delivery Service', hsk:4, passage:'中国的快递服务非常发达。在网上下单后，通常一到三天就能收到包裹。快递员会打电话通知你取件。有些快递甚至可以送到家门口。这种便利的物流系统让生活更加高效。不过随着快递数量的增加，包装垃圾也成了一个环境问题。', questions:[{ q:'中国的快递服务怎么样？', options:['一般','很发达','很慢','很贵'], correct:1 },{ q:'快递送到后会怎样？', options:['送到公司','打电话通知','发短信','放在门口'], correct:1 },{ q:'快递增加带来了什么问题？', options:['交通堵塞','包装垃圾','空气污染','噪音'], correct:1 },{ q:'通常几天能收到包裹？', options:['一天','一到三天','一周','十天'], correct:1 }] },
        { id:'hrex_182', title:'广场舞', titleEn:'Square Dancing', hsk:4, passage:'在中国很多城市的广场上，早晚都能看到跳广场舞的人群。大部分是中老年人。他们放着音乐，整齐地跳着舞。广场舞不仅锻炼了身体，还丰富了退休生活。不过有时候音乐声太大，影响了周围居民休息。因此也引起了一些争议。', questions:[{ q:'跳广场舞的主要是什么人？', options:['年轻人','中老年人','小孩','学生'], correct:1 },{ q:'跳广场舞有什么好处？', options:['赚钱','锻炼身体丰富生活','交朋友','减肥'], correct:1 },{ q:'广场舞引起了什么问题？', options:['交通问题','噪音问题','卫生问题','安全问题'], correct:1 },{ q:'什么时间段能看到跳广场舞？', options:['中午','早晚','深夜','只有周末'], correct:1 }] },
        { id:'hrex_183', title:'共享单车的发展', titleEn:'The Development of Bike-Sharing', hsk:4, passage:'共享单车在中国城市很普及。用手机扫码就可以骑走。解决了人们最后一公里的出行问题。价格也很便宜。但是随着共享单车数量的增加，也出现了乱停乱放的现象。有些城市开始限制投放数量。并且划定了专门的停车区域。', questions:[{ q:'共享单车解决了什么问题？', options:['长途出行','最后一公里','停车难','交通堵塞'], correct:1 },{ q:'共享单车出现了什么问题？', options:['价格太贵','乱停乱放','数量太少','质量不好'], correct:1 },{ q:'政府采取了什么措施？', options:['取消共享单车','限制投放划区域','提高价格','减少车辆'], correct:1 },{ q:'怎么使用共享单车？', options:['投币','办卡','扫码','买票'], correct:2 }] },
        { id:'hrex_184', title:'东北的冬天', titleEn:'Winter in Northeast China', hsk:4, passage:'中国东北的冬天非常寒冷，温度经常在零下二三十度。但是当地人早已习惯了。他们穿着厚厚的羽绒服，戴着帽子和手套。哈尔滨每年冬天都会举办冰雕节。用冰雕刻成各种建筑和动物。晚上配上彩灯，非常梦幻。吸引了大量游客。', questions:[{ q:'东北冬天温度怎么样？', options:['零度左右','零下二三十度','零下十度','零下四十度'], correct:1 },{ q:'当地人穿什么？', options:['薄外套','厚羽绒服','毛衣','皮衣'], correct:1 },{ q:'哈尔滨冬天举办什么节日？', options:['滑雪节','冰雕节','雪橇节','冬泳节'], correct:1 },{ q:'冰雕什么时候最好看？', options:['白天','早上','晚上配彩灯','中午'], correct:2 }] },
        { id:'hrex_185', title:'海外留学经历', titleEn:'Study Abroad Experience', hsk:4, passage:'去年我有机会去美国留学一年。刚去的时候语言不太通。上课只能听懂一半。后来我努力练习英语。多和本地学生交流。慢慢地进步了不少。留学不仅提高了我的语言能力，也让我了解了不同的文化。是一段非常宝贵的经历。', questions:[{ q:'他在美国留学了多久？', options:['半年','一年','两年','三年'], correct:1 },{ q:'刚去的时候他遇到了什么问题？', options:['住宿问题','语言问题','饮食问题','文化冲突'], correct:1 },{ q:'他通过什么方式提高英语？', options:['看书','看电视剧','多和本地学生交流','上补习班'], correct:2 },{ q:'留学给他带来了什么？', options:['更好的工作','提高了语言了解文化','赚了钱','移民了'], correct:1 }] },
        { id:'hrex_186', title:'中国的高铁网络', titleEn:'Chinas High-Speed Rail Network', hsk:4, passage:'中国的高铁网络是世界上最大的。总里程超过四万公里。高铁的速度很快，每小时能跑三百多公里。从北京到上海只需要四个多小时。高铁车厢干净舒适。还有免费的WiFi。越来越多的人选择坐高铁出行。', questions:[{ q:'中国高铁网络怎么样？', options:['世界第二','世界最大','一般','正在建设'], correct:1 },{ q:'高铁的速度是多少？', options:['两百多公里','三百多公里','四百多公里','五百多公里'], correct:1 },{ q:'从北京到上海坐高铁要多久？', options:['三个多小时','四个多小时','六个小时','八个小时'], correct:1 },{ q:'高铁上有什么服务？', options:['免费餐饮','免费WiFi','按摩座椅','电影'], correct:1 }] },
        { id:'hrex_187', title:'空气污染问题', titleEn:'Air Pollution Problem', hsk:4, passage:'随着工业的发展，空气污染成为了一个严重的问题。雾霾天气经常出现。人们出门不得不戴口罩。政府采取了很多措施来改善空气质量。比如限制汽车数量、关闭污染严重的工厂、推广新能源汽车等。经过几年的努力，空气质量已经有了明显的改善。', questions:[{ q:'空气污染的原因是什么？', options:['人口太多','工业发展','汽车太多','建筑工地'], correct:1 },{ q:'雾霾天气人们要做什么？', options:['不出门','戴口罩','开窗通风','去公园'], correct:1 },{ q:'政府采取了什么措施？', options:['限制汽车关闭工厂','搬迁城市','提高油价','种树'], correct:0 },{ q:'空气质量怎么样了？', options:['越来越差','没有变化','已经改善','还不知道'], correct:2 }] },
        { id:'hrex_188', title:'中国的教育制度', titleEn:'Chinese Education System', hsk:4, passage:'中国的教育制度和其他国家有所不同。小学六年，初中三年，高中三年。大学一般是四年。高考是非常重要的考试。决定了学生能上哪所大学。近年来教育部门在推行减负政策。希望减轻学生的课业负担。', questions:[{ q:'中国小学几年？', options:['五年','六年','七年','八年'], correct:1 },{ q:'什么考试非常重要？', options:['中考','高考','考研','期末考'], correct:1 },{ q:'近年来推行了什么政策？', options:['增负','减负','取消考试','延长学制'], correct:1 },{ q:'大学一般是几年？', options:['三年','四年','五年','六年'], correct:1 }] },
        { id:'hrex_189', title:'中国菜系介绍', titleEn:'Introduction to Chinese Cuisines', hsk:4, passage:'中国菜种类很多。主要有八大菜系。其中川菜以辣闻名。粤菜讲究原汁原味。鲁菜咸鲜。苏菜精致。每个菜系都有自己独特的风味。不同地方的人口味也不同。比如四川人爱吃辣，广东人喜欢清淡。这种饮食文化的多样性非常吸引人。', questions:[{ q:'中国主要有几个菜系？', options:['六个','七个','八个','九个'], correct:2 },{ q:'川菜以什么闻名？', options:['甜','酸','辣','咸'], correct:2 },{ q:'粤菜讲究什么？', options:['辣','原汁原味','咸鲜','精致'], correct:1 },{ q:'四川人喜欢什么口味？', options:['清淡','辣','甜','酸'], correct:1 }] },
        { id:'hrex_190', title:'网络购物节', titleEn:'Online Shopping Festival', hsk:4, passage:'中国有两大网络购物节。一个是双十一，另一个是六一八。双十一是十一月十一日。这一天电商平台会推出大量折扣。去年双十一的总交易额超过了五千亿元。很多人提前把想要的东西加入购物车。到了零点疯狂下单。快递公司也会增加人手来应对巨大的包裹量。', questions:[{ q:'中国有哪两个大购物节？', options:['双十一和双十二','双十一和六一八','元旦和春节','圣诞和新年'], correct:1 },{ q:'双十一是几月几号？', options:['十月十一日','十一月十一日','十二月十一日','十一月一日'], correct:1 },{ q:'去年双十一交易额多少？', options:['超过千亿','超过五千亿','超过万亿','超过百亿'], correct:1 },{ q:'人们提前做什么？', options:['取钱','加入购物车','请假','订机票'], correct:1 }] },
        { id:'hrex_191', title:'中国的人口问题', titleEn:'Chinas Population Issue', hsk:4, passage:'中国是世界上人口最多的国家。有超过十四亿人。但是近年来出生率一直在下降。老龄化问题越来越严重。政府已经放开了二胎和三胎政策。鼓励年轻人生育。但是很多人因为经济压力不愿意生。人口结构的变化会给社会带来很多挑战。', questions:[{ q:'中国人口超过多少？', options:['十三亿','十四亿','十五亿','十六亿'], correct:1 },{ q:'出生率在怎样变化？', options:['上升','下降','不变','波动'], correct:1 },{ q:'政府鼓励生育的政策是什么？', options:['放开二胎三胎','给奖金','延长假期','免费教育'], correct:0 },{ q:'为什么很多人不愿意生？', options:['没时间','不喜欢孩子','经济压力','住房太小'], correct:2 }] },
        { id:'hrex_192', title:'海南旅游攻略', titleEn:'Hainan Travel Guide', hsk:4, passage:'海南是中国最南端的省份。气候温暖，四季如春。三亚是著名的旅游城市。有美丽的海滩和清澈的海水。游客可以潜水、游泳和晒太阳。海鲜也非常新鲜便宜。不过旺季的时候酒店价格会翻倍。最好提前预订。', questions:[{ q:'海南的气候怎么样？', options:['四季分明','四季如春','冬天很冷','夏天很凉快'], correct:1 },{ q:'三亚以什么著名？', options:['历史文化','海滩海水','购物','美食'], correct:1 },{ q:'游客在海南可以做什么活动？', options:['滑雪','爬山','潜水游泳','滑冰'], correct:2 },{ q:'旺季去海南要注意什么？', options:['带厚衣服','提前订酒店','换外币','打疫苗'], correct:1 }] },
        { id:'hrex_193', title:'新能源汽车', titleEn:'New Energy Vehicles', hsk:4, passage:'新能源汽车在中国越来越受欢迎。电动汽车不需要汽油，用电就可以跑。充电比加油便宜。而且对环境更友好。很多城市对新能源汽车有优惠政策。比如免费停车、不限号等。但是充电桩还不够普及。跑长途的时候充电不太方便。', questions:[{ q:'新能源汽车用什么作为能源？', options:['汽油','柴油','电','天然气'], correct:2 },{ q:'新能源车有什么优势？', options:['速度快','更安全','便宜又环保','空间大'], correct:2 },{ q:'城市对新能源车有什么优惠？', options:['免费停车不限号','免购置税','优先通行','免费上牌'], correct:0 },{ q:'新能源车有什么问题？', options:['速度太慢','充电桩不够普及','容易坏','不安全'], correct:1 }] },
        { id:'hrex_194', title:'中国功夫电影', titleEn:'Chinese Kung Fu Movies', hsk:4, passage:'中国功夫电影在世界范围内都有影响力。李小龙把中国功夫推向了世界。后来成龙、李连杰等演员继续发扬光大。功夫电影不仅展示精彩的打斗场面，还传递着侠义精神。近年来功夫电影的种类更多了。结合了电脑特技，视觉效果更加震撼。', questions:[{ q:'谁最先把中国功夫推向世界？', options:['成龙','李小龙','李连杰','甄子丹'], correct:1 },{ q:'功夫电影传递什么精神？', options:['和平','侠义精神','爱国','团结'], correct:1 },{ q:'近年来功夫电影有什么变化？', options:['越来越少了','结合电脑特技','回归传统','没有变化'], correct:1 },{ q:'功夫电影除了展示打斗还有什么？', options:['爱情故事','搞笑情节','侠义精神','历史故事'], correct:2 }] },
        { id:'hrex_195', title:'独生子女政策', titleEn:'One-Child Policy', hsk:4, passage:'中国曾经实行过独生子女政策。那时候一对夫妻只能生一个孩子。这个政策控制了人口增长速度。但也带来了一些问题。比如很多家庭只有一个孩子。孩子没有兄弟姐妹。成长过程中比较孤独。现在政策已经调整了。鼓励年轻人生育两个孩子或者三个孩子。', questions:[{ q:'独生子女政策要求生几个？', options:['一个','两个','三个','随便'], correct:0 },{ q:'这个政策起到了什么作用？', options:['增加人口','控制人口增长','减少人口','提高人口质量'], correct:1 },{ q:'这个政策带来的问题是什么？', options:['孩子太宠','孩子孤独没有兄弟姐妹','人口太多','老龄化'], correct:1 },{ q:'现在政策鼓励生几个？', options:['一个','两个或三个','四个','不限'], correct:1 }] },
        { id:'hrex_196', title:'中国书法艺术', titleEn:'Chinese Calligraphy Art', hsk:4, passage:'中国书法是一种独特的艺术形式。用毛笔在宣纸上写字。书法有五种主要字体：篆书、隶书、楷书、行书和草书。练习书法需要耐心和专注。很多老年人退休后开始学书法。可以修身养性。书法作品也经常作为装饰品挂在客厅或书房里。', questions:[{ q:'书法用什么工具？', options:['钢笔和纸','毛笔和宣纸','铅笔和本子','马克笔'], correct:1 },{ q:'书法有几种主要字体？', options:['三种','四种','五种','六种'], correct:2 },{ q:'练习书法需要什么？', options:['很大力气','耐心和专注','很快的速度','很多钱'], correct:1 },{ q:'书法作品常挂在哪里？', options:['卧室','厨房','客厅或书房','阳台'], correct:2 }] },
        { id:'hrex_197', title:'移动支付的安全', titleEn:'Mobile Payment Security', hsk:4, passage:'移动支付虽然方便，但也存在安全隐患。有些人会收到诈骗短信。点击链接后钱就被转走了。所以使用移动支付时要注意保护个人信息。不要连接公共WiFi进行支付。定期修改密码。开启双重验证。如果发现异常交易，要立即联系银行。', questions:[{ q:'移动支付有什么风险？', options:['手机没电','诈骗短信','网络不好','支付失败'], correct:1 },{ q:'使用移动支付要注意什么？', options:['多下载软件','保护个人信息','少用手机','不用密码'], correct:1 },{ q:'不要连接什么进行支付？', options:['家庭WiFi','公共WiFi','公司网络','手机热点'], correct:1 },{ q:'发现异常交易怎么做？', options:['等等看','联系银行','报警','自己解决'], correct:1 }] },
        { id:'hrex_198', title:'中国名胜古迹', titleEn:'Chinas Famous Historical Sites', hsk:4, passage:'中国有很多著名的名胜古迹。长城是世界上最长的城墙。故宫是明清两代的皇宫。兵马俑是秦始皇的陪葬品。西湖因美丽的湖光山色而闻名。每年这些景点都会吸引大量国内外游客。为了保护这些文化遗产，游客需要遵守规定。不能乱涂乱画。', questions:[{ q:'文中提到了几个名胜古迹？', options:['三个','四个','五个','六个'], correct:1 },{ q:'长城是什么？', options:['最长的城墙','最大的宫殿','最大的陵墓','最高的塔'], correct:0 },{ q:'兵马俑是谁的陪葬品？', options:['汉武帝','秦始皇','唐太宗','康熙'], correct:1 },{ q:'游客需要遵守什么？', options:['买门票','不能乱涂乱画','拍照','排队'], correct:1 }] },
        { id:'hrex_199', title:'减肥的经历', titleEn:'Weight Loss Experience', hsk:4, passage:'去年我体重超标了。医生建议我减肥。于是我制定了一个计划。每天控制饮食。少吃碳水化合物。多吃蛋白质和蔬菜。同时每周运动四次。坚持了半年后。我成功减掉了十五公斤。腰围也小了。整个人感觉轻松多了。但是减肥需要长期坚持。否则很容易反弹。', questions:[{ q:'医生建议他做什么？', options:['多休息','减肥','吃药','住院'], correct:1 },{ q:'他每天怎么控制饮食？', options:['不吃东西','少吃碳水化合物多吃蛋白质','只吃水果','只喝水'], correct:1 },{ q:'他每周运动几次？', options:['两次','三次','四次','五次'], correct:2 },{ q:'他减掉了多少公斤？', options:['十公斤','十五公斤','二十公斤','二十五公斤'], correct:1 }] },
        { id:'hrex_200', title:'中国戏曲', titleEn:'Chinese Opera', hsk:4, passage:'中国戏曲是一种综合性的舞台艺术。京剧是最有代表性的剧种。被称为国粹。演员通过唱、念、做、打来表演故事。脸谱的颜色代表不同的性格。红色代表忠诚，白色代表奸诈。除了京剧，还有越剧、黄梅戏、川剧等地方剧种。每一种都有自己的特色。', questions:[{ q:'京剧被称为什么？', options:['国剧','国粹','国宝','经典'], correct:1 },{ q:'演员通过什么来表演？', options:['唱念做打','说学逗唱','吹拉弹唱','跳唱演'], correct:0 },{ q:'红色脸谱代表什么？', options:['奸诈','忠诚','勇敢','智慧'], correct:1 },{ q:'除了京剧文中还提到了什么剧种？', options:['越剧黄梅戏川剧','话剧','歌剧','舞剧'], correct:0 }] },
        { id:'hrex_201', title:'独居生活', titleEn:'Living Alone', hsk:4, passage:'越来越多的年轻人选择独居。独居可以自由安排时间。想做什么就做什么。但是独居也有不好的地方。有时候会感到孤独。特别是生病的时候没有人照顾。而且一个人住的开销也比较大。房租和生活费都要自己承担。', questions:[{ q:'独居有什么好处？', options:['省钱','自由安排时间','有人做饭','热闹'], correct:1 },{ q:'独居的坏处是什么？', options:['没人洗碗','感到孤独','没人打扫','不会做饭'], correct:1 },{ q:'独居的开销怎么样？', options:['比较小','比较大','和合租一样','不用花钱'], correct:1 },{ q:'什么情况下独居特别不好？', options:['过节的时候','生病的时候','周末','下雨天'], correct:1 }] },
        { id:'hrex_202', title:'中国传统婚礼', titleEn:'Traditional Chinese Wedding', hsk:4, passage:'中国传统婚礼有很多习俗。以前新娘要穿红色的嫁衣。坐花轿去新郎家。现在大多数新人选择西式婚礼。穿白色婚纱。但是有些传统仍然保留着。比如拜天地、敬茶和发红包。红色仍然是中国婚礼的主要颜色。因为它代表喜庆和吉祥。', questions:[{ q:'以前新娘穿什么颜色的衣服？', options:['白色','红色','粉色','金色'], correct:1 },{ q:'现在大多数新人选择什么婚礼？', options:['中式婚礼','西式婚礼','户外婚礼','旅行结婚'], correct:1 },{ q:'哪些传统仍然保留？', options:['坐花轿','拜天地敬茶','穿古装','骑大马'], correct:1 },{ q:'红色代表什么？', options:['纯洁','喜庆吉祥','高贵','浪漫'], correct:1 }] },
        { id:'hrex_203', title:'网络直播', titleEn:'Live Streaming', hsk:4, passage:'网络直播在中国非常流行。很多人通过直播展示才艺、卖东西或者聊天。主播可以通过观众的礼物赚钱。有些主播年收入很高。但是直播行业也存在问题。有些内容低俗。未成年人沉迷直播打赏的新闻也经常出现。相关部门正在加强监管。', questions:[{ q:'主播通过什么赚钱？', options:['广告费','观众的礼物','平台工资','卖课'], correct:1 },{ q:'直播行业存在什么问题？', options:['网络卡顿','内容低俗','人数太少','手机没电'], correct:1 },{ q:'谁容易出现沉迷打赏问题？', options:['老年人','中年人','未成年人','外国人'], correct:2 },{ q:'相关部门在做什么？', options:['关闭直播','加强监管','提高税收','增加流量'], correct:1 }] },
        { id:'hrex_204', title:'中医疗法', titleEn:'Chinese Medicine Therapy', hsk:4, passage:'中医是中国传统的医疗方法。它和西医不同。中医讲究调理身体的平衡。常用的疗法有针灸、拔罐和中药。针灸是用细针刺激身体的穴位。拔罐是在皮肤上放置罐子形成负压。很多人认为中医对慢性病的治疗效果很好。现在中医在全世界也越来越受欢迎。', questions:[{ q:'中医讲究什么？', options:['吃药','调理平衡','手术','检查'], correct:1 },{ q:'文中提到了几种中医疗法？', options:['两种','三种','四种','五种'], correct:1 },{ q:'针灸用什么工具？', options:['小刀','细针','罐子','艾草'], correct:1 },{ q:'中医对什么病效果比较好？', options:['急性病','慢性病','传染病','遗传病'], correct:1 }] },
        { id:'hrex_205', title:'春运现象', titleEn:'Spring Festival Travel Rush', hsk:4, passage:'春运是中国每年春节前后的人口大迁移。成千上万的人从城市回到家乡过年。火车站和机场人山人海。火车票非常难买。很多人提前一个月就抢票了。虽然旅途辛苦，但是回家的心情是迫切的。近年来高铁的发展缓解了春运的压力。提供了更多的座位。', questions:[{ q:'春运是什么时候？', options:['国庆前后','春节前后','五一前后','暑假'], correct:1 },{ q:'春运时火车票怎么样？', options:['很好买','很难买','很贵','不需要票'], correct:1 },{ q:'什么缓解了春运的压力？', options:['飞机','高铁','自驾','大巴'], correct:1 },{ q:'人们回家的心情怎么样？', options:['无所谓','很迫切','害怕','不想回家'], correct:1 }] },
        { id:'hrex_206', title:'人工智能的应用', titleEn:'Applications of AI', hsk:4, passage:'人工智能正在改变我们的生活。智能手机的语音助手可以回答我们的问题。导航软件可以规划最佳路线。短视频平台会根据你的喜好推荐内容。在医疗领域，人工智能可以帮助医生诊断疾病。在制造业，机器人可以代替人类做重复性的工作。未来人工智能会在更多领域发挥作用。', questions:[{ q:'语音助手能做什么？', options:['打电话','回答问题','发短信','玩游戏'], correct:1 },{ q:'导航软件能做什么？', options:['听音乐','规划最佳路线','看电影','订酒店'], correct:1 },{ q:'在医疗领域AI能做什么？', options:['做手术','帮助诊断','开药方','护理病人'], correct:1 },{ q:'在制造业机器人能做什么？', options:['做管理','代替人类做重复工作','做设计','做销售'], correct:1 }] },
        { id:'hrex_207', title:'睡眠质量', titleEn:'Sleep Quality', hsk:4, passage:'睡眠对健康非常重要。成年人每天需要七到八个小时的睡眠。但是现在很多人睡眠不足。熬夜已经成为一种普遍现象。长期睡眠不好会导致记忆力下降、免疫力降低。还可能引起肥胖和心血管疾病。为了改善睡眠，睡前尽量不要玩手机。保持规律的作息时间。', questions:[{ q:'成年人每天需要睡多久？', options:['五六小时','七八小时','八九小时','十小时'], correct:1 },{ q:'长期睡眠不好会怎样？', options:['更健康','记忆力下降免疫力降低','变胖','更有精神'], correct:1 },{ q:'为了改善睡眠应该怎么做？', options:['多喝茶','睡前不玩手机','多做运动','吃安眠药'], correct:1 },{ q:'文中没有提到睡眠不好会导致什么？', options:['记忆力下降','免疫力降低','癌症','肥胖'], correct:2 }] },
        { id:'hrex_208', title:'中国年轻人买房', titleEn:'Young People Buying Homes', hsk:4, passage:'在中国买房是很多年轻人的目标。但是房价很高。尤其是在北京、上海这样的大城市。一套房子的价格可能要几百万元。很多年轻人需要父母帮忙付首付。然后自己每个月还房贷。为了买房子，很多年轻人不得不节省开支。也有人选择租房。认为租房更灵活自由。', questions:[{ q:'在大城市买房要多少钱？', options:['几十万','几百万元','几千万','上亿'], correct:1 },{ q:'很多年轻人怎么付首付？', options:['自己存钱','父母帮忙','贷款','借钱'], correct:1 },{ q:'买房后年轻人要做什么？', options:['每个月还房贷','装修','买家具','出租'], correct:0 },{ q:'有些人选择租房的原因是什么？', options:['更便宜','更灵活自由','更舒服','更方便'], correct:1 }] },
        { id:'hrex_209', title:'舌尖上的中国', titleEn:'A Bite of China', hsk:4, passage:'舌尖上的中国是一部很受欢迎的美食纪录片。介绍了中国各地的美食。从北方的面食到南方的米饭。从四川的火锅到广东的早茶。每一集都让人流口水。这部纪录片不仅展示了美食。还讲述了食物背后的文化和故事。很多人看了以后决定去当地品尝美食。', questions:[{ q:'舌尖上的中国是什么类型的节目？', options:['电视剧','美食纪录片','综艺节目','新闻节目'], correct:1 },{ q:'纪录片从北方到南方介绍了什么变化？', options:['从面食到米饭','从辣到甜','从冷到热','从咸到淡'], correct:0 },{ q:'纪录片除了展示美食还讲述什么？', options:['名人故事','食物背后的文化和故事','天气预报','历史事件'], correct:1 },{ q:'很多人看了以后决定做什么？', options:['学做饭','去当地品尝美食','开餐厅','写美食书'], correct:1 }] },
        { id:'hrex_210', title:'电子书和纸质书', titleEn:'E-books vs Paper Books', hsk:4, passage:'现在越来越多的人用手机或平板看书。电子书方便携带。一个设备可以存上千本书。而且随时可以购买下载。但是有些人仍然喜欢纸质书。纸质书有真实的触感。翻页的声音让人安心。而且看纸质书不伤眼睛。两种方式各有优点。选择哪种主要看个人习惯。', questions:[{ q:'电子书有什么优点？', options:['便宜','方便携带容量大','好看','不伤眼'], correct:1 },{ q:'纸质书有什么优点？', options:['方便携带','有触感不伤眼','便宜','环保'], correct:1 },{ q:'一个设备可以存多少本书？', options:['几百本','上千本','上万本','不限量'], correct:1 },{ q:'选择看书方式取决于什么？', options:['价格','个人习惯','流行趋势','推荐'], correct:1 }] },
        { id:'hrex_211', title:'中国的沙漠治理', titleEn:'Desert Control in China', hsk:4, passage:'中国有大量的沙漠地区。其中最大的沙漠是塔克拉玛干沙漠。过去沙漠面积不断扩大。沙尘暴影响了人们的生活。为了治理沙漠，中国实施了很多项目。最著名的是三北防护林工程。大量种树防止沙漠扩张。经过几十年的努力。沙漠面积开始减少。生态环境得到了改善。', questions:[{ q:'中国最大的沙漠是什么？', options:['戈壁沙漠','塔克拉玛干','腾格里','毛乌素'], correct:1 },{ q:'沙尘暴影响了什么？', options:['交通','人们的生活','经济','旅游'], correct:1 },{ q:'著名的治沙工程是什么？', options:['三峡工程','三北防护林','南水北调','西气东输'], correct:1 },{ q:'经过努力后生态环境怎么样？', options:['恶化了','没有变化','得到了改善','不知道'], correct:2 }] },
        { id:'hrex_212', title:'宠物经济', titleEn:'Pet Economy', hsk:4, passage:'现在养宠物的人越来越多。宠物经济也迅速发展。宠物食品、宠物医疗、宠物美容等产业都在增长。很多人把宠物当作家人。愿意为宠物花钱。一只宠物狗一个月的花费可能上千元。包括狗粮、零食、玩具和看病。但是养宠物也需要责任感。不能一时冲动就养。', questions:[{ q:'宠物经济包括哪些产业？', options:['宠物食品医疗美容','宠物服装','宠物酒店','宠物保险'], correct:0 },{ q:'很多人把宠物当做什么？', options:['工具','家人','玩具','装饰'], correct:1 },{ q:'一只宠物狗一个月花费可能多少？', options:['几百元','上千元','上万元','几百块'], correct:1 },{ q:'养宠物需要什么？', options:['钱','责任感','大房子','时间'], correct:1 }] },
        { id:'hrex_213', title:'中国高铁出海', titleEn:'Chinas High-Speed Rail Going Global', hsk:4, passage:'中国的高铁技术已经出口到很多国家。印尼的雅万高铁就是中国建设的。全长一百四十多公里。中国高铁技术先进、成本合理、建设速度快。在国际市场上很有竞争力。中国还在帮助其他国家建设铁路。这种合作促进了共同发展。也增进了国家之间的友谊。', questions:[{ q:'印尼的雅万高铁是谁建设的？', options:['日本','德国','中国','法国'], correct:2 },{ q:'雅万高铁全长多少？', options:['一百多公里','一百四十多公里','两百公里','三百公里'], correct:1 },{ q:'中国高铁有什么优势？', options:['最便宜','技术先进成本合理速度快','最安全','最豪华'], correct:1 },{ q:'高铁出海带来了什么？', options:['竞争和冲突','促进发展和友谊','文化入侵','环境破坏'], correct:1 }] },
        { id:'hrex_214', title:'中国传统服饰', titleEn:'Traditional Chinese Clothing', hsk:4, passage:'汉服是中国传统服饰。近年来在年轻人中又重新流行起来。很多人穿着汉服去公园拍照或者参加传统节日活动。汉服的款式很多。不同朝代有不同的风格。唐朝的汉服比较开放华丽。宋朝的比较简约。除了汉服，旗袍也很有中国特色。展现了女性的优雅。', questions:[{ q:'近年来什么在年轻人中流行？', options:['西装','汉服','和服','韩服'], correct:1 },{ q:'唐朝的汉服风格怎么样？', options:['简约','开放华丽','保守','朴素'], correct:1 },{ q:'宋朝的汉服怎么样？', options:['华丽','简约','开放','复杂'], correct:1 },{ q:'旗袍展现了什么？', options:['女性的优雅','男性的帅气','孩子的可爱','老人的稳重'], correct:0 }] },
        { id:'hrex_215', title:'短视频的利弊', titleEn:'Pros and Cons of Short Videos', hsk:4, passage:'短视频平台在中国非常流行。很多人每天花几个小时刷短视频。短视频的内容很丰富。有搞笑的、有知识科普的、有美食制作的。但是刷短视频容易上瘾。不知不觉几个小时就过去了。影响了学习和工作效率。而且内容质量也参差不齐。有些虚假信息会误导观众。', questions:[{ q:'短视频的内容包括什么？', options:['只有搞笑','搞笑科普美食等','只有知识','只有美食'], correct:1 },{ q:'刷短视频有什么负面影响？', options:['伤眼睛','容易上瘾影响效率','浪费钱','没营养'], correct:1 },{ q:'内容质量方面有什么问题？', options:['都很好','参差不齐有虚假信息','都很差','太复杂'], correct:1 },{ q:'文中没有提到短视频的什么内容？', options:['搞笑','知识科普','新闻','美食制作'], correct:2 }] },
        { id:'hrex_216', title:'中国的节日食品', titleEn:'Chinese Festival Foods', hsk:4, passage:'中国的每个传统节日都有对应的食品。春节吃饺子。饺子像元宝，象征财富。元宵节吃汤圆。汤圆圆圆的，象征团圆。端午节吃粽子。中秋节吃月饼。这些食品不仅好吃。还有美好的寓意。现在超市里一年四季都能买到这些食品。但是节日当天吃更有意义。', questions:[{ q:'春节吃什么？', options:['汤圆','饺子','粽子','月饼'], correct:1 },{ q:'饺子象征什么？', options:['团圆','财富','长寿','幸福'], correct:1 },{ q:'汤圆象征什么？', options:['财富','团圆','好运','甜蜜'], correct:1 },{ q:'什么时候吃这些食品更有意义？', options:['饿了就吃','节日当天吃','早上吃','和朋友一起吃'], correct:1 }] },
        { id:'hrex_217', title:'中国互联网发展', titleEn:'Chinas Internet Development', hsk:4, passage:'中国的互联网发展非常迅速。网民数量已经超过十亿。移动支付、网购、外卖等服务非常普及。几乎每个人都离不开手机。互联网改变了人们的生活方式。以前出门要带钱包。现在一个手机就够了。但是互联网也带来了隐私泄露的问题。个人信息保护变得越来越重要。', questions:[{ q:'中国网民数量超过多少？', options:['五亿','八亿','十亿','十五亿'], correct:2 },{ q:'互联网改变了什么？', options:['交通方式','生活方式','饮食习惯','穿着风格'], correct:1 },{ q:'以前出门要带什么？', options:['手机','钱包','钥匙','身份证'], correct:1 },{ q:'互联网带来了什么问题？', options:['网络慢','隐私泄露','手机贵','费电'], correct:1 }] },
        { id:'hrex_218', title:'学汉语的外国人', titleEn:'Foreigners Learning Chinese', hsk:4, passage:'现在越来越多的外国人开始学习汉语。汉语已经成为热门语言。很多国家的中小学都开设了中文课。外国人学汉语最大的难点是声调和汉字。同音字很多。容易混淆。但是汉语的语法相对简单。没有时态变化。很多外国人因为对中国文化感兴趣而学汉语。也有人因为工作需要。', questions:[{ q:'汉语在哪方面比较难？', options:['语法','声调和汉字','词汇','发音'], correct:1 },{ q:'汉语语法有什么特点？', options:['很复杂','没有时态变化','有很多动词变化','很难学'], correct:1 },{ q:'外国人为什么学汉语？', options:['因为考试','因为对中国文化感兴趣或工作','因为容易','因为流行'], correct:1 },{ q:'文中没有提到什么？', options:['中小学开中文课','声调难','同音字多','汉字笔顺'], correct:3 }] },
        { id:'hrex_219', title:'中国熊猫保护', titleEn:'Panda Conservation in China', hsk:4, passage:'大熊猫是中国的国宝。也是濒危动物。主要生活在四川、陕西和甘肃的山区。它们以竹子为主要食物。一只成年熊猫每天要吃几十公斤竹子。中国建立了多个熊猫保护区。人工繁殖技术也越来越成熟。经过努力，大熊猫的数量在增加。已经从濒危降级为易危了。', questions:[{ q:'大熊猫主要生活在哪些省份？', options:['四川陕西甘肃','云南贵州四川','湖南湖北广东','青海甘肃西藏'], correct:0 },{ q:'熊猫的主要食物是什么？', options:['肉','竹子','水果','蔬菜'], correct:1 },{ q:'熊猫的保护等级从濒危降为什么？', options:['无危','易危','近危','安全'], correct:1 },{ q:'一只成年熊猫每天吃多少竹子？', options:['几公斤','几十公斤','上百公斤','几百公斤'], correct:1 }] },
        { id:'hrex_220', title:'中国人的储蓄习惯', titleEn:'Chinese Saving Habits', hsk:4, passage:'中国人有储蓄的传统。很多人会把收入的百分之二十到三十存起来。为了应对紧急情况或者为将来做打算。结婚、买房、子女教育都需要大量资金。中国的储蓄率在世界上是比较高的。但是现在年轻人的消费观念改变了。很多人更愿意花钱享受生活。储蓄率在下降。', questions:[{ q:'中国人会把多少收入存起来？', options:['百分之十到二十','百分之二十到三十','百分之三十到四十','百分之四十到五十'], correct:1 },{ q:'储蓄是为了什么？', options:['应对紧急和为将来打算','旅行','买东西','投资'], correct:0 },{ q:'现在年轻人的消费观念怎么了？', options:['更爱存钱','更愿花钱享受','和以前一样','不知道'], correct:1 },{ q:'中国的储蓄率在世界上怎么样？', options:['较低','较高','平均','最低'], correct:1 }] },
        { id:'hrex_221', title:'城市交通拥堵', titleEn:'Urban Traffic Congestion', hsk:4, passage:'中国大城市的交通拥堵问题越来越严重。上下班高峰期堵车是家常便饭。很多人每天花在路上的时间超过两个小时。为了缓解交通压力，很多城市采取了限行措施。比如根据车牌尾号限制上路。同时也在大力发展公共交通。地铁线路不断增加。共享单车也起到了辅助作用。', questions:[{ q:'很多人每天花在路上的时间是多少？', options:['一小时','超过两小时','半小时','三小时'], correct:1 },{ q:'城市采取了什么限行措施？', options:['单双号限行','根据车牌尾号','限速','收费'], correct:1 },{ q:'城市在大力发展什么？', options:['高速公路','公共交通','私家车','出租车'], correct:1 },{ q:'共享单车起了什么作用？', options:['主要作用','辅助作用','没有作用','负面作用'], correct:1 }] },
        { id:'hrex_222', title:'中国茶道精神', titleEn:'Chinese Tea Ceremony Spirit', hsk:4, passage:'中国茶道讲究和、敬、清、寂四个字。和是指和谐。喝茶让人心情平和。敬是指尊敬。给客人倒茶是表示尊重。清是指清洁。茶具要干净。寂是指安静。喝茶时保持安静能更好地品味茶香。茶道不仅是一种饮茶方式。更是一种生活态度。在忙碌的生活中喝茶可以让人放松下来。', questions:[{ q:'茶道的第一个字是什么？', options:['和','敬','清','寂'], correct:0 },{ q:'敬代表什么意思？', options:['和谐','尊敬','清洁','安静'], correct:1 },{ q:'茶道是什么？', options:['一种饮料','一种生活态度','一种宗教','一种运动'], correct:1 },{ q:'喝茶有什么作用？', options:['提神','让人放松','减肥','治病'], correct:1 }] },
        { id:'hrex_223', title:'双职工家庭', titleEn:'Dual-Income Families', hsk:4, passage:'现在很多家庭夫妻双方都工作。称为双职工家庭。双职工家庭收入比较高。但是也有挑战。家务活谁来干是个问题。很多家庭会请钟点工帮忙打扫。有孩子的家庭还要考虑谁接送孩子。有些老人会帮忙带孙子。工作家庭两不误需要很好的时间管理能力。', questions:[{ q:'双职工家庭指什么？', options:['一个人工作','夫妻双方都工作','两个人都不工作','一个人打两份工'], correct:1 },{ q:'双职工家庭的挑战是什么？', options:['收入低','家务和照顾孩子','没朋友','没时间吃饭'], correct:1 },{ q:'很多家庭怎么解决家务问题？', options:['不打扫','请钟点工','等周末做','让一个人辞职'], correct:1 },{ q:'谁经常帮忙带孩子？', options:['邻居','保姆','老人','幼儿园'], correct:2 }] },
        { id:'hrex_224', title:'中国民间艺术', titleEn:'Chinese Folk Art', hsk:4, passage:'中国有很多民间艺术形式。剪纸是用剪刀在纸上剪出各种图案。窗花就是剪纸的一种。过年时家家户户贴窗花。泥人是捏出来的小人物。色彩鲜艳。糖画是用糖浆画出的图案。可以吃也可以看。这些民间艺术正在慢慢消失。因为年轻人不太愿意学习这些传统手艺。', questions:[{ q:'文中提到了几种民间艺术？', options:['两种','三种','四种','五种'], correct:1 },{ q:'窗花属于什么？', options:['泥人','糖画','剪纸','刺绣'], correct:2 },{ q:'糖画用什么做？', options:['糖浆','面粉','泥巴','纸'], correct:0 },{ q:'民间艺术正在怎么样？', options:['蓬勃发展','慢慢消失','走向世界','越来越受欢迎'], correct:1 }] },
        { id:'hrex_225', title:'中国孩子的课外班', titleEn:'Chinese Childrens Extracurricular Classes', hsk:4, passage:'中国很多孩子放学后还要上各种课外班。最常见的辅导班是英语、数学和钢琴。有些孩子周末比上学还忙。家长希望孩子多学一些技能。以后有更好的发展。但是孩子压力很大。没有时间玩。教育部门一直在提倡减负。但是家长的焦虑心态很难改变。', questions:[{ q:'最常见的课外班是什么？', options:['英语数学钢琴','画画跳舞','游泳武术','围棋象棋'], correct:0 },{ q:'有些孩子周末怎么样？', options:['比上学还忙','在家休息','出去旅游','看电视'], correct:0 },{ q:'家长为什么让孩子上辅导班？', options:['希望孩子有更好发展','别人都上','老师要求的','孩子喜欢'], correct:0 },{ q:'教育部门提倡什么？', options:['多上课','减负','增加考试','取消课外班'], correct:1 }] },
        { id:'hrex_226', title:'高考的压力', titleEn:'College Entrance Exam Pressure', hsk:4, passage:'高考是中国学生最重要的考试。每年有上千万学生参加。高考成绩直接决定了能上哪所大学。所以学生和家长都非常重视。高三这一年学生每天学习十几个小时。有些学生甚至出现焦虑和失眠的症状。高考虽然重要，但也不是人生的全部。现在越来越多的学生选择出国留学或者上职业学校。', questions:[{ q:'每年有多少学生参加高考？', options:['几百万','上千万','上亿','几十万'], correct:1 },{ q:'高三学生每天学习多久？', options:['八小时','十小时多','十几小时','六小时'], correct:2 },{ q:'高考压力导致了什么问题？', options:['肥胖','焦虑和失眠','近视','没有朋友'], correct:1 },{ q:'除了高考还有什么选择？', options:['出国留学或上职业学校','不上学','直接工作','创业'], correct:0 }] },
        { id:'hrex_227', title:'中国养老问题', titleEn:'Chinas Elderly Care Issue', hsk:4, passage:'中国正在快速进入老龄化社会。六十岁以上的人口越来越多。养老问题成为社会关注的热点。传统的养老方式是子女照顾父母。但是现在很多子女在外地工作。没有时间照顾老人。所以养老院的需求在增加。但是好的养老院费用不低。政府正在建立更完善的养老保障体系。', questions:[{ q:'中国面临什么社会问题？', options:['人口过多','老龄化','就业难','住房难'], correct:1 },{ q:'传统的养老方式是什么？', options:['去养老院','子女照顾','政府养老','自己养老'], correct:1 },{ q:'现在很多子女为什么不能照顾老人？', options:['不想照顾','在外地工作','太忙了','关系不好'], correct:1 },{ q:'政府正在做什么？', options:['建立养老保障体系','盖更多房子','提高工资','延长退休'], correct:0 }] },
        { id:'hrex_228', title:'中国白酒文化', titleEn:'Chinese Baijiu Culture', hsk:4, passage:'白酒是中国传统的酒精饮料。有几千年的历史。中国的酒文化很丰富。朋友聚会要喝酒。商务宴请也要喝酒。敬酒有讲究。晚辈要给长辈敬酒。碰杯时自己的杯沿要低于对方。但是过量饮酒有害健康。现在越来越多的人开始注意适量饮酒。无酒不成席的观念也在改变。', questions:[{ q:'白酒的历史有多久？', options:['几百年','几千年','一万年','几万年'], correct:1 },{ q:'什么场合要喝酒？', options:['朋友聚会和商务宴请','开会','上课','运动'], correct:0 },{ q:'敬酒时晚辈要注意什么？', options:['多喝','杯沿低于对方','说祝酒词','先干为敬'], correct:1 },{ q:'现在什么观念在改变？', options:['无酒不成席','酒是粮食精','少喝酒','不喝酒'], correct:0 }] },
        { id:'hrex_229', title:'中国姓氏文化', titleEn:'Chinese Surname Culture', hsk:4, passage:'中国人的姓氏有很多。百家姓是最有名的姓氏书。赵钱孙李是前四个。李姓是中国最大的姓氏。有将近一亿人姓李。中国人的姓氏来源很丰富。有的来自地名。有的来自官职。还有的来自祖先的名字。同姓的人五百年前可能是一家。中国人见面时常说您贵姓。', questions:[{ q:'百家姓前四个是什么？', options:['赵钱孙李','周吴郑王','冯陈褚卫','蒋沈韩杨'], correct:0 },{ q:'中国最大的姓氏是什么？', options:['王','李','张','刘'], correct:1 },{ q:'有多少人姓李？', options:['几千万','将近一亿','几亿','几百万'], correct:1 },{ q:'中国人见面时常问什么？', options:['你几岁','你叫什么','您贵姓','你从哪里来'], correct:2 }] },
        { id:'hrex_230', title:'外卖行业的发展', titleEn:'Development of Food Delivery', hsk:4, passage:'中国的外卖行业非常发达。手机下单三十分钟左右就能送到。外卖平台有美团和饿了么。骑手们在城市里穿梭。风雨无阻。外卖给人们的生活带来了很大方便。不用做饭也能吃上热饭。但是外卖也产生了大量塑料垃圾。一次性餐盒和塑料袋对环境造成压力。', questions:[{ q:'外卖通常多久能送到？', options:['十五分钟','三十分钟左右','一小时','两小时'], correct:1 },{ q:'文中提到哪两个外卖平台？', options:['美团和饿了么','百度外卖和口碑','滴滴和京东','淘宝和拼多多'], correct:0 },{ q:'外卖给生活带来什么？', options:['方便','便宜','健康','美味'], correct:0 },{ q:'外卖造成什么问题？', options:['交通堵塞','塑料垃圾','噪音','食品安全'], correct:1 }] },
        { id:'hrex_231', title:'雨水节气', titleEn:'Rain Water Solar Term', hsk:4, passage:'雨水是中国二十四节气中的第二个节气。通常在每年二月十八日到二十日之间。雨水节气意味着降水开始增多。气温回升。冰雪融化。农民开始准备春耕。雨水时节天气变化大。要注意春捂。不要着急脱掉厚衣服。这个时节吃的食物应该清淡一些。多吃蔬菜水果。', questions:[{ q:'雨水是第几个节气？', options:['第一个','第二个','第三个','第四个'], correct:1 },{ q:'雨水节气通常在什么时间？', options:['一月','二月十八到二十日','三月','四月'], correct:1 },{ q:'雨水时节天气怎么样？', options:['稳定','变化大','一直下雨','一直晴天'], correct:1 },{ q:'雨水时节要注意什么？', options:['多喝水','春捂','多运动','少吃'], correct:1 }] },
        { id:'hrex_232', title:'相亲文化', titleEn:'Matchmaking Culture', hsk:4, passage:'在中国相亲是一种常见的找对象方式。很多年轻人工作忙没时间谈恋爱。父母会帮忙安排相亲。公园里有相亲角。父母们拿着子女的信息互相交换。现在也有相亲网站和APP。相亲时双方会问对方的工作、收入和房子情况。这种直接的方式有人喜欢有人不喜欢。', questions:[{ q:'文中提到了几种相亲方式？', options:['一种','两种','三种','四种'], correct:2 },{ q:'相亲角在哪里？', options:['商场','公园','咖啡厅','办公室'], correct:1 },{ q:'相亲时会问什么？', options:['兴趣爱好','工作收入房子','身高体重','星座血型'], correct:1 },{ q:'为什么很多年轻人去相亲？', options:['喜欢相亲','工作忙没时间谈恋爱','父母逼的','找不到对象'], correct:1 }] },
        { id:'hrex_233', title:'中国快递员', titleEn:'Chinese Couriers', hsk:4, passage:'快递员是中国城市中常见的职业。他们每天骑着电动车穿梭在大街小巷。无论刮风下雨都要准时送达包裹。双十一期间快递量暴增。快递员每天要送几百件。工作非常辛苦。但是快递员的收入不算高。而且没有稳定的社保。随着无人机和智能快递柜的发展。快递行业也在发生变化。', questions:[{ q:'快递员用什么交通工具？', options:['自行车','电动车','汽车','摩托车'], correct:1 },{ q:'双十一期间快递量怎么样？', options:['减少','暴增','不变','消失'], correct:1 },{ q:'快递员每天送多少件？', options:['几十件','几百件','几千件','上万件'], correct:1 },{ q:'什么在发展影响快递行业？', options:['无人机和智能快递柜','机器人','无人超市','人工智能'], correct:0 }] },
        { id:'hrex_234', title:'中国的山岳崇拜', titleEn:'Mountain Worship in China', hsk:4, passage:'中国人民间有山岳崇拜的传统。五岳是中国最著名的五座山。东岳泰山在山东。西岳华山在陕西。南岳衡山在湖南。北岳恒山在山西。中岳嵩山在河南。古代皇帝会去泰山封禅。认为泰山离天最近。现在很多人去五岳旅游。登山也是锻炼身体的好方式。', questions:[{ q:'中国最著名的五座山叫什么？', options:['五岳','五峰','五岭','五山'], correct:0 },{ q:'泰山位于哪个省？', options:['陕西','湖南','山东','河南'], correct:2 },{ q:'古代皇帝去泰山做什么？', options:['旅游','封禅','居住','开会'], correct:1 },{ q:'五岳中哪个在陕西？', options:['泰山','华山','衡山','嵩山'], correct:1 }] },
        { id:'hrex_235', title:'中国春运抢票', titleEn:'Spring Festival Ticket Rush', hsk:4, passage:'春运期间买火车票是一件很困难的事。售票系统一开放。热门线路的票几秒钟就卖光了。所以人们要想办法抢票。有些人用抢票软件。有些人找朋友帮忙加速。还有些人买短途票上车后再补票。黄牛也在高价倒卖车票。铁路部门在严厉打击黄牛。并且增加了车次来缓解购票难。', questions:[{ q:'春运期间车票卖得怎么样？', options:['很慢','几秒钟卖光','没人买','不限量'], correct:1 },{ q:'抢票软件的作用是什么？', options:['自动购票','加价购票','退票','查票'], correct:0 },{ q:'黄牛在做什么？', options:['帮忙抢票','高价倒卖车票','免费送票','退票'], correct:1 },{ q:'铁路部门采取了什么措施？', options:['提高票价','打击黄牛增加车次','减少车次','取消抢票软件'], correct:1 }] },
        { id:'hrex_236', title:'中国人在海外买房', titleEn:'Chinese Buying Property Abroad', hsk:4, passage:'越来越多的中国人开始在国外买房。美国、澳大利亚、英国是最受欢迎的国家。有些人为了孩子留学。有些人为了投资。还有些人是为了移民。在海外买房需要注意很多问题。不同国家的法律不同。税费也不同。还有一个问题是管理。房子如果出租需要有人负责维护。', questions:[{ q:'哪些国家是中国人海外买房的热门？', options:['美澳英','日韩','法德','意西'], correct:0 },{ q:'为什么在海外买房？', options:['留学投资移民','度假','养老','工作需要'], correct:0 },{ q:'在海外买房要注意什么？', options:['法律税费和管理','房价','装修','邻居'], correct:0 },{ q:'房子出租需要什么？', options:['有人负责维护','降价','广告','中介'], correct:0 }] },
        { id:'hrex_237', title:'中国方言', titleEn:'Chinese Dialects', hsk:4, passage:'中国有几十种方言。不同地方的人说不同的话。普通话是全国通用的语言。但是很多人在家里还是说方言。常见的方言有粤语、闽南语、上海话和四川话等。粤语在广东和香港使用。闽南语在台湾和福建使用。方言之间差别很大。比如粤语有九个声调。普通话只有四个。', questions:[{ q:'中国有多少种方言？', options:['十几种','几十种','上百种','几种'], correct:1 },{ q:'什么话是全国通用的？', options:['粤语','普通话','闽南语','上海话'], correct:1 },{ q:'粤语在哪里使用？', options:['福建和台湾','广东和香港','上海和浙江','四川和重庆'], correct:1 },{ q:'粤语有几个声调？', options:['四个','六个','九个','八个'], correct:2 }] },
        { id:'hrex_238', title:'中国电竞产业', titleEn:'Chinese E-Sports Industry', hsk:4, passage:'电子竞技在中国发展很快。电竞已经正式成为体育项目。中国有专业的电竞俱乐部和联赛。很多年轻人梦想成为职业电竞选手。优秀的选手年收入很高。但是职业选手的训练很辛苦。每天要练习十几个小时。电竞产业也带动了直播、解说等相关职业。不过家长仍然担心孩子沉迷游戏。', questions:[{ q:'电竞在中国发展怎么样？', options:['很慢','很快','刚起步','停滞'], correct:1 },{ q:'电竞已经成为什么？', options:['娱乐项目','体育项目','教育项目','艺术项目'], correct:1 },{ q:'职业选手每天训练多久？', options:['八小时','十几个小时','六小时','四小时'], correct:1 },{ q:'家长担心什么？', options:['孩子受伤','孩子沉迷游戏','选手收入','比赛安全'], correct:1 }] },
        { id:'hrex_239', title:'中国凉茶文化', titleEn:'Chinese Herbal Tea Culture', hsk:4, passage:'凉茶是广东人喜欢喝的一种饮料。虽然叫茶但实际上是用中草药熬制的。凉茶有清热解毒的作用。夏天喝凉茶可以防暑。广州有很多凉茶铺。路边的凉茶铺卖各种凉茶。二十四味是最常见的一种。凉茶的味道很苦。但是广东人相信良药苦口。现在瓶装凉茶在超市里也能买到。', questions:[{ q:'凉茶是用什么做的？', options:['茶叶','中草药','水果','花'], correct:1 },{ q:'凉茶有什么作用？', options:['提神','清热解毒','助消化','美容'], correct:1 },{ q:'最常见的凉茶是什么？', options:['二十四味','王老吉','加多宝','和其正'], correct:0 },{ q:'凉茶的味道怎么样？', options:['甜的','很苦','酸的','辣的'], correct:1 }] },
        { id:'hrex_240', title:'中国职场文化', titleEn:'Chinese Workplace Culture', hsk:4, passage:'中国职场有一些独特的文化。加班是比较普遍的现象。九九六工作制在很多互联网公司存在。员工之间的关系也比较微妙。和领导搞好关系很重要。饭桌上谈生意的习惯很常见。酒量好有时候比能力还重要。不过新一代年轻人开始抵制这种文化。他们更注重工作生活平衡。', questions:[{ q:'中国职场什么现象比较普遍？', options:['早退','加班','休假','兼职'], correct:1 },{ q:'九九六工作制在哪里存在？', options:['工厂','互联网公司','学校','医院'], correct:1 },{ q:'谈生意常常在哪里进行？', options:['办公室','饭桌上','咖啡厅','网上'], correct:1 },{ q:'新一代年轻人注重什么？', options:['高工资','工作生活平衡','升职','加班费'], correct:1 }] },
        { id:'hrex_241', title:'丝绸之路的历史', titleEn:'History of the Silk Road', hsk:5, passage:'丝绸之路是古代连接中国和西方的贸易路线。最早由张骞在汉朝时期开辟。这条路线全长七千多公里。中国的丝绸、瓷器和茶叶通过这条路线运往西方。西方的香料、珠宝和玻璃也传入了中国。丝绸之路不仅促进了贸易往来，还促进了文化交流。佛教就是通过丝绸之路从印度传入中国的。一带一路倡议正是借鉴了丝绸之路的历史意义。', questions:[{ q:'丝绸之路最早由谁开辟？', options:['郑和','张骞','司马迁','班超'], correct:1 },{ q:'丝绸之路全长多少公里？', options:['五千多公里','六千多公里','七千多公里','一万公里'], correct:2 },{ q:'什么宗教通过丝绸之路传入中国？', options:['伊斯兰教','基督教','佛教','道教'], correct:2 },{ q:'一带一路借鉴了什么？', options:['丝绸之路的历史意义','长城','大运河','茶马古道'], correct:0 }] },
        { id:'hrex_242', title:'中国高考改革', titleEn:'Reform of College Entrance Exam', hsk:5, passage:'中国的高考制度一直在改革。传统的文理分科将被取消。学生可以根据自己的兴趣选择科目。英语考试也进行了调整。一年可以考两次。取最高成绩。综合素质评价也被纳入招生参考。这些改革旨在减轻学生负担。促进全面发展。但是改革的推行也面临挑战。城乡教育资源的差距仍然很大。农村学生在综合素质评价中可能处于劣势。', questions:[{ q:'高考改革取消了什么？', options:['所有考试','文理分科','英语考试','面试'], correct:1 },{ q:'英语考试一年可以考几次？', options:['一次','两次','三次','四次'], correct:1 },{ q:'改革的目的是什么？', options:['增加考试难度','减轻负担促进全面发展','增加科目','减少招生'], correct:1 },{ q:'改革面临什么挑战？', options:['学生反对','城乡教育资源差距','教师不足','经费不够'], correct:1 }] },
        { id:'hrex_243', title:'中国的北斗卫星系统', titleEn:'Chinas BeiDou Satellite System', hsk:5, passage:'北斗是中国自主研发的卫星导航系统。已经为全球用户提供定位、导航和授时服务。北斗系统精度很高，可以达到厘米级别。广泛应用于交通运输、农业、渔业和救灾等领域。渔民在海上可以用北斗发送短报文。这是北斗的特色功能。北斗的建成让中国不再依赖其他国家的导航系统。对国家安全和经济发展都有重要意义。', questions:[{ q:'北斗系统能达到什么精度？', options:['米级','厘米级','毫米级','分米级'], correct:1 },{ q:'北斗在什么领域有应用？', options:['交通农业渔业救灾','娱乐教育医疗','金融法律','军事航天'], correct:0 },{ q:'北斗有什么特色功能？', options:['通话功能','发送短报文','拍照功能','视频功能'], correct:1 },{ q:'北斗的意义是什么？', options:['提高国际地位','不再依赖别国导航系统','增加就业','促进旅游'], correct:1 }] },
        { id:'hrex_244', title:'中国的中产阶级', titleEn:'Chinas Middle Class', hsk:5, passage:'随着经济的快速发展，中国的中产阶级规模不断扩大。中产阶级通常指收入稳定、有房有车、受过良好教育的人群。他们注重生活品质。喜欢旅游、健身和品尝美食。对子女教育投入很大。送孩子出国留学成为趋势。但是中产阶级也有焦虑。房价高、工作压力大、养老负担重都是问题。消费降级的现象也开始出现。', questions:[{ q:'中产阶级通常具备什么特征？', options:['收入稳定有房有车教育良好','收入高工作轻松','不需要工作','很年轻'], correct:0 },{ q:'中产阶级对孩子教育怎么样？', options:['不关心','投入很大','顺其自然','让孩子自己决定'], correct:1 },{ q:'中产阶级有什么焦虑？', options:['房价高压力大养老负担','找不到工作','没朋友','不会理财'], correct:0 },{ q:'开始出现什么现象？', options:['消费升级','消费降级','移民潮','创业潮'], correct:1 }] },
        { id:'hrex_245', title:'故宫文物修复', titleEn:'Cultural Relic Restoration in the Forbidden City', hsk:5, passage:'故宫博物院收藏了大量珍贵文物。但是很多文物因为年代久远出现了破损。文物修复师的工作就是让这些文物恢复原貌。修复一件文物可能需要几个月甚至几年的时间。修复师需要有耐心和精湛的技艺。还要了解历史文化背景。近年来一部纪录片让文物修复师这个职业走进了大众视野。年轻人对这个职业的兴趣也在增加。', questions:[{ q:'故宫收藏了什么？', options:['现代艺术品','大量珍贵文物','外国文物','家具'], correct:1 },{ q:'修复一件文物需要多久？', options:['几天','几个月甚至几年','几个小时','一周'], correct:1 },{ q:'修复师需要具备什么？', options:['耐心技艺和历史文化知识','体力和速度','美术基础','数学能力'], correct:0 },{ q:'什么让修复师走进大众视野？', options:['新闻报道','纪录片','电影','广告'], correct:1 }] },
        { id:'hrex_246', title:'共享经济的兴起', titleEn:'Rise of the Sharing Economy', hsk:5, passage:'共享经济在中国经历了一个从兴起到调整的过程。共享单车是最典型的例子。初期大量资本涌入。各种颜色的共享单车遍布城市街头。但是过度竞争导致很多公司倒闭。大量废弃单车成为城市垃圾。共享充电宝也面临类似问题。虽然使用方便，但归还困难。共享经济的教训是企业不能只靠烧钱扩张。需要找到可持续的盈利模式。', questions:[{ q:'共享经济的典型例子是什么？', options:['共享汽车','共享单车','共享房屋','共享知识'], correct:1 },{ q:'共享单车初期出现了什么问题？', options:['数量太少','过度竞争大量公司倒闭','太贵','不安全'], correct:1 },{ q:'共享充电宝有什么问题？', options:['充电太慢','归还困难','价格太贵','容易损坏'], correct:1 },{ q:'共享经济的教训是什么？', options:['要多烧钱','要找可持续盈利模式','要扩大市场','要减少投入'], correct:1 }] },
        { id:'hrex_247', title:'中国电影市场', titleEn:'Chinese Film Market', hsk:5, passage:'中国已经成为全球第二大电影市场。国产电影票房屡创新高。战狼二和流浪地球都是现象级作品。中国观众越来越支持国产电影。古装大片和喜剧片仍然受欢迎。但是现实主义题材也开始崛起。动画电影的技术水平也在提高。哪吒之魔童降世创下了动画电影票房纪录。不过中国电影在海外市场的表现仍然不够理想。文化差异是主要的障碍。', questions:[{ q:'中国是全球第几大电影市场？', options:['第一','第二','第三','第四'], correct:1 },{ q:'文中提到了哪些电影？', options:['战狼二流浪地球哪吒','复仇者联盟','阿凡达','泰坦尼克号'], correct:0 },{ q:'什么题材的电影开始崛起？', options:['科幻片','现实主义题材','恐怖片','纪录片'], correct:1 },{ q:'中国电影在海外面临什么障碍？', options:['技术问题','文化差异','语言问题','资金问题'], correct:1 }] },
        { id:'hrex_248', title:'支付宝和微信支付', titleEn:'Alipay and WeChat Pay', hsk:5, passage:'支付宝和微信支付是中国最主要的移动支付工具。几乎覆盖了所有消费场景。从大型商场到路边小摊都可以扫码支付。移动支付的普及率在中国非常高。连乞丐都接受扫码捐款。移动支付不仅方便了消费者，还帮助商家提高了效率。不需要找零钱。也减少了假币的风险。但是老年人不太会使用智能手机支付。数字鸿沟问题值得关注。', questions:[{ q:'中国最主要的移动支付工具有哪些？', options:['支付宝和微信支付','银行卡和现金','信用卡','Apple Pay'], correct:0 },{ q:'移动支付覆盖了哪些场景？', options:['只有大商场','所有消费场景','只有网上','只有超市'], correct:1 },{ q:'移动支付帮助商家减少了什么风险？', options:['盗窃风险','假币风险','火灾风险','退货风险'], correct:1 },{ q:'移动支付带来了什么问题？', options:['隐私问题','数字鸿沟','网络问题','安全问题'], correct:1 }] },
        { id:'hrex_249', title:'中国的垃圾分类进程', titleEn:'Chinas Garbage Sorting Process', hsk:5, passage:'垃圾分类在中国推行了几年。上海是最早实施强制垃圾分类的城市之一。垃圾分为可回收物、有害垃圾、湿垃圾和干垃圾四类。刚开始市民很不适应。很多人搞不清楚怎么分类。出现了很多有趣的现象。比如有人把垃圾分类做成游戏。还有人专门帮忙分类。经过一段时间的适应。越来越多的人养成了分类的习惯。垃圾分类对环境保护有重要意义。', questions:[{ q:'哪个城市最早实施强制垃圾分类？', options:['北京','上海','广州','深圳'], correct:1 },{ q:'垃圾分为几类？', options:['两类','三类','四类','五类'], correct:2 },{ q:'刚开始市民怎么样？', options:['很适应','很不适应','很欢迎','没感觉'], correct:1 },{ q:'垃圾分类有什么意义？', options:['美化城市','保护环境','节约时间','降低成本'], correct:1 }] },
        { id:'hrex_250', title:'中国航天成就', titleEn:'Chinas Aerospace Achievements', hsk:5, passage:'中国的航天事业取得了举世瞩目的成就。嫦娥探月工程成功实现了月球背面软着陆。这是人类历史上第一次。祝融号火星车在火星表面行驶。中国人独立完成了空间站的建设。天宫空间站已经接待了多批宇航员。中国还计划在2030年前实现载人登月。这些成就的背后是几代航天人的努力。也展示了中国科技实力的快速提升。', questions:[{ q:'嫦娥工程实现了什么第一次？', options:['载人登月','月球背面软着陆','火星登陆','空间站建设'], correct:1 },{ q:'祝融号是什么？', options:['月球车','火星车','卫星','空间站'], correct:1 },{ q:'天宫是什么？', options:['卫星','空间站','火箭','探测器'], correct:1 },{ q:'中国计划什么时候实现载人登月？', options:['2025年','2030年前','2035年','2040年'], correct:1 }] },
        { id:'hrex_251', title:'中国的医保制度', titleEn:'Chinas Medical Insurance System', hsk:5, passage:'中国建立了覆盖全民的基本医疗保险制度。城镇职工医保和城乡居民医保是两大支柱。医保可以报销一部分医疗费用。减轻了患者的负担。但是医保也有不足之处。有些昂贵的进口药不能报销。异地就医的报销流程也比较复杂。近年来国家推行药品集中采购政策。大幅降低了药品价格。还有大病保险作为补充。医保制度还在不断完善中。', questions:[{ q:'中国医保的两大支柱是什么？', options:['城镇职工和城乡居民医保','公立和私立医保','门诊和住院医保','药品和手术医保'], correct:0 },{ q:'医保有什么不足？', options:['报销太少','进口药不能报销','服务态度差','医院太少'], correct:1 },{ q:'国家推行了什么政策降低药价？', options:['药品限价','药品集中采购','药品补贴','药品进口'], correct:1 },{ q:'医保制度的现状如何？', options:['已经完美','还在不断完善','没有变化','在倒退'], correct:1 }] },
        { id:'hrex_252', title:'中国的桥梁建设', titleEn:'Chinas Bridge Construction', hsk:5, passage:'中国是世界闻名的桥梁大国。港珠澳大桥是世界上最长的跨海大桥。全长五十五公里。连接了香港、珠海和澳门。这座大桥建设难度极大。工程师们攻克了许多技术难题。还采用了抗震设计。可以抵抗八级地震。另外北盘江大桥是世界上最高的桥梁。桥面到谷底有五百多米。中国桥梁的建造技术已经达到世界领先水平。', questions:[{ q:'港珠澳大桥全长多少？', options:['四十五公里','五十五公里','六十五公里','七十五公里'], correct:1 },{ q:'港珠澳大桥连接了哪些城市？', options:['香港深圳广州','香港珠海澳门','香港澳门深圳','广州珠海澳门'], correct:1 },{ q:'大桥可以抵抗几级地震？', options:['六级','七级','八级','九级'], correct:2 },{ q:'北盘江大桥以什么闻名？', options:['最长','最高','最宽','最古老'], correct:1 }] },
        { id:'hrex_253', title:'中国育儿观念变化', titleEn:'Changing Parenting Concepts in China', hsk:5, passage:'中国父母的育儿观念正在发生变化。过去父母信奉棍棒底下出孝子。打骂是常见的教育方式。现在越来越多的父母开始学习科学育儿。尊重孩子的个性发展。课外辅导班的热度也在降温。双减政策实施后。学科类辅导班大量减少。非学科类的兴趣班受到欢迎。但是家长的焦虑并没有完全消失。中考分流政策让很多家长担心孩子上不了高中。', questions:[{ q:'过去父母信奉什么教育方式？', options:['鼓励教育','棍棒底下出孝子','放任自流','奖励教育'], correct:1 },{ q:'现在父母注重什么？', options:['成绩排名','尊重孩子个性发展','听话','早睡早起'], correct:1 },{ q:'双减政策减少了什么？', options:['作业量','学科类辅导班','考试','上课时间'], correct:1 },{ q:'家长仍然担心什么？', options:['孩子不听话','中考分流','老师不好','作业太少'], correct:1 }] },
        { id:'hrex_254', title:'中国人均寿命提高', titleEn:'Increasing Life Expectancy in China', hsk:5, passage:'中国的人均预期寿命在不断提高。从1949年的三十五岁提高到了现在的七十八岁。这得益于医疗条件的改善和生活水平的提高。过去很多传染病夺走了大量生命。现在这些疾病已经被有效控制。取而代之的是慢性病成为主要死亡原因。高血压、糖尿病和癌症是常见的慢性病。健康的生活方式对预防慢性病非常重要。合理饮食和适度运动是关键。', questions:[{ q:'1949年中国人均寿命是多少？', options:['三十五岁','四十五岁','五十五岁','六十五岁'], correct:0 },{ q:'现在中国人均寿命大约多少？', options:['七十岁','七十八岁','八十五岁','九十岁'], correct:1 },{ q:'现在主要死亡原因是什么？', options:['传染病','慢性病','意外','自然灾害'], correct:1 },{ q:'什么对预防慢性病非常重要？', options:['吃药','健康生活方式','定期体检','住院'], correct:1 }] },
        { id:'hrex_255', title:'中国的网红经济', titleEn:'Chinas Influencer Economy', hsk:5, passage:'网红经济是中国互联网的一大特色。网红通过社交媒体积累粉丝。然后通过直播带货、广告代言和知识付费等方式变现。李佳琦是最著名的带货主播之一。一场直播的销售额可以达到几亿元。网红经济的门槛看起来很低。但实际上竞争非常激烈。只有极少数的头部网红能赚到很多钱。大多数小网红收入有限。而且网红行业更新换代很快。', questions:[{ q:'网红通过什么方式变现？', options:['直播带货广告代言知识付费','工资','投资收益','彩票'], correct:0 },{ q:'李佳琦是什么职业？', options:['演员','带货主播','歌手','运动员'], correct:1 },{ q:'网红经济的门槛怎么样？', options:['很高','看起来低但竞争激烈','非常低','没有门槛'], correct:1 },{ q:'大多数小网红收入怎么样？', options:['很高','有限','和上班一样','没有收入'], correct:1 }] },
        { id:'hrex_256', title:'中国少数民族文化', titleEn:'Chinese Ethnic Minority Culture', hsk:5, passage:'中国有五十六个民族。汉族占大多数。其他五十五个是少数民族。少数民族有自己独特的文化传统。傣族有泼水节。蒙古族有那达慕大会。藏族有藏历新年。他们的服装、音乐和舞蹈也各具特色。政府建立了民族区域自治制度。保护少数民族的语言和文化。旅游业的兴起让更多人了解少数民族文化。但也面临文化商业化的问题。', questions:[{ q:'中国有多少个少数民族？', options:['五十五个','五十六个','五十个','六十个'], correct:0 },{ q:'傣族的传统节日是什么？', options:['火把节','泼水节','那达慕大会','藏历新年'], correct:1 },{ q:'蒙古族的传统活动是什么？', options:['泼水节','那达慕大会','赛龙舟','舞龙舞狮'], correct:1 },{ q:'旅游业带来了什么问题？', options:['文化消失','文化商业化','文化冲突','文化误解'], correct:1 }] },
        { id:'hrex_257', title:'中国的住房变迁', titleEn:'Housing Changes in China', hsk:5, passage:'中国城镇居民的住房条件发生了巨大的变化。几十年前大多数家庭住在单位分的筒子楼里。没有独立厨房和卫生间。后来商品房市场兴起。人们可以自由买卖房屋。住房面积越来越大。小区环境也越来越好。但是房价飙升让年轻人买房变得困难。很多人选择租房子住。长租公寓和保障性住房正在成为解决住房问题的重要途径。', questions:[{ q:'几十年前人们住在什么房子里？', options:['别墅','筒子楼','公寓','四合院'], correct:1 },{ q:'筒子楼缺少什么？', options:['独立厨房和卫生间','卧室','窗户','暖气'], correct:0 },{ q:'商品房市场兴起后房价怎么样？', options:['下降','飙升','不变','波动不大'], correct:1 },{ q:'什么正在成为解决住房问题的途径？', options:['长租公寓和保障性住房','酒店','合租','买房'], correct:0 }] },
        { id:'hrex_258', title:'中国茶饮市场', titleEn:'Chinese Tea Beverage Market', hsk:5, passage:'中国的新式茶饮市场发展迅猛。喜茶、奈雪的茶等品牌受到年轻人追捧。与传统茶馆不同。新式茶饮店注重创新和包装。水果茶、奶盖茶等新品种层出不穷。一杯奶茶的价格从十几元到三十多元不等。茶饮店门口经常排着长队。但是茶饮市场也面临同质化竞争。品牌之间互相模仿。为了吸引顾客。商家不断推出联名款和限定款。', questions:[{ q:'文中提到了哪些新式茶饮品牌？', options:['喜茶奈雪的茶','立顿','统一','康师傅'], correct:0 },{ q:'新式茶饮和传统茶馆有什么不同？', options:['更注重创新和包装','价格更低','更传统','服务更好'], correct:0 },{ q:'一杯奶茶的价格范围是多少？', options:['五到十元','十几到三十多元','五十到一百元','一百元以上'], correct:1 },{ q:'茶饮市场面临什么问题？', options:['供不应求','同质化竞争','没人喝','质量差'], correct:1 }] },
        { id:'hrex_259', title:'中国传统文化复兴', titleEn:'Revival of Traditional Chinese Culture', hsk:5, passage:'近年来中国出现了一股传统文化复兴的热潮。穿汉服、学国学、练书法成为时尚。诗词大会和国家宝藏等电视节目受到欢迎。越来越多的年轻人对传统文化产生兴趣。汉服社在大学里很常见。家长们也愿意送孩子去学国画和古筝。这种复兴现象反映了文化自信的提升。不过也有人担心传统文化会被过度商业化。变成一种消费符号。', questions:[{ q:'哪些电视节目受到欢迎？', options:['诗词大会国家宝藏','快乐大本营','奔跑吧兄弟','中国好声音'], correct:0 },{ q:'大学里什么社团很常见？', options:['汉服社','电竞社','舞蹈社','篮球社'], correct:0 },{ q:'家长愿意送孩子学什么？', options:['编程','国画和古筝','英语','数学'], correct:1 },{ q:'有人担心什么？', options:['传统文化消失','过度商业化','没人学','太贵了'], correct:1 }] },
        { id:'hrex_260', title:'中国的主要河流', titleEn:'Major Rivers of China', hsk:5, passage:'中国有两条主要的河流。长江和黄河。长江是中国最长的河流。全长六千三百多公里。流经十一个省市。长江流域经济发达。上海、武汉、重庆等大城市都在长江沿岸。黄河是中华民族的母亲河。全长五千四百多公里。黄河流域是中华文明的发源地。但是黄河含沙量很大。下游经常改道。历史上造成过多次水灾。近年来通过治理得到了改善。', questions:[{ q:'长江全长多少？', options:['五千四百公里','六千三百公里','七千公里','八千公里'], correct:1 },{ q:'长江流经几个省市？', options:['九个','十个','十一个','十二个'], correct:2 },{ q:'黄河有什么问题？', options:['含沙量大经常改道','水太少','污染严重','结冰期长'], correct:0 },{ q:'黄河下游历史上怎么样？', options:['经常断流','多次水灾','航运发达','水很清'], correct:1 }] },
        { id:'hrex_261', title:'中国新能源汽车出口', titleEn:'Chinas New Energy Vehicle Exports', hsk:5, passage:'中国已经成为全球最大的新能源汽车生产和出口国。比亚迪、蔚来等品牌在国际市场上越来越有竞争力。欧洲是主要出口市场之一。中国新能源汽车在技术和价格上都有优势。电池技术尤其领先。续航里程不断提高。充电速度也在加快。但是出口也面临挑战。欧盟对中国电动车加征关税。一些国家对中国电池的安全性有疑虑。', questions:[{ q:'中国在新能源汽车方面是全球第几？', options:['最大生产出口国','第二大','第三大','第四大'], correct:0 },{ q:'哪些品牌在国际市场有竞争力？', options:['比亚迪蔚来','丰田本田','大众宝马','福特通用'], correct:0 },{ q:'中国新能源汽车的优势是什么？', options:['技术和价格优势','品牌历史','服务好','设计漂亮'], correct:0 },{ q:'出口面临什么挑战？', options:['关税和安全疑虑','运输问题','语言障碍','文化差异'], correct:0 }] },
        { id:'hrex_262', title:'中国春运的变迁', titleEn:'Changes in Spring Festival Travel', hsk:5, passage:'春运被称为地球上最大规模的人口迁徙。过去人们只能坐绿皮火车回家。车厢里挤满了人和行李。旅途漫长而痛苦。现在高铁大大缩短了旅行时间。环境也更加舒适。买票方式也从窗口排队变成了网上抢票。人脸识别进站提高了效率。但是春运的压力依然存在。自驾回家的人越来越多。高速公路经常出现严重拥堵。', questions:[{ q:'过去人们坐什么火车回家？', options:['高铁','绿皮火车','动车','城际列车'], correct:1 },{ q:'现在买票方式变成了什么？', options:['电话购票','网上抢票','窗口排队','自动售票机'], correct:1 },{ q:'什么技术提高了进站效率？', options:['二维码','人脸识别','身份证','指纹'], correct:1 },{ q:'现在春运出现了什么新问题？', options:['买不到票','高速公路拥堵','火车太慢','飞机太贵'], correct:1 }] },
        { id:'hrex_263', title:'中国的老龄化挑战', titleEn:'Chinas Aging Challenge', hsk:5, passage:'中国正在以前所未有的速度进入老龄化社会。预计到2050年六十岁以上人口将超过五亿。老龄化给社会带来了多方面的挑战。劳动力人口减少。养老金支付压力增大。医疗资源需求增加。养老产业虽然蓬勃发展。但是服务质量参差不齐。社区养老服务还不完善。如何让老年人老有所养、老有所乐是一个需要全社会共同面对的问题。', questions:[{ q:'预计2050年六十岁以上人口将超过多少？', options:['三亿','四亿','五亿','六亿'], correct:2 },{ q:'老龄化对劳动力有什么影响？', options:['劳动力增加','劳动力减少','没有影响','劳动力不变'], correct:1 },{ q:'养老产业存在什么问题？', options:['发展太慢','服务质量参差不齐','价格太贵','没人愿意做'], correct:1 },{ q:'如何让老年人老有所养老有所乐是？', options:['一个人的问题','需要全社会面对的问题','政府的问题','子女的问题'], correct:1 }] },
        { id:'hrex_264', title:'中国电子商务发展', titleEn:'Development of E-commerce in China', hsk:5, passage:'中国的电子商务规模居世界首位。淘宝、京东和拼多多是三大电商平台。直播电商是近年来的新趋势。网红主播带货能力惊人。农村电商也发展迅速。农民通过电商平台把农产品卖到全国各地。社交电商通过微信群和朋友圈进行营销。跨境电商让中国消费者可以买到全球商品。电商的发展改变了传统零售业的格局。也创造了大量就业机会。', questions:[{ q:'中国电商规模在世界上排第几？', options:['第二','首位','第三','第四'], correct:1 },{ q:'文中提到了哪三个电商平台？', options:['淘宝京东拼多多','天猫苏宁国美','亚马逊易趣','当当卓越'], correct:0 },{ q:'农村电商有什么作用？', options:['卖农产品到全国','卖家电','卖服装','卖电子产品'], correct:0 },{ q:'跨境电商让消费者可以做什么？', options:['买全球商品','卖东西到国外','旅游','留学'], correct:0 }] },
        { id:'hrex_265', title:'中国传统文化中的孝道', titleEn:'Filial Piety in Chinese Culture', hsk:5, passage:'孝道是中国传统文化中非常重要的价值观。百善孝为先。意思是在所有美德中孝顺是最重要的。古代的二十四孝故事讲述了各种孝顺父母的事迹。现代社会孝道的形式发生了变化。但是核心精神没有变。孝顺父母不仅是物质上的供养。更重要的是精神上的关心。常回家看看比给钱更重要。', questions:[{ q:'百善孝为先的意思是什么？', options:['善良最重要','孝顺最重要','百种美德','先做好事'], correct:1 },{ q:'二十四孝包含什么？', options:['孝顺故事','历史事件','民间传说','神话故事'], correct:0 },{ q:'现代社会的孝道核心是什么？', options:['物质供养','精神关心','给钱买房','请保姆'], correct:1 },{ q:'什么比给钱更重要？', options:['买礼物','常回家看看','打电话','做饭'], correct:1 }] },
        { id:'hrex_266', title:'中国知识付费', titleEn:'Knowledge Payment in China', hsk:5, passage:'知识付费在中国发展迅速。得到、知乎和喜马拉雅是主要平台。用户可以花钱购买课程、听书或者订阅专栏。知识付费满足了人们碎片化学习的需求。很多人愿意为优质内容付费。但是知识付费也存在问题。课程质量良莠不齐。有些课程打着快速成功的旗号吸引用户。实际上内容空洞。而且买了课之后很多人并没有坚持学完。续费率不高。', questions:[{ q:'文中提到了哪些知识付费平台？', options:['得到知乎喜马拉雅','B站抖音快手','微博小红书','网易云QQ音乐'], correct:0 },{ q:'知识付费满足了什么需求？', options:['碎片化学习','社交需求','娱乐需求','购物需求'], correct:0 },{ q:'知识付费存在什么问题？', options:['内容太好','课程质量良莠不齐','价格太贵','平台太少'], correct:1 },{ q:'买了课之后很多人怎么样？', options:['认真学完','没有坚持学完','退课','分享给朋友'], correct:1 }] },
        { id:'hrex_267', title:'中国的快递包装问题', titleEn:'Chinas Express Packaging Problem', hsk:5, passage:'随着电商的繁荣，快递包装垃圾问题日益严重。一件小小的商品往往被多层包装。纸箱、胶带、气泡膜和塑料袋都是常见的包装材料。这些包装大部分只能使用一次。回收率很低。塑料包装需要几百年才能降解。对环境造成了巨大压力。一些电商平台开始推广绿色包装。使用可降解材料。但是成本较高。消费者也需要改变习惯。主动参与包装回收。', questions:[{ q:'快递包装垃圾问题为什么日益严重？', options:['快递数量多包装过度','包装太贵','没有垃圾桶','回收太麻烦'], correct:0 },{ q:'常见包装材料包括什么？', options:['纸箱胶带气泡膜塑料袋','金属','木头','玻璃'], correct:0 },{ q:'塑料包装需要多久降解？', options:['几十年','几百年','几年','几千年'], correct:1 },{ q:'推广绿色包装面临什么障碍？', options:['成本较高','技术不成熟','没人支持','政府不鼓励'], correct:0 }] },
        { id:'hrex_268', title:'中国的广场舞文化', titleEn:'Chinas Square Dance Culture', hsk:5, passage:'广场舞已经成为中国城市的一道独特风景。每天早晚在广场和公园里随处可见跳舞的人群。参与者主要是退休的中老年女性。她们随着音乐整齐地跳着各种舞蹈。广场舞不仅锻炼了身体。还丰富了退休生活。让老人们找到了社交圈子。但是广场舞也引发了一些社会矛盾。音乐声音太大影响了附近居民休息。场地争夺也时有发生。', questions:[{ q:'广场舞的主要参与者是谁？', options:['退休中老年女性','年轻人','小孩','男性'], correct:0 },{ q:'广场舞有什么积极作用？', options:['锻炼身体丰富社交','赚钱','出名','减肥'], correct:0 },{ q:'广场舞引发了什么矛盾？', options:['噪音和场地争夺','打架','交通堵塞','环境污染'], correct:0 }] },
        { id:'hrex_269', title:'中国改革开放的成就', titleEn:'Achievements of Chinas Reform and Opening', hsk:5, passage:'改革开放以来中国发生了翻天覆地的变化。经济总量跃居世界第二。数亿人摆脱了贫困。城市化进程加速推进。基础设施不断完善。高速公路和高速铁路网络覆盖全国。人民生活水平显著提高。从自行车王国变成了汽车大国。互联网和智能手机普及率很高。但是发展也带来了环境问题。收入差距仍然存在。未来需要在高质量发展的道路上继续前进。', questions:[{ q:'中国经济总量现在居世界第几？', options:['第一','第二','第三','第四'], correct:1 },{ q:'改革开放后多少人摆脱了贫困？', options:['几千万','数亿','十几亿','几百万'], correct:1 },{ q:'文中提到了哪些变化？', options:['基础设施完善生活水平提高','政治制度变化','文化革命','军事扩张'], correct:0 },{ q:'发展中存在什么问题？', options:['环境问题收入差距','人口太多','教育落后','医疗不足'], correct:0 }] },
        { id:'hrex_270', title:'中国婚恋观的转变', titleEn:'Changing Views on Marriage', hsk:5, passage:'中国年轻人的婚恋观正在发生深刻变化。结婚率连续多年下降。初婚年龄推迟。大城市平均初婚年龄已经超过三十岁。单身人口越来越多。不婚主义者和丁克家庭也在增多。父母催婚的压力仍然是很多年轻人的困扰。相亲市场火爆。但是找到合适的对象并不容易。离婚率上升也是值得关注的现象。人们对婚姻质量的要求更高了。', questions:[{ q:'结婚率在怎样变化？', options:['上升','下降','不变','波动'], correct:1 },{ q:'大城市平均初婚年龄是多少？', options:['二十五岁','超过三十岁','三十五岁','四十岁'], correct:1 },{ q:'文中提到了哪些婚姻现象？', options:['不婚主义丁克家庭','闪婚闪离','跨国婚姻','裸婚'], correct:0 },{ q:'离婚率上升说明了什么？', options:['婚姻质量要求更高了','人们更随便了','社会退步了','法律更严了'], correct:0 }] },
        { id:'hrex_271', title:'中国互联网反垄断', titleEn:'Internet Antitrust in China', hsk:5, passage:'近年来中国加强了对互联网平台的反垄断监管。阿里巴巴和腾讯等巨头被处以巨额罚款。二选一和算法歧视等行为被禁止。监管部门要求平台不得滥用市场支配地位。保护中小商家的利益。这些措施的目的是促进公平竞争。防止资本无序扩张。对消费者来说。更多的竞争意味着更好的服务和更低的价格。反垄断将成为常态。', questions:[{ q:'哪些互联网巨头被罚款？', options:['阿里巴巴腾讯','百度京东','拼多多美团','字节跳动'], correct:0 },{ q:'二选一是什么行为？', options:['强迫商家选择一家平台','选择两个商品','二选一考试','选择两种支付方式'], correct:0 },{ q:'反垄断的目的是什么？', options:['促进公平竞争','增加税收','减少互联网公司','提高价格'], correct:0 },{ q:'反垄断对消费者有什么好处？', options:['更好服务和更低价格','更多广告','更少选择','更慢配送'], correct:0 }] },
        { id:'hrex_272', title:'中国家庭结构变化', titleEn:'Changes in Chinese Family Structure', hsk:5, passage:'中国的家庭结构正在发生变化。传统的四世同堂大家庭越来越少。核心家庭成为主流。即父母和未婚子女组成的家庭。独生子女政策影响了中国家庭结构几十年。造就了大量四二一家庭。四个老人、两个中年人和一个孩子。现在虽然放开了二胎三胎。但是很多年轻人不愿意生。家庭规模还在缩小。空巢老人和独居青年成为普遍现象。', questions:[{ q:'传统大家庭什么样？', options:['四世同堂','三口之家','两个人','单身'], correct:0 },{ q:'核心家庭由谁组成？', options:['父母和未婚子女','祖父母和孙辈','兄弟姐妹','亲戚'], correct:0 },{ q:'四二一家庭中的一代表什么？', options:['一个孩子','一个老人','一个中年人','一只宠物'], correct:0 },{ q:'现在普遍存在什么现象？', options:['空巢老人和独居青年','大家庭','多子多福','早婚早育'], correct:0 }] },
        { id:'hrex_273', title:'中国乡村旅游', titleEn:'Rural Tourism in China', hsk:5, passage:'乡村旅游在中国越来越受欢迎。城市人厌倦了快节奏的生活。想到乡村体验慢生活。民宿产业随之兴起。一些特色的古村落成为热门目的地。比如宏村、婺源和丽江古城。游客可以住农家院、吃农家菜、体验农耕。乡村旅游带动了农民增收致富。但是也出现了一些问题。过度商业化破坏了乡村的原生态。游客的不文明行为也影响了当地环境。', questions:[{ q:'城市人为什么喜欢乡村旅游？', options:['想体验慢生活','价格便宜','距离近','交通方便'], correct:0 },{ q:'文中提到了哪些古村落？', options:['宏村婺源丽江古城','周庄乌镇','平遥凤凰','西塘南浔'], correct:0 },{ q:'乡村旅游带动了什么？', options:['农民增收致富','城市发展','工业增长','出口贸易'], correct:0 },{ q:'乡村旅游出现了什么问题？', options:['过度商业化和环境破坏','价格太高','没人去','服务太差'], correct:0 }] },
        { id:'hrex_274', title:'中国芯片产业的挑战', titleEn:'Challenges of Chinas Chip Industry', hsk:5, passage:'芯片是现代科技的核心。中国每年进口芯片的金额超过石油。但是中国在高端芯片领域长期依赖进口。美国对华为等公司的制裁暴露了芯片自主的重要性。近年来中国政府大力扶持芯片产业。投入了大量资金。华为的麒麟芯片曾经达到世界先进水平。但是受制裁后无法生产。中国芯片产业正在努力突破技术瓶颈。光刻机是最大的难题。', questions:[{ q:'中国每年进口芯片金额超过什么？', options:['石油','钢铁','粮食','汽车'], correct:0 },{ q:'美国的制裁说明了什么？', options:['芯片自主的重要性','芯片不重要','美国太强大','中国太弱'], correct:0 },{ q:'华为的麒麟芯片怎么样了？', options:['无法生产','出口全球','世界第一','被收购'], correct:0 },{ q:'中国芯片产业最大的难题是什么？', options:['光刻机','原材料','人才','资金'], correct:0 }] },
        { id:'hrex_275', title:'中国的扶贫成就', titleEn:'Chinas Poverty Alleviation Achievements', hsk:5, passage:'中国在扶贫领域取得了举世瞩目的成就。按照现行标准。中国已经消除了绝对贫困。近一亿农村贫困人口脱贫。扶贫采取了很多措施。包括产业扶贫、易地搬迁和生态补偿等。干部驻村帮扶也是重要手段。扶贫不仅改善了贫困人口的生活条件。还改变了他们的精神面貌。但是脱贫不脱政策。防止返贫同样重要。乡村振兴战略接续推进。', questions:[{ q:'中国消除了什么？', options:['绝对贫困','相对贫困','城市贫困','所有贫困'], correct:0 },{ q:'多少农村贫困人口脱贫？', options:['几千万','近一亿','几亿','十几亿'], correct:1 },{ q:'扶贫采取了哪些措施？', options:['产业扶贫易地搬迁生态补偿','发放现金','减税','贷款'], correct:0 },{ q:'扶贫结束后还要做什么？', options:['防止返贫推进乡村振兴','停止所有政策','减少投入','转移目标'], correct:0 }] },
        { id:'hrex_276', title:'中国动漫产业发展', titleEn:'Development of Chinese Animation', hsk:5, passage:'中国动漫产业正在崛起。过去中国动漫被日本和美国动漫压制。市场份额很小。近年来出现了一批优秀的国产动漫作品。电影哪吒之魔童降世票房超过五十亿元。动画剧集如一人之下和狐妖小红娘在国内外都很受欢迎。中国动漫开始融合传统文化元素。形成了自己的风格。但是和日本动漫相比还有差距。产业链还不够完善。', questions:[{ q:'过去中国动漫的处境怎样？', options:['被日美动漫压制','世界领先','很受欢迎','出口全球'], correct:0 },{ q:'哪吒之魔童降世票房多少？', options:['超过十亿','超过三十亿','超过五十亿','超过百亿'], correct:2 },{ q:'文中提到了哪些国漫剧集？', options:['一人之下狐妖小红娘','海贼王','火影忍者','柯南'], correct:0 },{ q:'中国动漫开始融合什么元素？', options:['传统文化元素','西方元素','日漫风格','现代科技'], correct:0 }] },
        { id:'hrex_277', title:'中国的低碳生活', titleEn:'Low-Carbon Life in China', hsk:5, passage:'低碳生活的理念在中国越来越普及。人们开始注意节约能源。减少碳排放。绿色出行成为一种时尚。骑共享单车和乘坐公共交通的人越来越多。垃圾分类和减少使用塑料袋也在推广。有些年轻人选择极简主义生活方式。不买不必要的物品。但是低碳生活在实施中也有困难。电动汽车虽然环保。但充电仍然依赖燃煤发电。真正的低碳需要整个能源结构的转型。', questions:[{ q:'低碳生活理念怎么样？', options:['越来越普及','没人关心','已经过时','只在城市'], correct:0 },{ q:'绿色出行包括什么？', options:['骑单车和公共交通','开私家车','坐飞机','打车'], correct:0 },{ q:'极简主义生活方式指什么？', options:['不买不必要的物品','不吃饭','不工作','不出门'], correct:0 },{ q:'低碳生活面临什么困难？', options:['电动汽车充电依赖燃煤发电','没人支持','成本太高','技术不成熟'], correct:0 }] },
        { id:'hrex_278', title:'中国的人工智能发展', titleEn:'AI Development in China', hsk:5, passage:'中国将人工智能列为国家战略重点发展方向。在计算机视觉、自然语言处理和语音识别等领域取得了显著进展。人脸识别技术广泛应用于安防和支付。智能音箱和扫地机器人走进千家万户。百度的自动驾驶出租车已经在多个城市试运营。中国在人工智能论文数量和专利数量上都位居世界前列。但是在基础算法和高端芯片方面仍落后于美国。', questions:[{ q:'哪些AI领域取得了进展？', options:['计算机视觉自然语言处理语音识别','量子计算','生物工程','材料科学'], correct:0 },{ q:'人脸识别用于哪些方面？', options:['安防和支付','娱乐','教育','医疗'], correct:0 },{ q:'百度的自动驾驶出租车在做什么？', options:['试运营','全国推广','出口海外','停止测试'], correct:0 },{ q:'中国在AI方面仍然落后于美国什么？', options:['基础算法和高端芯片','应用落地','市场规模','人才数量'], correct:0 }] },
        { id:'hrex_279', title:'中国彩礼问题', titleEn:'The Bride Price Problem in China', hsk:5, passage:'彩礼是中国传统婚俗的一部分。男方要给女方一定数量的钱或财物。近年来彩礼金额越来越高。有些地方的彩礼高达几十万元。给男方家庭造成了沉重的经济负担。因彩礼引发的纠纷时有发生。天价彩礼甚至成为一些地区返贫的原因。政府倡导文明婚俗。反对铺张浪费。年轻人的观念也在改变。越来越多的情侣选择裸婚或者旅行结婚。', questions:[{ q:'彩礼是什么？', options:['男方给女方的钱物','女方给男方的钱','结婚戒指','婚宴费用'], correct:0 },{ q:'天价彩礼带来了什么后果？', options:['经济负担和返贫','促进消费','提高生活水平','增加储蓄'], correct:0 },{ q:'政府倡导什么？', options:['文明婚俗反对铺张浪费','提高彩礼','降低彩礼','取消婚姻'], correct:0 },{ q:'年轻人选择什么方式结婚？', options:['裸婚或旅行结婚','大办婚宴','传统婚礼','集体婚礼'], correct:0 }] },
        { id:'hrex_280', title:'中国的地铁建设', titleEn:'Chinas Subway Construction', hsk:5, passage:'中国的地铁建设速度世界第一。很多城市都在修建地铁。上海地铁里程全球最长。超过八百公里。北京、广州、深圳的地铁网络也很发达。地铁大大缓解了城市交通压力。也带动了沿线房地产升值。但是地铁建设成本高昂。一公里地铁的造价高达数亿元。运营也很难盈利。大多数城市的地铁都依赖政府补贴。未来需要探索更加可持续的运营模式。', questions:[{ q:'哪个城市的地铁里程全球最长？', options:['上海','北京','广州','深圳'], correct:0 },{ q:'上海地铁里程超过多少？', options:['六百公里','七百公里','八百公里','九百公里'], correct:2 },{ q:'地铁建设成本怎么样？', options:['高昂一公里数亿元','很低','一般','免费'], correct:0 },{ q:'地铁运营面临什么问题？', options:['难以盈利依赖补贴','没人坐','太拥挤','速度太慢'], correct:0 }] },
        { id:'hrex_281', title:'中国人出境游趋势', titleEn:'Chinese Outbound Tourism Trends', hsk:5, passage:'中国已经成为全球最大的出境旅游客源国。每年有上亿人次的中国游客出境旅游。泰国、日本和韩国是最热门的目的地。中国游客的消费能力很强。购物是出境游的重要环节。现在中国游客越来越注重深度体验。喜欢自由行。注重文化体验和美食。中国护照的含金量也在提高。越来越多的国家对中国公民免签。', questions:[{ q:'中国是世界第几大出境旅游客源国？', options:['第二','最大','第三','第四'], correct:1 },{ q:'每年有多少人次出境旅游？', options:['几千万','上亿','几亿','十几亿'], correct:1 },{ q:'哪些国家是热门目的地？', options:['泰国日本韩国','美英法','德意西','澳新加'], correct:0 },{ q:'现在中国游客喜欢什么方式？', options:['自由行深度体验','跟团游','买奢侈品','宅在酒店'], correct:0 }] },
        { id:'hrex_282', title:'中国房价调控', titleEn:'Housing Price Control in China', hsk:5, passage:'中国政府对房价进行了多轮调控。限购、限贷和限售是最常用的手段。房住不炒是基本原则。意思是房子是用来住的不是用来炒的。一些热点城市的房价曾经快速上涨。现在基本稳定下来。但是房价仍然处于高位。年轻人买房依然困难。长租公寓暴雷事件也让租房者缺乏安全感。共有产权住房和保障性租赁住房正在加快供应。', questions:[{ q:'常用的调控手段有哪些？', options:['限购限贷限售','加税','降价','补贴'], correct:0 },{ q:'房住不炒是什么意思？', options:['房子用来住不是炒的','房子应该便宜','不要买房','少买房子'], correct:0 },{ q:'现在房价水平怎么样？', options:['基本稳定但处于高位','大幅下降','快速上涨','崩溃'], correct:0 },{ q:'长租公寓发生了什么问题？', options:['暴雷事件','涨价','服务好','供不应求'], correct:0 }] },
        { id:'hrex_283', title:'中国人口流动趋势', titleEn:'Population Mobility Trends in China', hsk:5, passage:'中国人口流动呈现出新的趋势。过去人们主要从农村流向城市。从内地流向沿海。现在有一些新的变化。一线城市生活成本太高。有些人开始回流到二三线城市。新一线城市如成都、杭州、武汉吸引了大量人才。这些城市提供了更多就业机会和更好的生活质量。同时农村人口向县城集中。县城成为城镇化的重要载体。逆城市化现象也开始出现。', questions:[{ q:'过去人口流动的方向是什么？', options:['农村到城市内地到沿海','城市到农村','沿海到内地','国外到国内'], correct:0 },{ q:'现在出现了什么新变化？', options:['回流到二三线城市','全部出国','不流动了','去向不明'], correct:0 },{ q:'新一线城市包括哪些？', options:['成都杭州武汉','北上广深','西安重庆长沙','南京苏州无锡'], correct:0 },{ q:'文中提到了什么新现象？', options:['逆城市化','移民潮','出国热','创业潮'], correct:0 }] },
        { id:'hrex_284', title:'中国网络文学', titleEn:'Chinese Online Literature', hsk:5, passage:'中国网络文学是一个独特的文化现象。起点中文网、晋江文学城等平台拥有大量读者和作者。网络文学类型丰富。包括玄幻、言情、历史、悬疑等。很多作品被改编成电视剧和电影。中国网络文学在海外也有不少读者。外国人喜欢看翻译成英文的中国网络小说。但是网络文学的质量参差不齐。抄袭和注水问题也比较严重。', questions:[{ q:'文中提到了哪些网络文学平台？', options:['起点中文网晋江文学城','豆瓣读书','当当网','亚马逊'], correct:0 },{ q:'网络文学的类型包括什么？', options:['玄幻言情历史悬疑','新闻报道','学术论文','诗歌'], correct:0 },{ q:'网络文学有什么商业价值？', options:['改编成电视剧电影','直接卖书','广告收入','会员费'], correct:0 },{ q:'网络文学存在什么问题？', options:['抄袭和注水','太贵','没人看','类型太少'], correct:0 }] },
        { id:'hrex_285', title:'中国餐饮外卖的演变', titleEn:'Evolution of Food Delivery in China', hsk:5, passage:'中国餐饮外卖行业经历了巨大的变化。从电话订餐发展到手机APP下单。配送时间越来越短。美团和饿了么两大平台竞争激烈。外卖骑手成为城市中不可或缺的角色。疫情期间外卖行业发挥了重要作用。保障了人们的基本生活需求。但是外卖骑手的劳动权益问题也引发关注。平台需要改进算法。保障骑手的安全和收入。', questions:[{ q:'外卖从什么发展到什么？', options:['电话订餐到手机APP','信件订餐到传真','网上到线下','人工到机器'], correct:0 },{ q:'两大外卖平台是谁？', options:['美团和饿了么','百度和谷歌','京东和淘宝','滴滴和uber'], correct:0 },{ q:'疫情期间外卖起了什么作用？', options:['保障基本生活需求','传播病毒','关闭了','没人用'], correct:0 },{ q:'外卖骑手面临什么问题？', options:['劳动权益和算法问题','工资太高','太轻松','人数太少'], correct:0 }] },
        { id:'hrex_286', title:'中国的非物质文化遗产', titleEn:'Intangible Cultural Heritage of China', hsk:5, passage:'中国拥有丰富的非物质文化遗产。包括传统音乐、舞蹈、戏剧、手工艺和民俗等。昆曲和古琴艺术被联合国教科文组织列入人类非物质文化遗产代表作名录。皮影戏和剪纸也是珍贵的非遗项目。但是很多非遗项目面临失传的风险。年轻一代对传统技艺兴趣不大。传承人越来越少。政府采取了保护措施。设立非遗传承人制度。鼓励非遗进校园。', questions:[{ q:'非物质文化遗产包括什么？', options:['音乐舞蹈戏剧手工艺民俗','建筑','美食','服饰'], correct:0 },{ q:'哪些项目被列入联合国非遗名录？', options:['昆曲和古琴艺术','京剧','相声','杂技'], correct:0 },{ q:'非遗项目面临什么风险？', options:['失传','太流行','被收购','被模仿'], correct:0 },{ q:'政府采取了什么保护措施？', options:['设立传承人制度进校园','禁止表演','降低质量','取消保护'], correct:0 }] },
        { id:'hrex_287', title:'中国电动汽车的普及', titleEn:'Popularity of Electric Vehicles in China', hsk:5, passage:'中国是世界上最大的电动汽车市场。政府通过补贴和优惠政策大力推广电动汽车。很多城市对新能源车免除了限行限制。充电基础设施在快速建设。高速公路服务区都有了充电站。电动汽车的续航里程已经普遍达到四百公里以上。但是冬季续航缩水问题仍然存在。电池回收也是需要解决的课题。消费者的购买意愿在增强。电动汽车的市场占有率持续上升。', questions:[{ q:'中国是什么市场？', options:['最大电动汽车市场','最大燃油车市场','最大自行车市场','最大摩托车市场'], correct:0 },{ q:'政府怎么推广电动汽车？', options:['补贴和优惠政策','强制购买','加税','限制燃油车'], correct:0 },{ q:'电动汽车的续航里程怎么样？', options:['四百公里以上','不到一百公里','一千公里','五十公里'], correct:0 },{ q:'电动汽车面临什么问题？', options:['冬季续航缩水和电池回收','速度太慢','不安全','太丑'], correct:0 }] },
        { id:'hrex_288', title:'中国在太空的成就', titleEn:'Chinas Space Achievements', hsk:5, passage:'中国在太空探索领域取得了令人瞩目的成就。北斗卫星导航系统已经完成全球组网。嫦娥五号成功从月球带回土壤样本。天问一号实现了对火星的环绕、着陆和巡视。天宫空间站全面建成。中国宇航员在空间站进行了多项科学实验。中国还计划在月球建立国际科研站。这些成就标志着中国航天技术已经进入世界先进行列。', questions:[{ q:'北斗系统完成了什么？', options:['全球组网','载人登月','火星探测','空间站建设'], correct:0 },{ q:'嫦娥五号完成了什么？', options:['带回月球土壤样本','载人登月','火星着陆','探测金星'], correct:0 },{ q:'天问一号的目标是什么？', options:['探测火星','探测月球','探测金星','探测木星'], correct:0 },{ q:'中国计划在月球建立什么？', options:['国际科研站','城市','军事基地','旅游景点'], correct:0 }] },
        { id:'hrex_289', title:'中国消费者维权意识', titleEn:'Consumer Rights Awareness in China', hsk:5, passage:'中国消费者的维权意识在不断增强。每年的3月15日是消费者权益日。央视会举办315晚会曝光侵害消费者权益的行为。过去消费者遇到问题往往选择忍气吞声。现在更多人会通过投诉、曝光和法律途径维护自己的权益。电商平台推出了七天无理由退货政策。消费者评价体系也让商家更加重视口碑。但是刷单、虚假宣传等问题仍然存在。', questions:[{ q:'3月15日是什么日子？', options:['消费者权益日','国庆节','劳动节','环保日'], correct:0 },{ q:'央视315晚会做什么？', options:['曝光侵害消费者权益行为','娱乐表演','颁奖','新闻联播'], correct:0 },{ q:'过去消费者遇到问题怎么做？', options:['忍气吞声','投诉','曝光','起诉'], correct:0 },{ q:'电商平台的什么政策保护消费者？', options:['七天无理由退货','不退不换','概不负责','最终解释'], correct:0 }] },
        { id:'hrex_290', title:'中国在线教育的发展', titleEn:'Development of Online Education in China', hsk:5, passage:'中国在线教育市场曾经经历了爆发式增长。疫情期间在线教育发挥了重要作用。让学生可以在家上课。猿辅导、作业帮等平台获得了大量投资。但是随着双减政策的实施。学科类在线教育受到严格限制。很多公司转型做素质教育或职业教育。在线教育的模式也在发生变化。从直播大班课转向AI互动课和一对一辅导。行业进入了调整期。', questions:[{ q:'什么时候在线教育发挥了重要作用？', options:['疫情期间','平时','假期','周末'], correct:0 },{ q:'文中提到了哪些在线教育平台？', options:['猿辅导作业帮','新东方好未来','学而思','网易有道'], correct:0 },{ q:'双减政策对在线教育有什么影响？', options:['学科类受限制','鼓励发展','没有影响','取消在线教育'], correct:0 },{ q:'在线教育行业现在进入了什么阶段？', options:['调整期','高速增长期','衰退期','成熟期'], correct:0 }] },
        { id:'hrex_291', title:'中国周边外交', titleEn:'Chinas Neighborhood Diplomacy', hsk:5, passage:'中国非常重视与周边国家的关系。一带一路倡议为周边国家带来了发展机遇。中国东盟关系不断深化。成为区域合作的典范。中老铁路开通运营。连接中国和老挝。促进了区域互联互通。中日韩三国合作也在推进。但是在南海问题上中国和一些邻国存在争议。中国主张通过对话协商解决分歧。维护地区的和平稳定。', questions:[{ q:'一带一路为周边国家带来了什么？', options:['发展机遇','战争','债务','文化入侵'], correct:0 },{ q:'中老铁路连接了哪两个国家？', options:['中国和老挝','中国和缅甸','中国和越南','中国和泰国'], correct:0 },{ q:'中国东盟关系怎么样？', options:['不断深化','恶化','停滞','倒退'], correct:0 },{ q:'中国如何解决南海争议？', options:['通过对话协商','武力解决','不承认','搁置不理'], correct:0 }] },
        { id:'hrex_292', title:'中国冰雪运动发展', titleEn:'Development of Ice and Snow Sports', hsk:5, passage:'北京冬奥会极大地推动了中国冰雪运动的发展。三亿人参与冰雪运动的目标已经实现。滑雪场和滑冰场数量大幅增加。冰雪运动不再只是北方人的专利。南方城市也建起了室内滑雪场。冰雪装备产业也随之兴起。但是冰雪运动的普及还面临一些挑战。场地运营成本高。专业教练缺乏。安全也需要重视。', questions:[{ q:'北京冬奥会推动了多少人参与冰雪运动？', options:['一亿','三亿','五亿','十亿'], correct:1 },{ q:'文中提到了什么变化？', options:['南方也建起了室内滑雪场','只有北方能滑','没人滑冰','冰雪运动消失了'], correct:0 },{ q:'冰雪运动的普及面临什么挑战？', options:['场地成本高教练缺乏','没有人喜欢','天气太热','禁止运动'], correct:0 },{ q:'冰雪装备产业怎么样？', options:['随之兴起','没有变化','萎缩了','被淘汰'], correct:0 }] },
        { id:'hrex_293', title:'中国粮食安全', titleEn:'Chinas Food Security', hsk:5, passage:'中国已经把粮食安全提升到了国家战略高度。中国用占世界百分之九的耕地养活了百分之二十的人口。这是一个了不起的成就。水稻和小麦是主要的粮食作物。袁隆平院士的杂交水稻技术大幅提高了产量。中国的粮食储备充足。但是粮食安全仍然面临挑战。耕地面积在减少。种粮成本在上升。大豆等部分农产品依赖进口。确保粮食安全需要持续努力。', questions:[{ q:'中国用多少耕地养活了百分之二十的人口？', options:['百分之九','百分之五','百分之十五','百分之二十'], correct:0 },{ q:'袁隆平的什么技术提高了产量？', options:['杂交水稻','转基因','有机种植','无土栽培'], correct:0 },{ q:'哪些农产品依赖进口？', options:['大豆等部分农产品','水稻','小麦','玉米'], correct:0 },{ q:'粮食安全面临什么挑战？', options:['耕地减少成本上升','粮食太多','人口减少','进口太多'], correct:0 }] },
        { id:'hrex_294', title:'中国在线旅游平台', titleEn:'Chinese Online Travel Platforms', hsk:5, passage:'中国的在线旅游市场由携程、去哪儿和飞猪等平台主导。这些平台提供机票、酒店和旅游产品的预订服务。消费者可以在线比价和查看评价。旅游产品也变得越来越丰富。定制游、主题游和小团游受到欢迎。在线旅游平台还推出了先用后付和行程助手等功能。但是大数据杀熟问题也引起关注。同样的产品老用户看到的价格更高。', questions:[{ q:'文中提到了哪些在线旅游平台？', options:['携程去哪儿飞猪','美团大众点评','滴滴快车','淘宝京东'], correct:0 },{ q:'在线旅游平台提供什么服务？', options:['机票酒店旅游产品','外卖','打车','快递'], correct:0 },{ q:'哪些旅游方式受欢迎？', options:['定制游主题游小团游','跟团游','自驾游','穷游'], correct:0 },{ q:'大数据杀熟指什么？', options:['老用户价格更高','新用户优惠','数据泄露','算法推荐'], correct:0 }] },
        { id:'hrex_295', title:'中国工匠精神', titleEn:'Chinese Craftsmanship Spirit', hsk:5, passage:'工匠精神在中国传统手工艺中体现得淋漓尽致。景德镇陶瓷、苏州刺绣和北京雕漆等都需要精湛的技艺。一件精品往往需要数月甚至数年的精心制作。老一辈工匠几十年如一日地打磨自己的手艺。但是随着工业化的发展。传统手工艺受到冲击。年轻人不愿意学。很多技艺面临失传。政府设立了工艺美术大师制度。保护和传承传统技艺。', questions:[{ q:'文中提到了哪些传统手工艺？', options:['景德镇陶瓷苏州刺绣北京雕漆','木雕','玉雕','金银器'], correct:0 },{ q:'一件精品需要制作多久？', options:['数月甚至数年','几天','几小时','几周'], correct:0 },{ q:'传统手工艺面临什么问题？', options:['年轻人不愿意学','质量太好','价格太贵','产量太高'], correct:0 },{ q:'政府采取了什么措施？', options:['设立工艺美术大师制度','降低标准','取消传统工艺','全部机械化'], correct:0 }] },
        { id:'hrex_296', title:'中国企业的国际化', titleEn:'Internationalization of Chinese Companies', hsk:5, passage:'越来越多的中国企业走向国际市场。华为、小米、字节跳动等公司在全球范围内有影响力。华为的5G技术领先世界。TikTok在全球拥有数十亿用户。中国品牌的形象在提升。不再只是廉价产品的代名词。高端制造和科技创新成为中国企业的新名片。但是国际化道路并不平坦。地缘政治风险、文化差异和法律障碍都是挑战。', questions:[{ q:'文中提到了哪些中国企业？', options:['华为小米字节跳动','阿里巴巴腾讯','百度京东','拼多多美团'], correct:0 },{ q:'华为在哪方面领先？', options:['5G技术','手机设计','芯片制造','软件开发'], correct:0 },{ q:'TikTok在全球有多少用户？', options:['数十亿','几百万','几千万','几亿'], correct:0 },{ q:'中国企业国际化面临什么障碍？', options:['地缘政治文化差异法律障碍','没有障碍','语言不通','技术不够'], correct:0 }] },
        { id:'hrex_297', title:'中国湿地保护', titleEn:'Wetland Protection in China', hsk:5, passage:'中国拥有广阔的湿地资源。湿地被称为地球之肾。具有净化水质和调节气候的功能。但是过去几十年大量湿地被填埋用于城市建设。导致生态功能退化。现在政府高度重视湿地保护。建立了多个湿地自然保护区。杭州西溪湿地是成功的修复案例。从一个被污染的水域变成了美丽的湿地公园。湿地保护法的实施为湿地保护提供了法律保障。', questions:[{ q:'湿地被称为什么？', options:['地球之肾','地球之肺','地球之肝','地球之心'], correct:0 },{ q:'湿地具有什么功能？', options:['净化水质调节气候','发电','灌溉','航运'], correct:0 },{ q:'过去湿地遇到了什么问题？', options:['被填埋用于城市建设','被保护得很好','面积增加','水质变好'], correct:0 },{ q:'西溪湿地是什么案例？', options:['成功的修复案例','失败的案例','自然湿地','人工湿地'], correct:0 }] },
        { id:'hrex_298', title:'中国人的时间观念', titleEn:'Chinese Concept of Time', hsk:5, passage:'中国人的时间观念在发生变化。传统农业社会中人们遵循日出而作日落而息的生活节奏。现在城市化让生活节奏加快。时间就是金钱的观念深入人心。上下班打卡、项目截止日期让人们感到时间紧迫。碎片化时间被充分利用。通勤路上看手机成为常态。但是也有人开始反思快节奏生活。慢生活理念逐渐兴起。人们开始重视工作与生活的平衡。', questions:[{ q:'传统农业社会的生活节奏怎样？', options:['日出而作日落而息','快速','紧张','悠闲'], correct:0 },{ q:'什么观念深入人心？', options:['时间就是金钱','时间就是生命','时间就是效率','时间就是知识'], correct:0 },{ q:'碎片化时间被用来做什么？', options:['看手机','运动','读书','休息'], correct:0 },{ q:'什么理念逐渐兴起？', options:['慢生活','快生活','极简生活','奢侈生活'], correct:0 }] },
        { id:'hrex_299', title:'中国航天员的太空生活', titleEn:'Astronauts Life in Space', hsk:5, passage:'中国航天员在天宫空间站的生活引起了广泛关注。他们在太空中每天工作八小时。进行科学实验和设备维护。业余时间可以锻炼身体。看视频和与家人通话。空间站内设有厨房和卫生间。航天员可以吃到宫保鸡丁和鱼香肉丝等中餐。在微重力环境下生活需要适应。睡觉时要把自己固定在睡袋里。太空生活虽然有趣但也充满挑战。对身体和心理都是考验。', questions:[{ q:'航天员每天工作几小时？', options:['八小时','六小时','十小时','十二小时'], correct:0 },{ q:'业余时间可以做什么？', options:['锻炼看视频与家人通话','出去散步','逛街','游泳'], correct:0 },{ q:'航天员能吃到什么？', options:['宫保鸡丁鱼香肉丝','西餐','日本料理','韩国泡菜'], correct:0 },{ q:'在微重力下睡觉要注意什么？', options:['把自己固定在睡袋里','不能睡觉','站着睡','倒着睡'], correct:0 }] },
        { id:'hrex_300', title:'中国人与水的关系', titleEn:'Relationship Between Chinese and Water', hsk:5, passage:'中国人与水的关系源远流长。大禹治水的故事流传了几千年。南水北调工程是世界上最大的调水工程。把长江水送到北方干旱地区。三峡大坝是世界上最大的水电站。提供了大量清洁能源。但是水资源的分布很不均匀。北方缺水。南方洪涝。水资源短缺和污染问题并存。节约用水和保护水环境成为每个人的责任。', questions:[{ q:'大禹治水是什么时期的故事？', options:['古代传说','近代','现代','当代'], correct:0 },{ q:'南水北调工程把水送到哪里？', options:['北方干旱地区','南方','西部','东部'], correct:0 },{ q:'三峡大坝提供什么？', options:['清洁能源','灌溉','航运','旅游'], correct:0 },{ q:'中国水资源有什么问题？', options:['分布不均短缺和污染','太多','没有污染','非常充足'], correct:0 }] },
    ];
    items.forEach(function(it) {
        var key = 'hsk' + it.hsk;
        if (byLevel[key]) byLevel[key].push(it);
    });
    if (typeof HSKReadingMassive !== 'undefined') {
        Object.keys(byLevel).forEach(function(key) {
            var arr = HSKReadingMassive[key];
            if (arr) {
                byLevel[key].forEach(function(it) {
                    if (!arr.find(function(x) { return x.id === it.id; })) {
                        arr.push(it);
                    }
                });
            }
        });
    }
})();
